.wordpress.org/hellofromtonya/\">Tonya Mork</a> · <a href=\"https://profiles.wordpress.org/r0uter/\">tonythomas01</a> · <a href=\"https://profiles.wordpress.org/toro_unit/\">Toro_Unit (Hiroshi Urabe)</a> · <a href=\"https://profiles.wordpress.org/zodiac1978/\">Torsten Landsiedel</a> · <a href=\"https://profiles.wordpress.org/itowhid06/\">Towhidul I Chowdhury</a> · <a href=\"https://profiles.wordpress.org/scep/\">Tryon</a> · <a href=\"https://profiles.wordpress.org/twstokes/\">twstokes</a> · <a href=\"https://profiles.wordpress.org/tyb/\">TyB</a> · <a href=\"https://profiles.wordpress.org/ugyensupport/\">Ugyen Dorji</a> · <a href=\"https://profiles.wordpress.org/umesh84/\">Umesh Gupta</a> · <a href=\"https://profiles.wordpress.org/umeshmcakadi/\">Umesh Patel</a> · <a href=\"https://profiles.wordpress.org/upadalavipul/\">upadalavipul</a> · <a href=\"https://profiles.wordpress.org/utsav72640/\">Utsav tilava</a> · <a href=\"https://profiles.wordpress.org/uxtremist/\">uxtremist</a> · <a href=\"https://profiles.wordpress.org/eboxnet/\">Vagelis</a> · <a href=\"https://profiles.wordpress.org/valterlorran/\">valterlorran</a> · <a href=\"https://profiles.wordpress.org/vasilism/\">Vasilis Manthos</a> · <a href=\"https://profiles.wordpress.org/victoranto/\">victoranto</a> · <a href=\"https://profiles.wordpress.org/gvgvgvijayan/\">Vijayan</a> · <a href=\"https://profiles.wordpress.org/szepeviktor/\">Viktor Sz&#233;pe</a> · <a href=\"https://profiles.wordpress.org/vivekawsm/\">vivekawsm</a> · <a href=\"https://profiles.wordpress.org/vladytimy/\">Vlad</a> · <a href=\"https://profiles.wordpress.org/vortfu/\">vortfu</a> · <a href=\"https://profiles.wordpress.org/westonruter/\">Weston Ruter</a> · <a href=\"https://profiles.wordpress.org/whaze/\">whaze</a> · <a href=\"https://profiles.wordpress.org/skorasaurus/\">Will Skora</a> · <a href=\"https://profiles.wordpress.org/williampatton/\">williampatton</a> · <a href=\"https://profiles.wordpress.org/wojtekszkutnik/\">Wojtek Szkutnik</a> · <a href=\"https://profiles.wordpress.org/wplmillet/\">wplmillet</a> · <a href=\"https://profiles.wordpress.org/xerpa43/\">xerpa43</a> · <a href=\"https://profiles.wordpress.org/xmarcos/\">xmarcos</a> · <a href=\"https://profiles.wordpress.org/yaniiliev/\">Yani</a> · <a href=\"https://profiles.wordpress.org/fierevere/\">Yui</a> · <a href=\"https://profiles.wordpress.org/zdrobau/\">Zdrobau</a> · <a href=\"https://profiles.wordpress.org/zebaafiashama/\">Zeba Afia Shama</a> · <a href=\"https://profiles.wordpress.org/zebulan/\">Zebulan Stanphill</a> · <a href=\"https://profiles.wordpress.org/zenaulislam/\">Zenaul Islam</a> · <a href=\"https://profiles.wordpress.org/zunaid321/\">Zunaid Amin</a></p></p>\n\n\n\n<h3 class=\"wp-block-heading\">WordPressin tukifoorumit</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Suuri kiitos yhteisön vapaaehtoisille, jotka osallistuvat <a href=\"https://wordpress.org/support/\">tukifoorumien</a> toimintaan vastaamalla WordPress-käyttäjien kysymyksiin maailmanlaajuisesti.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Tule osallistumaan mukaan</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Jos WordPressiin osallistuminen kiinnostaa sinua, osallistuminen on helppoa. Tutustu tiimiin, jotka kokoontuvat tekemään WordPressiä <a href=\"https://make.wordpress.org/\">Make WordPress -sivustolla</a>, ja tutustu tuotteen etenemissuunnitelmaan <a href=\"https://make.wordpress.org/core/\">Make WordPress Core -blogissa</a>. Tämän <a href=\"https://make.wordpress.org/contribute/\">interaktiivisen työkalun</a> avulla voit myös päättää, mikä tiimi sopii sinulle.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Jos sinua kiinnostaa osallistua WordPressin tai sen lisäosien kääntämiseen tai muulla tavoin osallistua WordPressin kehittämiseen,&nbsp;<a href=\"https://fi.wordpress.org/osallistu/\">löydät tiiviin tietopaketin täältä myös suomeksi</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Katse kohti tulevaisuutta</h2>\n\n\n\n<p class=\"wp-block-paragraph\">20 vuotta sitten viime toukokuusta <a href=\"https://wordpress.org/news/2003/05/wordpress-now-available/\">WordPress julkaisi ensimmäisen versionsa, 0.7</a>. Se, mikä alkoi toisen perustajan Matt Mullenwegin blogikirjoituksesta ja perustajajäsenen Mike Littlen kommentista, kehittyi lopulta maailman suosituimmaksi verkkojulkaisualustaksi.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress-ohjelmisto kehittyy sykleittäin edelleen vahvan ja monipuolisen käyttäjäyhteisönsä tarpeiden ja toiveiden mukaisesti. Tämä julkaisu on WordPressin <a href=\"https://wordpress.org/about/roadmap/\">kehityssuunnitelman</a> <a href=\"https://make.wordpress.org/core/2023/02/04/phase-2-finale/\">vaiheen 2</a> huippu. Yhteisön katsoessa tulevaisuuteen kaikki ponnistelut suuntautuvat 6.4:ään ja sen jälkeen siirtymiseen <a href=\"https://make.wordpress.org/core/2023/03/24/phase-3-collaboration/\">vaiheeseen 3</a>, jonka odotetaan tuovan tehokkaita työkaluja yhteistyöhön verkkosivustojen luomiseen ja hallintaan.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<h2 class=\"wp-block-heading\">6.3 Haiku</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Huippujulkaisu<br>Työkaluja kaikille<br>Yhteistyön voima</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<h2 class=\"wp-block-heading\">WordCamp Finland kokoaa Suomen WordPress-yhteisön</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Suomen suurin WordPress-tapahtuma järjestetään tänä vuonna 14.–15.9.2023. WordCamp yhdistää kaikentasoiset WordPress-käyttäjät yhteiseen tapahtumaan. Tapahtuma sisältää jotain niin freelancereille, kehittäjille, suunnittelijoille, sisällöntuottajille, digitoimistojen tai mainostoimistojen vetäjille kuin vasta WordPressiä opetteleville.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://fi.wordpress.org/2023/03/13/wordcamp-finland-palaa-2023/\">Lue lisää WordCamp Finlandista</a></li>\n\n\n\n<li><a href=\"https://finland.wordcamp.org/2023/tickets/\">Osta liput tapahtumaan</a></li>\n</ul>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://fi.wordpress.org/2023/08/09/lionel/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1035\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"Syksyllä kuullaan ja opitaan näistä teemoista WordCamp Finlandissa\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:107:\"https://fi.wordpress.org/2023/06/30/syksylla-kuullaan-ja-opitaan-naista-wordpressiin-liittyvista-teemoista/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:115:\"https://fi.wordpress.org/2023/06/30/syksylla-kuullaan-ja-opitaan-naista-wordpressiin-liittyvista-teemoista/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 30 Jun 2023 13:49:15 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:10:\"Tapahtumat\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://fi.wordpress.org/?p=1002\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:501:\"[In English version below] Suomen ensimmäinen WordCamp keräsi Tamperelle pari sataa osallistujaa vuonna 2015. Tänä syksynä, 14.-15. syyskuuta, palaamme kaupunkiin josta kaikki alkoi. Tänä vuonna WordCamp Finlandin tiimi haluaa tuoda yhteen koko yhteisön. Olitpa sitten WordPressin käyttäjä, kehittäjä, suunnittelija, markkinoija ja työskentelitpä isommassa toimistossa tai yksin freelancerina, olet lämpimästi tervetullut riippumatta taitotasostasi! WordCampit ovat rentoja, [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Timi Wahalahti\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7368:\"\n<p class=\"wp-block-paragraph\">[In English version below]</p>\n\n\n\n<p class=\"wp-block-paragraph\">Suomen ensimmäinen WordCamp keräsi Tamperelle pari sataa osallistujaa vuonna 2015. Tänä syksynä, 14.-15. syyskuuta, palaamme kaupunkiin josta kaikki alkoi.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Tänä vuonna <a href=\"https://finland.wordcamp.org/2023/\">WordCamp Finlandin</a> tiimi haluaa tuoda yhteen koko yhteisön. Olitpa sitten WordPressin käyttäjä, kehittäjä, suunnittelija, markkinoija ja työskentelitpä isommassa toimistossa tai yksin freelancerina, olet lämpimästi tervetullut riippumatta taitotasostasi!</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordCampit ovat rentoja, vapaaehtoisten yhteisöjäsenten koko yhteisölle järjestämiä tapahtumia. Sponsorit mahdollistavat alhaisen osallistumismaksun, jonka ansiosta useampien eri elämäntilanteissa olevien on mahdollista osallistua, oppia ja verkostoitua.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Olemme erittäin innoissamme tulevasta ohjelmistosta ja puhujista! Parasta on, että iso osa aiheista ja puhujista tulee tyypillisen WordPress-maailman ulkopuolelta. WordCamp Finlandin ohjelmistosta löytyy opettavaisia, oivaltavia ja ajatuksia herättäviä teemoja kaikille.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Tässä pieni katsaus tuleviin aiheisiin:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Analytiikka GDPRn maailmassa</li>\n\n\n\n<li>Ilmastonmuutos ja WordPress, asioita tuumailtavaksi</li>\n\n\n\n<li>Verkkokauppa kokemuksen optimointi</li>\n\n\n\n<li>Miten estää uupumusta töissä ja selvitä siitä</li>\n\n\n\n<li>Avoin lähdekoodi ja WordPress yhteisö, mitä hyödyt niistä?</li>\n\n\n\n<li>Web Platform API ja Gutenberg, modernia Javascript kehitystä WordPressin kanssa</li>\n\n\n\n<li>Terminaali ja WP-CLI</li>\n\n\n\n<li>Saavutettavien sivustojen suunnittelu ja testaaminen</li>\n\n\n\n<li>Parempien ja inklusiivisempien sivustojen suunnittelu, käyttöliittymät ja sisältö</li>\n\n\n\n<li>… sekä paljon muuta!</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">WordCamp Finlandin esitykset ovat perjantaina 15.9. Suurin osa esityksistä pidetään englanniksi, joidenkin ollessa suomenkielisiä.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Edeltävänä päivänä, torstaina 14.9., pidetään kontribuutioilta alkaen kello 16:00. Illan ohjelmassa on työpajatyylisiä mahdollisuuksia antaa takaisin WordPress-projektille ja oppia uutta käytännön kautta. Sinun ei tarvitse osata koodata osallistuaksesi!</p>\n\n\n\n<p class=\"wp-block-paragraph\">Tapahtuman aikana on paljon aikaa tavata tuttuja ja muodostaa uusia ystävyyssuhteita. Muiden tapaaminen ja heiltä oppiminen on yksi suurimmista syistä osallistua WordCamppeihin. Monet osallistujat luovat uransa kannalta merkityksellisiä yhteyksiä tapahtuman aikana.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://finland.wordcamp.org/2023/tickets\">Osta lippusi nyt</a> ja varmista paikkasi tapahtumassa!</p>\n\n\n\n<p class=\"wp-block-paragraph\">Ota myös seurantaan sosiaalisen median tilit <a href=\"https://twitter.com/wordcampfinland\">Twitterissä</a>, <a href=\"https://www.facebook.com/WordCampFinland\">Facebookissa</a> ja <a href=\"https://www.linkedin.com/company/wordcamp-finland\">Linkedinissä</a> jotta saat elokuussa ensimmäisten joukossa tiedon täyden ohjelman julkaisusta. Keskustelu on aktiivista myös WordPress Suomen Slackissa <a href=\"https://fi.wordpress.org/chat/\">#events-wcfi</a> kanavalla ja Facebookin <a href=\"https://m.facebook.com/groups/597228300478293/\">WPWoofi</a> ryhmässä.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">The first-ever Finnish WordCamp gathered a few hundred fellow WordPress enthusiasts to Tampere back in 2015. This September, on 14.-15., our community will return to the city where everything started.</p>\n\n\n\n<p class=\"wp-block-paragraph\">This year the <a href=\"https://finland.wordcamp.org/2023/\">WordCamp Finland</a> organising team wishes to unite all Finnish WordPress users. Content has been planned with all skill levels, employment types and interests in mind. We do not discriminate, and WordPress users, developers, designers, people working in agencies or as a freelancer and other enthusiasts are all welcome, regardless of the experience level.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://central.wordcamp.org\">WordCamps</a> are casual community organised events, made possible by volunteer team and sponsors. Ticket price is affordable — cheap, even — to allow people from all walks of life to attend, meet, share, and learn.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We are more than thrilled about the upcoming lineup of talks and speakers. The best and most exciting part is that many of the topics do come outside of the WordPress world! WordCamp Finland will truly have educational, insightful and thought-provoking talks for everyone.&nbsp;</p>\n\n\n\n<p class=\"wp-block-paragraph\">Here’s a sneak peak of some of the topics:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Analytics in GDPR era</li>\n\n\n\n<li>Climate change and WordPress, things to consider</li>\n\n\n\n<li>Optimizing e-commerce</li>\n\n\n\n<li>Work fatigue, how to prevent it and cope from it</li>\n\n\n\n<li>Open source and WordPress communities, how do those benefit you?</li>\n\n\n\n<li>Web Platform API’s and Gutenberg, modern Javascript development with WordPress</li>\n\n\n\n<li>Terminal and WP-CLI</li>\n\n\n\n<li>Designing more accessible websites and accessibility testing</li>\n\n\n\n<li>Achieving better and more inclusive web design, content and UX</li>\n\n\n\n<li>Security and hacked websites</li>\n\n\n\n<li>…and much more!</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">WordCamp Finland 2023 sessions will take place in Tampere on Friday 15. September. Most of the sessions will be held in English, although there are a handful of sessions held in Finnish as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The day before, on Thursday 14. September, a contributing evening will take place starting at 16:00. The contributing evening will feature workshops where you can contribute and learn about various WordPress-related topics in a hands-on setting. No coding skills required!</p>\n\n\n\n<p class=\"wp-block-paragraph\">During the whole event, there will also be ample time for networking and meeting other WordPress enthusiasts. Getting to meet and learn from other WordPress users face-to-face is one of the main reasons people attend WordCamps. In addition to learning from each other, attendees often make new friends and find employees/employers from the WordCamp crowd.&nbsp;</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://finland.wordcamp.org/2023/tickets\">Secure your tickets </a>now and ensure you’ll get to experience all of the insightful talks and activities with a welcoming community!</p>\n\n\n\n<p class=\"wp-block-paragraph\">The full list of speakers, session descriptions and schedule will be published in early August, so make sure to follow us on <a href=\"https://twitter.com/wordcampfinland\">Twitter</a>, <a href=\"https://www.facebook.com/WordCampFinland\">Facebook</a> and <a href=\"https://www.linkedin.com/company/wordcamp-finland\">Linkedin</a> to get the latest updates. Naturally the WordPress Finland Slack has <a href=\"https://fi.wordpress.org/chat/\">#events-wcfi</a> channel and discussion is ongoing on <a href=\"https://m.facebook.com/groups/597228300478293/\">WPWoofi</a> Facebook group.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:112:\"https://fi.wordpress.org/2023/06/30/syksylla-kuullaan-ja-opitaan-naista-wordpressiin-liittyvista-teemoista/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1002\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"WordCamp Finland palaa 2023!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"https://fi.wordpress.org/2023/03/13/wordcamp-finland-palaa-2023/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"https://fi.wordpress.org/2023/03/13/wordcamp-finland-palaa-2023/#comments\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 13 Mar 2023 16:55:49 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:10:\"Tapahtumat\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"https://fi.wordpress.org/?p=983\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:610:\"Suomen suurin WordPress-tapahtuma järjestetään tänä vuonna 14.–15.9.2023. WordCamp yhdistää kaikentasoiset WordPress-käyttäjät yhteiseen tapahtumaan. Tapahtuma sisältää jotain niin freelancereille, kehittäjille, suunnittelijoille, sisällöntuottajille, digitoimistojen tai mainostoimistojen vetäjille kuin vasta WordPressiä opetteleville. Tapahtumassa voi tavata ja verkostoitua laajasti Suomen WordPress-yhteisön jäseniä aina vasta-alkajista kokeneisiin ammattilaisiin sekä kuulla esityksiä WordPressiin liittyvistä aiheista. Tilaa WordCamp Finland -uutiskirje tai ota jokin [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Teemu Suoranta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2426:\"\n<p class=\"wp-block-paragraph\">Suomen suurin WordPress-tapahtuma järjestetään tänä vuonna 14.–15.9.2023. WordCamp yhdistää kaikentasoiset WordPress-käyttäjät yhteiseen tapahtumaan. Tapahtuma sisältää jotain niin freelancereille, kehittäjille, suunnittelijoille, sisällöntuottajille, digitoimistojen tai mainostoimistojen vetäjille kuin vasta WordPressiä opetteleville.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Tapahtumassa voi tavata ja verkostoitua laajasti Suomen WordPress-yhteisön jäseniä aina vasta-alkajista kokeneisiin ammattilaisiin sekä kuulla esityksiä WordPressiin liittyvistä aiheista.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Tilaa <a href=\"https://finland.wordcamp.org/2023/\">WordCamp Finland -uutiskirje</a> tai ota jokin sosiaalisen median kanavista seurantaan niin saat ensimmäisenä tiedot muun muassa lipunmyynnistä, puhujista ja sponsoroinnista.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Tervetuloa WordCamp Finland -tapahtumaan, nähdään syyskuussa!</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://finland.wordcamp.org/2023/\">WordCamp Finland -sivusto</a></li>\n\n\n\n<li><a href=\"https://twitter.com/WordCampFinland\">Seuraa Twitterissä</a></li>\n\n\n\n<li><a href=\"https://www.facebook.com/events/982809019764836/\">Seuraa Facebookissa</a></li>\n\n\n\n<li><a href=\"https://www.linkedin.com/company/wordcamp-finland\">Seuraa LinkedInissä</a></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\"><em>WordCampit ovat rentoja, paikallisesti järjestettyjä WordPress-aiheisia konferensseja. Tapahtumiin osallistuu niin blogaajia, aloittelijoita, konsultteja kuin myös WordPressiä ammattimaisesti käyttäviä kehittäjiä.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Tutustu myös aiempiin WordCamppeihin:</em></p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://finland.wordcamp.org/2020/\"><em>WordCamp Finland Online 2020</em></a></li>\n\n\n\n<li><a href=\"https://nordic.wordcamp.org/2019/\"><em>WordCamp Nordic 2019</em></a></li>\n\n\n\n<li><a href=\"https://2018.turku.wordcamp.org/\"><em>WordCamp Turku 2018</em></a></li>\n\n\n\n<li><a href=\"https://2018.jyvaskyla.wordcamp.org/\"><em>WordCamp Jyväskylä 2018</em></a></li>\n\n\n\n<li><a href=\"https://2017.helsinki.wordcamp.org/\"><em>WordCamp Helsinki 2017</em></a></li>\n\n\n\n<li><a href=\"https://finland.wordcamp.org/2016/\"><em>WordCamp Finland 2016</em></a></li>\n\n\n\n<li><a href=\"https://finland.wordcamp.org/2015/\"><em>WordCamp Finland 2015</em></a></li>\n</ul>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"https://fi.wordpress.org/2023/03/13/wordcamp-finland-palaa-2023/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:3:\"983\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:35:\"https://fi.wordpress.org/news/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:4:\"site\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"13096039\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";O:48:\"WpOrg\\Requests\\Utility\\CaseInsensitiveDictionary\":1:{s:7:\"\0*\0data\";a:11:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Wed, 22 Apr 2026 23:07:16 GMT\";s:12:\"content-type\";s:34:\"application/rss+xml; charset=UTF-8\";s:4:\"vary\";s:37:\"Accept-Encoding, accept, content-type\";s:6:\"x-olaf\";s:3:\"⛄\";s:13:\"last-modified\";s:29:\"Thu, 04 Dec 2025 16:58:28 GMT\";s:4:\"link\";s:61:\"<https://fi.wordpress.org/wp-json/>; rel=\"https://api.w.org/\"\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:2:\"br\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 2\";}}s:5:\"build\";i:1727736619;s:21:\"cache_expiration_time\";i:1776942436;s:23:\"__cache_expiration_time\";i:1776942436;}','off'),
