:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:44;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"Matt: JAŸ-Z Returns\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=151726\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:26:\"https://ma.tt/2026/03/hov/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:851:\"<p class=\"wp-block-paragraph\">Since <a href=\"https://www.nytimes.com/interactive/2017/11/29/t-magazine/jay-z-dean-baquet-interview.html\">he spoke to Dean Baquet in 2017</a>, JAŸ-Z hasn&#8217;t done an interview. Hov&#8217;s back! <a href=\"https://www.gq.com/story/jay-z-cover-interview-april-2026\">He sat down with GQ</a>, and it&#8217;s a lovely listen and read. </p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">We played enough defense, 2026 is all about offense.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Your morality defines who you are, not what you’ve attained.</p>\n</blockquote>\n\n\n\n<figure class=\"wp-block-embed alignwide is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 30 Mar 2026 00:44:41 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:45;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:99:\"Gutenberg Times: Gutenberg Changelog #129 Artificial Intelligence, WordPress 7.0 and Gutenberg 22.8\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://gutenbergtimes.com/?post_type=podcast&p=45087\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"https://gutenbergtimes.com/podcast/gutenberg-changelog-129/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:66144:\"<p class=\"wp-block-paragraph\">In this episode, Birgit Pauli-Haack welcomes Beth Soderberg to discuss key updates in WordPress 7.0 and Gutenberg 22.8. They kick off with small talk about shifting seasons in Munich and Virginia before diving into the new content guidelines in Gutenberg 22.7, focused on standardizing editorial voice across AI and human content contributors. Both speakers express healthy skepticism about AI-generated content, stressing that while AI assists with research and “grunt work” like alt text or excerpts, the core value in writing remains human expertise and review. They caution about automation pitfalls and emphasize validating all AI outputs.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The discussion shifts to the new WordPress AI connectors, which let users connect to services like OpenAI, Gemini, Anthropic Claude, and others—including local providers such as Olama and European alternatives like Mistral. Birgit Pauli-Haack explains the evolving infrastructure allowing developers to add and switch connectors with ease, and encourages the community to experiment and test.</p>\n\n\n\n<p class=\"wp-block-paragraph\">A central topic is the release of WordPress 7.0, with a highlight on the increased minimum PHP requirement to 7.4, likely to disrupt agencies with older sites. The admin’s new look-and-feel is poised to confuse some clients, demanding extra support from agencies. Beth Soderberg also celebrates practical improvements: cover block video embeds using external sources, block visibility by screen size, pattern overrides, breadcrumbs block, and streamlined font management. Both speakers note the importance of hidden, friction-reducing features and the advancement of developer-facing infrastructure. The episode closes with a preview of ongoing enhancements in Gutenberg 22.8 and beyond.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-129/#shownotes\">Show Notes</a> / <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-129/#transcript\">Transcript</a></p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Editor: <a href=\"https://www.linkedin.com/in/sandy-reed/\">Sandy Reed</a></li>\n\n\n\n<li>Logo: <a href=\"https://markuraine.com/\">Mark Uraine</a></li>\n\n\n\n<li>Production: <a href=\"https://icodeforapurpose.com\">Birgit Pauli-Haack</a></li>\n</ul>\n\n\n\n<p class=\"has-larger-font-size wp-block-paragraph\" id=\"shownotes\"><strong>Show Notes</strong></p>\n\n\n\n<h2 class=\"wp-block-heading\">Special Guest: Beth Soderberg</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://bethink.studio/\">Bethink Studio</a></li>\n\n\n\n<li><a href=\"https://profiles.wordpress.org/bethsoderberg/\">WordPress.org Profile + Slack</a></li>\n\n\n\n<li><strong>Talks by Beth Soderberg</strong>\n<ul class=\"wp-block-list\">\n<li><a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-122-gutenberg-21-8-and-wordpress-6-9/\">Gutenberg Changelog #122 – Gutenberg 21.8 and WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://wordpress.tv/2025/07/25/my-process-for-building-a-custom-wordpress-theme-in-2025/\">My Process for Building a Custom WordPress Theme in 2025</a></li>\n\n\n\n<li><a href=\"https://wordpress.tv/2020/04/16/bill-ericksonellen-bauer-beth-soderberg-case-studies-how-to-prepare-your-theme-for-gutenberg/\">Bill Erickson,Ellen Bauer, Beth Soderberg: Case Studies – How to Prepare your Theme for Gutenberg</a></li>\n\n\n\n<li><a href=\"https://wordpress.tv/?s=beth%20soderberg&amp;sort=newest\">And more</a></li>\n</ul>\n</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">AI in WordPress</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/ai/2026/03/23/guidelines-lands-in-gutenberg-22-7/\">Guidelines Lands in Gutenberg 22.7</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/ai/2026/03/25/call-for-testing-community-ai-connector-plugins/\">Call for Testing: Community AI Connector Plugins</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/plugins/ai-provider-for-openrouter/\">AI Provider for OpenRouter</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/plugins/ai-provider-for-ollama/\">AI Provider for Ollama</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/plugins/ai-provider-for-mistral/\">AI Provider for Mistral</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/plugins/ai/\">AI Experiements plugin</a></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>WordPress Core and Gutenberg</strong></p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2026/03/25/wordpress-6-9-2-retrospective/\">WordPress 6.9.2 retrospective</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/news/2026/03/wordpress-7-0-release-candidate-2/\">WordPress 7.0 RC2</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/25/whats-new-in-gutenberg-22-8-25-march/\">What’s new in Gutenberg 22.8? (25 March)</a></li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Dev Notes</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2026/03/16/pattern-overrides-in-wp-7-0-support-for-custom-blocks/\">Pattern Overrides in WP 7.0</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/15/pattern-editing-in-wordpress-7-0/\">Pattern Editing in WordPress 7.0</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/15/block-visibility-in-wordpress-7-0/\">Block Visibility in WordPress 7.0</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/15/dimensions-support-enhancements-in-wordpress-7-0/\">Dimensions Support Enhancements in WordPress 7.0</a> </li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/15/custom-css-for-individual-block-instances-in-wordpress-7-0/\">Custom CSS for Individual Block Instances</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/15/new-block-support-text-indent-textindent/\">New Block Support: Text Indent (textIndent)</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/18/introducing-the-connectors-api-in-wordpress-7-0/\">Introducing the Connectors API in WordPress 7.0</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/24/introducing-the-ai-client-in-wordpress-7-0/\">Introducing the AI Client in WordPress 7.0</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/24/client-side-abilities-api-in-wordpress-7-0/\">Client-Side Abilities API in WordPress 7.0</a></li>\n</ul>\n\n\n\n<p class=\"has-large-font-size wp-block-paragraph\">Stay in Touch</p>\n\n\n\n<div class=\"wp-block-group\"><div class=\"wp-block-group__inner-container is-layout-flow wp-block-group-is-layout-flow\">\n<ul class=\"wp-block-list\">\n<li>Did you like this episode? <a href=\"https://lovethepodcast.com/gutenbergchangelog\"><strong>Please write us a review </strong></a></li>\n\n\n\n<li>Ping us on X (formerly known as Twitter) or send DMs with questions. <a href=\"https://twitter.com/gutenbergtimes\">@gutenbergtimes </a>and <a href=\"https://twitter.com/bph\">@bph</a>.</li>\n\n\n\n<li><em>If you have questions or suggestions, or news you want us to include, send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a>. </em></li>\n\n\n\n<li><em>Please write us a review on iTunes! <a href=\"https://gutenbergtimes.com/itunes/\">(Click here to learn how)</a></em></li>\n</ul>\n</div></div>\n\n\n\n<p class=\"has-large-font-size wp-block-paragraph\" id=\"transcript\"><strong>Transcript</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Welcome to our 129th episode of the Gutenberg Changelog podcast. In today&#8217;s episode we will talk about WordPress 7.0 and Gutenberg 22.8. I&#8217;m your host, Birgit Pauli-Haack, curator of the Gutenberg Times and full-time core contributor for the WordPress open source project sponsored by Automattic. With me today, and I&#8217;m really happy about that, is again Beth Soderberg, founder and CEO of Bethink Studio, a full-service boutique agency and of web experts to tackle any project. Beth has been a longtime WordPress theme builder and WordCamp speaker. She&#8217;s also been an early adopter of the blog editor and block themes. Beth, how are you today? Welcome to the show.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I am well. How are you today? Thank you for having me.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>I&#8217;m good, I&#8217;m good. We have winter in Munich again. It was spring and now it&#8217;s back to winter. So I&#8217;m happy to get out of the town for WordCamp Asia next week. So yes, I&#8217;m really happy about that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>We&#8217;ve been switching from winter to spring every day here. Every day in Virginia. Yep. It&#8217;s different every day.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. So what&#8217;s the weather doing? Well, I don&#8217;t know.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>No, I&#8217;ve had to look every morning because it&#8217;s in the last week I&#8217;ve been outside in a winter coat and a tank top and rain boots and you just don&#8217;t know. You wake up and it&#8217;s a surprise.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Well, it&#8217;s the beauty of surprises. But who likes surprises? I want my spring be steady.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg:</em> Yeah, I agree.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Announcements</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>All right, so under the announcements we have one thing that&#8217;s that content guidelines landed in Gutenberg 22.7. We didn&#8217;t really talk about it with Maggie Cabrera at the last episode, but the WordPress AI team has launched guidelines. They are live experiments in the Gutenberg 22.7 or Gutenberg plugin and this project creates a single source of truth for site standards and ensures that everyone, humans and AI tools, follow the same editorial voice and content rules. By providing this infrastructure layer, WordPress can finally maintain a consistency across content contributors. So that&#8217;s so far from the experiment post that I&#8217;m definitely going to share in the show notes. When you want to use AI for helping you produce content, you definitely want to store some of the standards somewhere. And the experiment lets you do this on your website in your interface with a nice interface for that. I don&#8217;t know how I feel about this because I have been using AI quite a bit in the last two years and some of it was for content creation ideas. But the writing is still kind of mostly a human factor. But it helps me for research and it helps me for learning. So I&#8217;m not quite sure how that translates to a WordPress site, but I guess if you have ongoing content reproduction that is more service oriented, then you might want to use the help of LLMs or something like that. What do you think?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I&#8217;m skeptical for the same reasons. I think that I have had clients ask for something like this. But the more those clients have actually used AI to create content, the more those very same people who had announced that they were going to create all of their content through AI decide that they are going to use AI for research and then create their content. So the AI in actual practical use has been more about reducing friction in that discovery research phase of writing and less about creating the writing itself until you get to the editing part when it becomes helpful again for grammar. But that actual connecting ideas and proving expertise piece is where AI can&#8217;t do it. And you need something, somebody who actually understands what they&#8217;re reading to piece together the logic of it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>I can also see, and we will see this in that you use AI to write an excerpt or to give you suggestions for titles or make sure that there&#8217;s an alt text on the image. I think these grunt work tasks kind of thing of AI is really helpful, but I think the human ideas are still. Well, humans hallucinate so much better than AI can ever can. Right.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>How can we possibly replicate that? And I think there&#8217;s also a place for it with things like you mentioned the alt text. Right. Having it generate them all and then validating that it did it correctly is much faster than writing it all yourself. That is where we&#8217;re going to see these things actually become practical. Right. There&#8217;s a lot of big ideas about it, which makes sense when you&#8217;re dealing with a new technology and an innovation in a major workflow. But in actuality, I think that&#8217;s more how people are going to use it. And I think if people set it up to automate everything and then never look at it, never validate it, that&#8217;s people are just going to get in trouble over that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And I, you know, I use it a lot to generate fake content so that I can show someone what something will look like knowing that the content I&#8217;m showing them is not real. Right. But when you&#8217;re dealing with real content, the biggest mistake I&#8217;ve seen over and over again, and humans will learn because we always eventually do. But the mistake is not reviewing what AI has done.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, definitely. Yeah. It&#8217;s not a replacement. It&#8217;s a tool that you need to validate like any other tool you have to do. I can see that if you have a longer text like for 4,000 words or something like that, you could actually use AI to identify the gaps. If a reader goes through it and say, okay, there is a gap because it didn&#8217;t explain why something happens. I think those tips are really helpful, especially when you have longer text or you want to focus on one problem and just kind of figure out what&#8217;s in scope and out scope. But I think that&#8217;s more like an advisory kind of thing and not a doer.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, validating. Because sometimes I love Grammarly Pro. Grammarly the free version is very annoying, but if you pay it becomes a really useful tool. But even then, the content suggestions it makes, sometimes they tighten up your language and they make it. They add the commas, which is the thing that I don&#8217;t do naturally on my own apparently. But sometimes they change the meaning completely.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And that&#8217;s when you&#8217;re like, nope, thanks for the suggestion. That&#8217;s a no.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I think how this type of thing used well, will make people more efficient. But I also can see it creating a mountain of work for somebody who doesn&#8217;t actually need to go through all of these ridiculous suggestions about it. And I think that deciding when to use it, when it makes sense, those strategic decisions about how to use it are going to be what makes it either something that really helps somebody in their publishing workflow or really hinders somebody else.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Well, if you&#8217;re a single blog blogger having a little editor go through that and give you some tips that might not be a bad idea, but sometimes. But right. If you have been blogging for many, many years, you don&#8217;t need things like that. It changes your voice and it changes the outlook. That&#8217;s what the guidelines are actually for that you can create some of the guidelines as it meant to be to help AI to streamline some of that stuff and also to know about what you want to do. And that certainly helps.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, yeah.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Community Contributions</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Speaking of AI, what I found in so in 7.0 WordPress. So getting closer to that release, there is now a new connectors page that you could connect to an OpenAI to Google Gemini or to Anthropic Cloud from your site. And if you have certain tools that help you with those connections. So there are AI providers for other AI systems like I just discovered three of them. One is the AI provider for Open router or router depending on which English speaking country you go to. It&#8217;s a little bit different. So open, I say Router is a service that lets developers use many different AI models like those from Google OpenAI but also others through one simple connection. And the provider was developed by Jonathan Bossenger who is on the AI team and talks about AI on the developer blog. There&#8217;s also an AI provider for Ollama, and Ollama is a local system where you can connect local LLMs so you can download an LLM set and Ollama helps you connect that with the task that you want to do. The benefit of Ollama is that it&#8217;s on your server and it doesn&#8217;t go out to the third-party services, but you still need a provider and connector to it. You can do this on any VPS connection or virtual private server system because you have room and space there to download and add certain things. But it&#8217;s definitely important for companies that want to not get data outside of their system. </p>\n\n\n\n<p class=\"wp-block-paragraph\">And the last one is for Europeans. The AI provider for Mistral. Mistral AI is a French AI company founded in 2023 by a former Google DeepMind and Meta researchers and they built and publish large language model and be a respected independent AI in Europe. Speaking of this, what that all comes together is that the AI team and with that Lauri Saarni published a call for testing for community AI connector plugins. There are certain links to the plugins and the connectors, so it would be really cool if you&#8217;re interested in that part of it, to actually go ahead and test things and report back what you find and what you didn&#8217;t find and how it all works for your site. It&#8217;s a totally different approach for working with the site using AI as we discussed. But it might be pretty interesting for developers to connect with all those AI providers and provide services in a plugin or something like that. </p>\n\n\n\n<p class=\"wp-block-paragraph\">And if you are not a developer, you can install the AI Experiments plugin that also comes from the core AI team and it will show up on the Connectors page with a link to the plugin and what you can do with it. And it has these things like create an excerpt or check the alt text or create a featured image just so you can kind of get a feel for these kinds of works on the WebPress site. Do you have, do you think you have a need for. To kind of use some of the providers for your agency or for some clients?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I think for some clients it has started. I think that for the agency itself, not yet. We have started to do more writing publicly, but really what we&#8217;re doing is turning internal communications to clients into public facing documentation so that we can point to them more easily. So it&#8217;s not something we need help with. In the same way, I think for some clients we have started to integrate things like this in an experimental way. Right. And there are, as with anything that&#8217;s new, people don&#8217;t know how to use these things yet. And I am not against experimenting with a new thing. I love the new stuff, but at the same time I&#8217;m cautious about putting new things into a production environment without really making sure that it makes sense. Some of these, in terms of experimentation, like I will install them and actually Grammarly is a great example. It took me several years to decide that I was fine with it because I tried it and it was annoying. And then a few years later I tried it again and it was still annoying. And then one day I realized that it really was like their premium suggestions really were fixing my comma issue, which is a known issue I have with writing and grammar. I just don&#8217;t put commas anywhere.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>I put them in randomly and so there&#8217;s a few commas.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>But you know, I experimented with the tool probably three times before I was like, you know what, let me try the premium version and see how that goes. And I tried it and a few days later I was like, yeah, this is actually making my writing better. But it was one of those, like I was monitoring over time if it really made sense with my workflow.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, yeah. And that&#8217;s how I approach it too.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, yeah, yeah. That&#8217;s how I felt about these. And I think what&#8217;s exciting about it is that the infrastructure to do it is becoming more full fledged. But that does not mean people know how to do it yet.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack:</em> Right.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And so that&#8217;s the next step is that experimentation phase collectively of how, what. How can we make these tools that we&#8217;ve now created function in the best way.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>So I really appreciate that the WordPress core developers think about the plumbing of all these services and putting it all the foundation in to open up that total space for freedom for the developers. And there&#8217;s a standard there on how to approach certain. So if you are as a site owner, don&#8217;t have a plugin that kind of taps into LMMs and you open up Gemini for it, you couldn&#8217;t switch just easily to Claude when you think that&#8217;s a better fit for that problem, but the plugin will still work. So that&#8217;s actually what this whole connector thing is about. And it just came up as for the AI providers, but actually the connector API is for any external service standard. So a standard for any external service. So if you need the OpenStreetMap on your site and you have an API key, the plugin can actually use the connectors API to monitor those API keys and just put it in there. The plugin doesn&#8217;t have to come up with its own interface for that, which a lot of plugin developers did for the last 15 years. Yeah. But now they can could actually throw away that piece of the plugin and just tab into the connectors API and don&#8217;t have to maintain that piece of the code.</p>\n\n\n\n<h3 class=\"wp-block-heading\">What’s Released &#8211; WordPress 7.0 RC2</h3>\n\n\n\n<p class=\"wp-block-paragraph\"> But anyway, so that&#8217;s kind of the bigger picture behind it. And that&#8217;s all coming with WordPress 7.0, which we are now getting to the more practical stuff of WordPress 7.0. So first of all, the WordPress 7.0 release candidate 2 has been published this week. It&#8217;s crunch time. The final release is only two weeks away. So if you haven&#8217;t tested it, now is really the time to get in there and figure out if your theme plugins and sites actually still work with 7.0, and the developer notes are published. The field guide is in the works and I will continue the list of dev notes in the show Notes like we did the last two episodes. I also know because I have been working on it. The Gutenberg Times Source of Truth is almost done and will be published before this episode actually hits your favorite podcast app. So you get an additional link there. So, Beth, did you get a chance to look over the WordPress 7.0 features? What are the most important ones for you and your fellow agency owners and developers? Is there anything that you are really excited about?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yes and yes. So the first thing that I think is going to be honestly hugely problematic for a lot of agencies is the change in PHP minimums, because I think that there are. I know that there are a lot of folks sitting on older sites, older themes, maybe they&#8217;re stuck at PHP 7.1 and there are old things out there. And I think that this PHP requirement jump is going to catch some people off guard. So it jumps from it&#8217;s we&#8217;re now requiring 7.4.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And if you do, it&#8217;s already 6.9.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Right?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah. But I think this is going to hit harder. Okay. Because people are going to want the new stuff. Like there&#8217;s a lot in here that is really great and I&#8217;m starting with the thing that I think is going to be most disruptive because I think that people are going to want the other stuff, right? And so I think that that&#8217;s going to catch some people off guard. The other thing that I think is going to be really important is the new admin look and feel because people have been training their clients for many, many, many, many, many years with what it looks like now. And there is a client education need here because when the admin changes, even in minor ways, you get clients that come back and say, what happened? I don&#8217;t know how to do it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Okay, Even if nothing changes except the color, right?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Where did it go? Why is this different? And did I do something? Did I write the, that human element of like, hey, you&#8217;re okay, it&#8217;s gonna look a little different, but I promise you&#8217;re gonna be able to do it. Just holler if you have any questions. Right? Because I think that there&#8217;s a lot of at least working with long term clients where you become sort of an advisor on the technology rather than a day to day implementer. And for those folks with something like this, I, what I like to do is say, hey, heads up, we are doing, we never do the major core updates right away. I am a let me see how it goes for everyone else.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Right.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Type and then if it seems okay, then I&#8217;ll go for it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack:</em> So you&#8217;re one of the ones who wait for 7.0.1.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Absolutely. Unless it&#8217;s been like three weeks and there isn&#8217;t one. Yeah, right. So I either wait for a period of time or I wait for a point release. And if there&#8217;s a point release, I wait at least 24 hours to make sure there&#8217;s not another point release. But point being though, that this is a big enough shift in terms of what people will see and what people can do.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Which part of the admin is actually the one that will disrupt people&#8217;s minds.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Just I think it looking different at all.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Oh, okay. So we should never change that. Is that what you&#8217;re kind of thinking?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>No, we should absolutely change it. But because we have not changed it for many, many, many years, it will be a surprise. And I think that it&#8217;s easy as folks who are in these systems every day to be like, wow, they finally fixed that. That&#8217;s great. That might be my reaction to many of these changes. Right. But I also know when I log in to pay my credit card. And they&#8217;ve changed it all. And even though the buttons are the same, it looks different. I don&#8217;t have as much confidence about clicking the button. And there&#8217;s this. The vast majority of people who are maintaining the contents on these sites day to day are marketing people, communications people, regular everyday writing people. And they are not sitting there thinking about how the structure of the software works all the time the way we do.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. But they still get their work done.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>They still get their work done. What I like to do with clients is just reduce friction by increasing confidence.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Right. And so, like, my message to them is going to be, hey, you need to know that this is going to look different, but your workflow in terms of the things you know how to do is the same. Don&#8217;t let it freak you out. You&#8217;ve got this. Keep going. Right. But like, just that little bit, because that&#8217;s. That is 100% what gets people. It&#8217;s the smallest stuff. They just need to know, like, hey, the problem&#8217;s not me. Oh, wait, there&#8217;s not a problem. It&#8217;s fine. And then they&#8217;re good.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. Yeah. It&#8217;s the first five seconds. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>It&#8217;s that psychological adjustment. And I think because it hasn&#8217;t changed for so long that it&#8217;s just going to be something that I mentioned.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Is there anything else that you are really excited about or is it just.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I know. Okay.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Things change. Okay. I don&#8217;t like it to change.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Things change. I&#8217;m really, really excited about the cover block video embeds.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>That is really, really going to reduce the size of things as they load for a lot of websites. And that is fabulous. In addition to improving workflow, all of the things around block visibility by screen size make me really happy. I&#8217;m really happy about the changes in the header block. And I&#8217;ve been building this into themes for years. And the only thing that makes me nervous about it is that I need to go back and see how it impacts the things I&#8217;ve already built that replicate this feature.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>But you mean the navigation overlays?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>The navigation overlays. Yeah. Because you&#8217;re going to have such increases in both accessibility compliance and SEO optimization just by virtue of having the option to manage your headings visually versus syntactically. So I&#8217;m very excited about that. I love that our revisions menu now has visual changes.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack:</em> Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Because I know that most people looking at the markup that&#8217;s been in there lately are like, I don&#8217;t know.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. I have to squint so much to look through the code to find things. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And then there&#8217;s a few exciting changes to the navigation and the better workflows for pattern overrides. Yeah, it was there before, but it was one of those mystery off menu features if it was there, if you knew how to find it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, yeah. Right.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>So those are the things I&#8217;m most excited about. I think there&#8217;s some other cool stuff in there and I am excited about the general infrastructure that we were just referencing that is being solidified with this release. And I think that piece may not be as exciting on the outset because it&#8217;s infrastructure. It&#8217;s like nonprofits have a hard time funding infrastructure process projects. It&#8217;s the same reason. But it lays the groundwork for a whole new level of experimentation. I&#8217;m excited to see where that goes and I recognize I think you said it very well a few minutes ago the thoughtfulness to create an extensible infrastructure that has gone into these features in the roadmap and sort of planning moving forward.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>You mentioned the cover block video embeds. That means that you can have a video just to catch up with our listeners. It&#8217;s to use a URL to YouTube or to Vimeo and pull that in into a cover block instead of uploading the video to the website because that reduces the cost of hosting and bandwidth for the website. Definitely. And it also you don&#8217;t have to maintain the speed and all that on your own server. So it&#8217;s always good to offset that into a different service. How are you feeling about the manage the fonts from the appearance menu directly instead of hunting it down under the fonts typography menu on the slobber styles,</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg:</em> I&#8217;m feeling really good about that. It remains to be seen for me the biggest issue I have with font management. I am not sure it might be addressed here, but I need to experiment. When you get a font from a total third party non-standard like independent type foundry place getting those integrated, there has still been some friction. So I&#8217;m excited about it being easier to find in general. I think that&#8217;s great. .</p>\n\n\n\n<p class=\"wp-block-paragraph\">I will be experimenting a little bit with if it reduces friction in some of these more edge cases. Because if you&#8217;re using a Google font it&#8217;s great and it&#8217;s been pretty good for a while. But if you are integrating something from another provider, if it&#8217;s a big provider the friction is not as bad. But if it&#8217;s like this obscure type foundry that makes like only these little types of historic fonts, which I run into recently, getting it actually integrated properly, it&#8217;s really hard because you&#8217;re dealing with not the most sophisticated type foundry in terms of the format of their files and they&#8217;re not necessarily plugging in as best as the totally optimized stuff from the more common sources. So, yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Is it more a format issue or is it more kind of how it scales in different font sizes and different typography features?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>It&#8217;s a format issue with the font files themselves. And so I think some of it is probably an education piece for people who make fonts, but I also know that most developers don&#8217;t know that much about how fonts are made. And so when you put those two things together, you create some problems. But I think this is a huge step towards getting to the point of being able to solve the edge cases. Right. Because right now finding where you manage the fonts is difficult.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Right? Yeah, totally. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>We&#8217;re going in a great direction, getting into the nitty gritty of which font providers are supported and that I think that&#8217;s the next step from here, personally, because I do think there&#8217;s a homogeny that started from a type standpoint around everyone&#8217;s using Google fonts because they. It&#8217;s easy.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. But it&#8217;s also problematic for European sites.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, right, yeah. Because the different requirements over whether you&#8217;re hosting the font files or Google is hosting the font files, like, then you&#8217;re getting all into all of these legal technicalities of where the font is and who owns it. And I&#8217;m glad I&#8217;m not a lawyer.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, me too. So, all right, so there are a few developer goodies coming, so to speak, down the pipeline. The PHP-only block registrations and then the pattern overrides for custom blocks that you already mentioned. Those. I think there are a few smaller stuff like the HTML block enhancements where you can put the CSS separately from the JavaScript and the HTML. You could actually kind of create your own little app there, depending on what privileges you have. I found that there are some problems when you don&#8217;t have admin privileges. The HTML block really gets scrambled, but that&#8217;s an overall kind of problem with the capabilities, I think. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Oh, I forgot the breadcrumbs block. That. That&#8217;ll help a lot of things.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>So. Yeah, yeah. I&#8217;m also sure that a lot of agencies and site owners already had that problem solved through like for instance, the Yoast SEO plugin had already programs for many, many years. Yeah, yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>But I like my websites to be as lean and efficient as possible. And this feels like when, for a long time I was using Coblox for accordions. Right. And in the beginning, coblox had a lot of things that Core didn&#8217;t. And so you were using a bunch of things. And eventually it became that I was only using the accordion everywhere. And then one day it became possible to do the equivalent in Core and I was like, great, I can get rid of this plugin that&#8217;s only doing this one thing, but has all this other stuff. And I think that&#8217;s what makes me excited about this. Yeah. You can do it through Yoast. There&#8217;s a number of ways to do it. There&#8217;s some independent breadcrumbs block plugins that are really good.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. I know that Justin Tadlock had a very good breadcrumbs plugin and he was advising on the core implementation there.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, right. Yeah. And I&#8217;ve used Justin Tadlock&#8217;s breadcrumbs plugin for a long time, and I&#8217;m not going to rip it out of something just because it&#8217;s there. It works. It&#8217;s good. But for something else where, like, you only have this one thing that you&#8217;re really using in this big suite of plugins. Yoast is one of them. Jetpack is one of them. Any sort of like cadence blocks, code blocks, any collection of a large number of things when you&#8217;re only using one of them, you should be considering the idea that maybe you shouldn&#8217;t use it at all. And that&#8217;s what makes me excited about the ability to do this through Core, because it allows for some of that extra bloat to be stripped away in some circumstances.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. All right. Anything else that you want to kind of cover on 7.0 for your agency of developing theme building needs?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I think that the PHP-only block registration, we sort of glanced over it, but I think that&#8217;s a very exciting big deal. It opens up, you know, the whole challenge. I think from a developer standpoint, the whole time with Gutenberg has been, how do I level up to do this new thing? How do I level up to do this new thing? And this opens that door wider. And anything that we are doing to open that door wider is great. Similarly, there&#8217;s a few things in here that are just really tiny that I think will help people. They&#8217;re not like, again, reducing friction. So little enhancements to the query loop, adding some new navigation stuff that is just really tiny, but really Helpful dimension support for width and height. That sounds crazy, right? Like it&#8217;s little tiny stuff that reduces friction and stuff. So there&#8217;s more of that in here. Like the concept of the grid block being responsive is really great.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Well, it was responsive before, but there was a setting where it wasn&#8217;t and that&#8217;s kind of changed now, right? Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>So, yeah, I just. There&#8217;s a lot of hidden goodies in here that reduce friction. I do think the biggest things to look out for are if your themes are compatible, if your plugins are compatible, and if you have built in things that replicate some of this functionality. How does that work? Because we&#8217;re starting to enter, at least for how I&#8217;ve been building themes, a zone where things I have done historically to account for some of these needs are being subsumed by core, which is great. I just don&#8217;t know how it&#8217;s going to work. So, you know, I think that&#8217;s going to be different for everyone in terms of which things it is. But hopefully, and I say hopefully because I know that we have a unified development philosophy about how we build our themes and there&#8217;s sort of a continuous logical thread for our themes as they&#8217;re built over time. Hopefully agencies who have an internal logic to how they have been building themes can look at this list and say we should look at how we do that and make sure it still works. Yeah, right. Because there&#8217;s also going to be agencies where they have a mishmash of things and they don&#8217;t know and it&#8217;s going to be a one off for each site to see what happens. And you know, that goes for anybody who&#8217;s inherited themes too.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, but that&#8217;s also for any of the WordPress releases. Yeah, you have to go through a certain testing phase there.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, I think that&#8217;s true. And I think some of this is honestly that it&#8217;s been a while since we&#8217;ve had a major release and so the quantity of little things feels more.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, absolutely.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And I think that&#8217;s part of why my reaction is this way, because I haven&#8217;t had this thought process.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>At least five months.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>At least.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah, six months. Nine came out December 2nd.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Right. And so as somebody who was used to the four times a year cadence, it is longer and what&#8217;s packed into it is greater. And so I don&#8217;t think that&#8217;s necessarily bad, but it is an adjustment in terms of absolutely how you review things and what you&#8217;re looking for. And it&#8217;s more of a. This one feels more like a surprise. Not that it is a surprise, but it feels more like a surprise because it is not on this schedule that I had come to expect. Right. And I think we&#8217;re getting towards a new schedule, which is really great. But until we are all psychologically adjusted to whatever that new schedule is, it&#8217;s going to be a slightly bigger task to review because there&#8217;s more. And psychologically it&#8217;s going to be like, oh, right, I guess that&#8217;s happening and you&#8217;re, you know, you got to go do it. Yeah. So I just think it&#8217;s just. There&#8217;s a little more and the timing is not as predictable.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. And I think that the break that was in Twenty Twenty-Five kind of skewed that anyway. Yeah. So we had an April 25, we had a release, and then the last. The next one wasn&#8217;t until December. Yeah. So there were eight months that kind of 15 Gutenberg plugin releases. It didn&#8217;t feel that much that it is now in 7.0, because that was just kind of coming up out of that pause. And now there&#8217;s a real excitement about the Real Time collaboration. There&#8217;s excitement about AI. Yeah. So, yeah, it feels that there are quite a few heavy new features in there that also kind of drown out some of the really quality of life things that we have been waiting for quite a bit here.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Right. Yeah. And I. I think it&#8217;s like coming back from a long vacation, like, oh, ooh, this is really exciting, you know, but that&#8217;s how. That&#8217;s how it feels and it&#8217;s good. But it is, absolutely. I think that Twenty Twenty-Five, you didn&#8217;t have to be as vigilant because it wasn&#8217;t happening.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yep, it was a good break.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I think everyone needed it. Honestly, I think everyone really needed it. I know I needed it. But it is, you know, getting back into the. The groove of things is. Is where we are now.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>So. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>For which I am thankful, but it&#8217;s still an adjustment.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Me too. Yeah. And now with 7.0 kind of out the door almost. Yeah. </p>\n\n\n\n<h3 class=\"wp-block-heading\">Gutenberg 22.8</h3>\n\n\n\n<p class=\"wp-block-paragraph\">We are looking at Gutenberg 22.8 that has been released. Was released this week also kind of what comes into 7.1. It&#8217;s already starting and people are discussing things. So although there were quite a few PRs that were either all part of the new WordPress UI package that hasn&#8217;t been merged into Core yet, or it&#8217;s bug fixes for the connectors or the Real time collaboration for 7.0, so some of the PRs are actually backported to the release candidates and the beta to the release candidates. </p>\n\n\n\n<p class=\"wp-block-paragraph\">But let&#8217;s talk about some of the things that will not be in 7.0, but definitely in 7.1 and what&#8217;s new in the Gutenberg plugin. So the first thing is the navigation support for the current menu item. So in theme JSON, meaning when you have a navigation and you&#8217;re on a current page that&#8217;s part of the navigation, how do you signal that you are at the current page right now in the navigation? And that has been missing for quite a while or people have just did some CSS workaround of that, but now you can actually style that in theme JSON. And so this is cool. What&#8217;s also cool is that there is an interface for the states like Hover Focus current. I&#8217;m not sure if that&#8217;s going to be in there, but it&#8217;s also part of making the navigation and the hover states and the pseudo support that comes into 7.0, but now it comes also to the interface. So that&#8217;s pretty cool.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>That&#8217;s my favorite part.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Which one?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg:</em> The navigation stuff again. The interface around the navigation has gotten a lot better in various iterations of Gutenberg, but there&#8217;s still some stuff that you&#8217;d think you would be able to do that you can&#8217;t. And that&#8217;s what some of this is filling in.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Birgit Pauli-Haack: There have been some great work. Some of it gets into 7.0 and some of it is still ongoing. So I really like the navigation that&#8217;s actually in 7.0, that you can create pages and publish them and have them in the navigation in one workflow kind of thing. You don&#8217;t have to get out of it. You may have to think about it. You just kind of create the page and then you fill it in with content later.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah. And I&#8217;ve seen that in other systems. I don&#8217;t remember what that is. One of those things where some of these changes, you&#8217;re like, you know, I saw that once somewhere. Was it Joomla? Was it Drupal? Was it whatever? I don&#8217;t know. But I liked it. And now it&#8217;s here. And that&#8217;s good.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Absolutely.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And that&#8217;s how I feel about that because I do appreciate the tiny little decisions that are being considered here by the core team because it seems very small. But the amount of friction you&#8217;re reducing and the amount of time you&#8217;re saving for people is huge.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>It&#8217;s huge. Yeah. Yeah. And it&#8217;s millions of millions of site owners that kind of have advantage. Yeah. Do you want to take the next</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>thing, the tabs menu. So I think this is going to be fun too. So basically we&#8217;ve got a refactor of the tabs menu block. So it&#8217;s basically making this more efficient and making some templating changes to how the tabs block works. And if you look at the actual PR for it, there&#8217;s really good, very detailed descriptions of how. So it&#8217;s making it very clear of it&#8217;s no longer using the template block duplicated in PHP and instead it&#8217;s rendering with per tab context.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Right.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>And that&#8217;s like all gobbledygook to some listeners. Maybe, but like really what it&#8217;s doing is making it more efficient and making it more extensible from a code perspective.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>And also for theme developers.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, right. And making it more possible again, opening that door a little wider for more people to be able to work within the code infrastructure. Because that has been the thing that&#8217;s been the biggest challenge in terms of developer adoption of Gutenberg.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. And the refactor was also necessary to bring it in line with the approach for the accordion block so that certain methods and certain functions can be replicated in a similar way for the TAPS block. I was actually sad to hear that very early that it won&#8217;t make it into 7.0, but I think that was one of the reasons where they said, okay, let&#8217;s, let&#8217;s see if we can kind of align it a little bit more with the accordion block. And it&#8217;s no surprise that Sarah Norris, who has been a guest here at the Changelog quite a bit, she also created the accordion block and she has been now instrumental on the restructure of the tabs menu and inner blocks to get it in line and we have make it more streamlined for developers and theme builders.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>The one thing to add that is an exciting piece for especially theme developers is the addition of anchor support for the tabs. So that&#8217;ll help a lot in terms of things like navigation structures and feasibility. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>And also to kind of interlink different pages. You can link to some of the tabs if it&#8217;s interesting enough. Yeah. So I know that WooCommerce is using that for their products template. So they have built their own one back then and now they get a little bit closer to core, which makes it more extensible and also appreciative they don&#8217;t have to maintain the code for it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yep, absolutely.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Which is quite a bit. So right now I&#8217;m fishing around on my computer to find my notes again. So here we are. All right,</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>the next one, the showing one&#8217;s own presence and collaborative editing sessions is I think existentially important and just is really going to help this UI experience from the baseline that&#8217;s being released in 7.0.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>So yeah, I&#8217;m pretty sure that it will actually come to 7.0. That made it into the release. That&#8217;s good. So the next piece is the one that you can have the site logo and icon screen in the design panel. So in the site editor there&#8217;s another menu item now to update the site logo and the icon screen directly from the site editor. So you don&#8217;t have to go out into the settings page and upload everything that you need or into the site logo block or header. You can do it right there from, from the menu. So it&#8217;s really an interesting update to change the site logo and the site icon directly in the design site editor.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>It&#8217;s reducing friction. I think that there&#8217;s a workflow confusion. There&#8217;s the customizer that has become this vestigial organ that sometimes you need, sometimes you don&#8217;t need. Where&#8217;s this? Wait a minute, where do I add css? Is it over here? Is it over here? Is it over here? Could it be here? And I think that we&#8217;re pruning what we need to do through alternate interfaces through changes like this. And the more we can streamline, the better because the biggest confusion I&#8217;ve seen is actually with brand new or like more junior developers who do not know the quote old way. And so the idea that it&#8217;s even there, like they&#8217;ll get stuck because they can&#8217;t figure out where it could possibly be coming from. And then some old timer is like, oh, it&#8217;s over here in this menu that you can&#8217;t see anymore.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. Or yeah. So the site icon at the site logo has been a hidden place and only until now it&#8217;s kind of coming into the forefront. Yes. So the next thing is another one for the collaboration. I just wanted to point out that by default the collaboration on shared hosting is only. It&#8217;s limited to two users and there is also a method for the hosts to either enable that or disable the real time collaboration. So it might not be as obvious when you go on your site and looking for it. You might not be able to get real time collaboration out of the box. You might need to connect with your host to let that enabled because it&#8217;s such an additional load on a server. That certain server configurations are not meant for it to be in yet. So if you&#8217;re on a virtual private host, I think I mentioned it before, it wouldn&#8217;t. It was a different scenario. But it&#8217;s probably easier to get the collaboration working than if you are on a shared hosting with 10,000 websites on a. On a server where the hosting company will probably restrict that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah, I think that there&#8217;s going to be a lot of shifts in hosting, either requirements, configuration, pricing options, etc. as a result of all of these changes. And I don&#8217;t know what they&#8217;re going to be yet, but we do need to collectively remember that the AI features, the collaboration components, all of those things are resource intensive and are going to shift how hosting is being utilized and therefore the hosts are going to need to respond in order to account for the actual cost of that change. So I think that&#8217;s a big unknown right now and I think it&#8217;s, you know, there&#8217;s a few hosts where they&#8217;re locking in pricing for a few years, which is cool, but at the same time I&#8217;m like, I don&#8217;t know, in three years is this going to be enough to pay for that? What will it be in three years?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>So I think there&#8217;s a shift coming there and I am not gonna even pretend to know enough about all the details to know exactly how that&#8217;s going to play out, but I think that there&#8217;s enough shift in what types of resources we need from our hosting that there will be a shift. There has to be, because it&#8217;s just so much more resource intensive than what we&#8217;ve been doing in the past collectively.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack:</em> Yeah. And that is in line with what you said at the beginning, that the PHP requirements. Yeah, it always is also contributing to that because all the newer features. So there might be a. You can&#8217;t upload upgrade to 7.0 until you update your PHP. That&#8217;s totally sure.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah. And I&#8217;ve read that somewhere. Somewhere I did read that there&#8217;ll be security releases on 6.9 for sites that can&#8217;t go, you know. But then you end up with a situation where you&#8217;re gonna. How many sites are gonna be stuck on 6.9 forever?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>But that has been a problem. Yeah. Because the security team is actually backporting, although officially the release is only supported to 6.8 or something like that, but security team actually backported all the security updates that came with 6.3 or 6.4 to 4 point something. WordPress 4 point something is probably 15 years old. So it&#8217;s still getting security updates. So that definitely is a backwards compatibility promise that even the security team there. It takes a lot of time to backport that. And John Blackburn, one of the leads on the security team, has actually done a retrospective of the latest security updates because you saw that too. It was a. It&#8217;s kind of a galore of releases. 6.2, 6.3, 6.4, 7.4 beta. Yeah, it kind of was in within three days, I think there were four releases.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>It was a lot. Yes. All at once.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>I had a meetup here in Munich and we talked about it. I think the day the 6.4 came out that they were saying, well, is it all hacked or what happened here? Kind of how often do I have to update my WordPress site in a day? And he did a nice retrospective or explaining what happened and what was the reason for that. I&#8217;ll link it in the show notes if you&#8217;re interested. To listeners, it will probably be a little bit less prominent because of all the death notes that came out, but it&#8217;s on the blog on Core.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>I&#8217;m going to go back and listen to that because that hit during a particularly busy time, just for me personally in general. And so it was a little whiplashy to be like what is going on over there? And I think it will be good to be able to go back and just review so that I am aware moving forward of what exactly happened there.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. And back to Gutenberg 22.8. I mentioned it before. There is a feature that implements the state UI for sudo selectors in the global styles. Maggie Cabrera mentioned that in the last episode. It&#8217;s now available in the Gutenberg plugin so you can test it out. It gives you a. In the global styles on the right hand side you can select the design for your pseudo selectors like hover and focus and all that. It&#8217;s really cool. Hover, focus, Focus, visible and active. Yeah, so you can change all those settings for buttons, for instance. And you don&#8217;t have to use theme JSON for it anymore. So this is pretty cool.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yes. And then this one, I think this is fascinating. There is a PR adding client side navigation block with interactive features. That just sounds really fun to experiment with. So what it&#8217;s doing is adding a variant to the Create Block interactive template that allows you to add client side navigation. So this is starting to support the again supporting the infrastructure that exists with actual tooling and UI to use it. So the way that it describes it, this variant provides a self contained working example that mirrors real world patterns, query parameter navigation for pagination, search results, filtered archives and works immediately after scaffolding with no posts or setup required. That&#8217;s really cool. That&#8217;s a really nerdy and very arcane and wonderful. So I&#8217;m excited about that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. And that variant is for the Create block scaffolding feature, if I understood this correctly. Yeah, it&#8217;s a create block latest. So if you create a custom block, you can have the variant for your client side navigation and scaffold that up. That&#8217;s really cool. Yeah. Well, our developer advocacy team, we are working on a so-called showcase for all the good things that you could do with a website or theme, including some of the interactivity API features. And we will probably release that someday in the next two months I would think. And it will be a music site with albums and musicians and artists and using the tabs and using the playlist and block and then also kind of have some interesting changes in the theme. So it&#8217;s for custom post types and all that. So it&#8217;s going to be really cool. I know that Juan Ma Garrido who put the client side navigation template into the gray block scaffolding, he&#8217;s also creating a plugin to have the music play even if you navigate away from that page that had the list of the music. So it&#8217;s kind of really interesting to see. So you could use it for video and music. So things stay on the forefront on your browser even if you look at other pages on the website. So that&#8217;s one of the features.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>The person, the, the part of me that likes to listen to podcasts from the website themselves really appreciates this.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. So I, I definitely, once it&#8217;s out, I definitely gonna adopt it for the good changelog podcast.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>So I think always through, we are through with booked. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg:</em> Lots of little, little things, but those are the big exciting things, I think.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Yeah. And there were actually 38 PRs that were backported as bug fixes to 7.0. So it&#8217;s still an ongoing work that is coming out in two weeks and people are still fixing it. </p>\n\n\n\n<p class=\"wp-block-paragraph\">All right, well, I wish you and your agency all the best for that release that all the things that come in don&#8217;t disrupt your work or the work of your clients.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>We have a list. We know where to look for the problem.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Excellent. Yeah. Well, I&#8217;m so happy that you were on the show with me. And as always, dear listeners, the show notes will be published on GutenbergTimes.com podcast this is episode 129 and if you have questions and suggestions or news you want us to include, send them to <a href=\"http://changelogutenbergtimes.com\">changelogutenbergtimes.com</a> that&#8217;s <a href=\"http://changelogutenbergtimes.com\">changelogutenbergtimes.com</a> so thank you for listening and I wish you all a great weekend. Well, or next week. And also toy, toy for the WordPress 7.0 release updates. We will hear each other again in four weeks once I get back from WordCamp Asia. And then we&#8217;ll tackle what&#8217;s coming in 7.1 and what has been in. Good work. Plugin 22.9 and 23.0. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Thank you so much. Beth Soderberg, it was wonderful to have you and your perspective and your opinions on the show.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Thank you for having me. It was great to be here and to see you again and I wish you safe travels on all of your continuing travels.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Thank you. All right. Yeah, and you take care. And I&#8217;ll put in the show notes how people can connect with you.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Sounds good.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Of course. All right, you take care. Bye Bye.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Beth Soderberg: </em>Bye bye. Thanks, everybody.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 29 Mar 2026 08:59:05 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:46;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:26:\"Matt: Community Antibodies\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=151704\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"https://ma.tt/2026/03/community-antibodies/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:3022:\"<p class=\"wp-block-paragraph\">First, I want to say how great the jazz scene is in New York. I caught a little Latin at my go-to <a href=\"https://guantanamerany.com/\">Guantanamera</a> last night, but the band seemed to be phoning it in a bit, so I walked over to <a href=\"https://jazz.org/dizzys/\">Dizzy&#8217;s</a> and heard an amazing big band performance by the <a href=\"https://divajazz.com/\">Diva all-women Jass Orchestra</a>, they had <a href=\"https://clintholmesmusic.com/\">Clint Holmes</a> leading vocals and I got <a href=\"https://open.spotify.com/album/2m0W0n7zBYmRNs1QAgoa6Z\">Frank Sinatra / Count Basie vibes</a>, so great to see such a tight big band.</p>\n\n\n\n<p class=\"wp-block-paragraph\">In <a href=\"https://wordpress.org/\">WordPress</a>, last week it was fun to see the company some call <a href=\"https://x.com/WordPress/status/2032291317871468554\">parasitic WP Engine acquire WPackagist</a>. So a popular way to use WordPress with Composer, previously maintained by an <a href=\"https://outlandish.com/\">awesome co-op agency in London</a>, was now in the clutches of a company using <a href=\"https://ma.tt/2025/10/greenwashing/\">its capital advantage to try to openwash its alleged bad behavior</a>, probably in a <a href=\"https://ma.tt/2026/03/selling-your-company/\">process that wasn&#8217;t ideal for the sellers</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Four days later, an awesome independent organization <a href=\"https://roots.io\">roots.io</a> released <a href=\"https://wp-packages.org\">WP Composer (renamed to WP Packages</a>, in OpenClaw fashion) with 17x faster cold resolves than WPackagist. <a href=\"https://wp-packages.org/wp-packages-vs-wpackagist\">Check out their comparison page</a>.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-151706\" height=\"648\" src=\"https://i0.wp.com/ma.tt/files/2026/03/composer-compare.png?resize=604%2C648&#038;quality=80&#038;ssl=1\" width=\"604\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">It&#8217;s beautiful to see how resilient and nimble the antibodies in the WordPress community are. Major hat tip to <a href=\"https://benword.com\">Ben Word</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">In another type of <span style=\"margin: 0px; padding: 0px;\">antibody, Sid Sijbrandi, whom I <a href=\"https://ma.tt/2026/01/cancer-founder-mode/\" target=\"_blank\">previously talked about going into founder mode on his cancer</a>, gave <a href=\"https://sytse.com/cancer/\" target=\"_blank\">an incredible presentation</a> at the Open AI Forum abo</span>ut how he ran a bunch of N-of-1 experiments and therapies to cure his terminal osteosarcoma. He&#8217;s <a href=\"https://osteosarc.com/\">also open-sourced 25TB of his data for cancer research</a>. Incredible!</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you want to see the future of health care, <a href=\"https://forum.openai.com/public/videos/event-replay-from-terminal-to-turnaround-how-gitlabs-co-founder-leveraged-chatgpt-in-his-cancer-fight-2026-03-18\">give Sid&#8217;s presentation a watch</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 28 Mar 2026 22:12:33 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:47;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Matt: Stockfish\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=151702\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ma.tt/2026/03/stockfish/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:839:\"<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">Nobody is arguing that <a href=\"https://stockfishchess.org/\" rel=\"noreferrer noopener\" target=\"_blank\">Stockfish</a> is conscious, but Stockfish would kick Claude’s ass at chess.</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">Kevin Lincoln in <a href=\"https://www.bloomberg.com/news/articles/2026-03-27/ai-changed-chess-grandmasters-now-win-with-unpredictable-moves?accessToken=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzb3VyY2UiOiJTdWJzY3JpYmVyR2lmdGVkQXJ0aWNsZSIsImlhdCI6MTc3NDY4MDEzNSwiZXhwIjoxNzc1Mjg0OTM1LCJhcnRpY2xlSWQiOiJUQ0pTVzdLSVAzSkwwMCIsImJjb25uZWN0SWQiOiIwNEFGQkMxQkYyMTA0NUVEODg3MzQxQkQwQzIyNzRBMCJ9.nIWazrd0HBbGwk_nzijL8lTm8uyCPXr1F7molURiExg\">AI Perfected Chess. Humans Made It Unpredictable Again</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 28 Mar 2026 20:57:39 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:48;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:67:\"Gary: Claudaborative Editing 0.2: now with 500% more collaboration!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:25:\"https://pento.net/?p=5697\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://pento.net/2026/03/28/claudaborative-editing-0-2-now-with-500-more-collaboration/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:5416:\"<p class=\"wp-block-paragraph\">A week ago, I put together <a href=\"https://pento.net/2026/03/20/introducing-claudaborative-editing/\">a quick tech demo</a>, showing how an MCP server could be created for Claude Code that hooked directly into Gutenberg&#8217;s Collaborative Editing feature, allowing it to act as a digital collaborator on a post. The demo focused primarily on text generation, but that&#8217;s not really the benefit that I see coming with this kind of tool. Anyone can generate text, then copy/paste it into the editor. The real power comes from directly hooking into the entire post creation and editing process.</p>\n\n\n\n<h2 class=\"wp-block-heading\">What&#8217;s New?</h2>\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-2 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><img alt=\"A screenshot of the /review tool running on this post, prior to publication.\" class=\"wp-image-5711\" height=\"607\" src=\"https://pento.net/wp-content/uploads/2026/03/review-notes-1024x607.png\" width=\"1024\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"A screenshot of what Claude was doing behind the scenes when it was generating the review notes.\" class=\"wp-image-5714\" height=\"564\" src=\"https://pento.net/wp-content/uploads/2026/03/review-processing-1024x564.png\" width=\"1024\" /></figure>\n</figure>\n\n\n\n<p class=\"wp-block-paragraph\">Since last week&#8217;s release, I&#8217;ve added a host of editing and review tools:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><code>/edit {tell the LLM how you want this post adjusted}</code><br />Automatically make simple (or even not so simple!) edits on your post, giving your writing a little extra polish.</li>\n\n\n\n<li><code>/proofread</code><br />Find and automatically fix simple spelling, grammatical, and punctuation issues.</li>\n\n\n\n<li><code>/review</code><br />Read the post, and leave notes (using Gutenberg&#8217;s Notes feature!) about suggested improvements to your post. This doesn&#8217;t touch your post content, leaving you to make use of the suggestions as you see fit.</li>\n\n\n\n<li><code>/respond-to-notes</code><br />If you&#8217;re happy with the notes left in the review, you can also have it automatically apply them, too!</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">On top of that, I&#8217;ve also added an experimental <code>/translate</code> tool, to automatically translate a post into a different language. LLM translation quality varies significantly, though Claude is regularly considered to be quite good. It&#8217;s worth remembering that, like any LLM, the output is only as good as its input. If you&#8217;re translating to a language that it didn&#8217;t have much training data on, it&#8217;ll do a lot worse.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Behind The Scenes</h2>\n\n\n\n<p class=\"wp-block-paragraph\">The MCP server now does a much better job of making use of the REST API, too: it now handles all block types (and does a pretty good job of guessing how to use blocks provided by plugins!). It can upload media, and it can handle all the post metadata, like categories, tags, excerpt, etc.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Getting It Running</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Inspired by the recently released <a href=\"https://make.wordpress.org/meta/2026/03/20/plugin-directory-mcp-server/\">WordPress.org MCP server</a>, the install process got a refresh, too. If you&#8217;re running WordPress 7.0, you won&#8217;t even need to copy/paste the application password to connect to your site: just click the connect button in your browser, and your site will send credentials back to the installer! And if you&#8217;d prefer to avoid the magic, there&#8217;s still a <code>--manual</code> option to let you set it up the old-fashioned way.</p>\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-3 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><img alt=\"A screenshot of the initial installation of the claudaborative-editing MCP server, prompting the user to enter a site to connect to.\" class=\"wp-image-5700\" height=\"372\" src=\"https://pento.net/wp-content/uploads/2026/03/connect-1024x372.png\" width=\"1024\" /><figcaption class=\"wp-element-caption\">Connect</figcaption></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"The authorisation screen of the site that the MCP server is connecting to.\" class=\"wp-image-5702\" height=\"577\" src=\"https://pento.net/wp-content/uploads/2026/03/approve-1024x577.png\" width=\"1024\" /><figcaption class=\"wp-element-caption\">Authorise</figcaption></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"After authorisation, this screenshot shows the continu\" class=\"wp-image-5701\" height=\"667\" src=\"https://pento.net/wp-content/uploads/2026/03/install-1024x667.png\" width=\"1024\" /><figcaption class=\"wp-element-caption\">Install</figcaption></figure>\n</figure>\n\n\n\n<h2 class=\"wp-block-heading\">What&#8217;s Next?</h2>\n\n\n\n<p class=\"wp-block-paragraph\">This release shows how easy it is for an LLM to talk to your WordPress site. What about the other way? If you&#8217;re working on a post, you don&#8217;t want to have to switch to a terminal to get spell checking done, so how can we provide this kind of functionality directly from the block editor? Let&#8217;s experiment and find out!</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 28 Mar 2026 06:35:32 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Gary\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:49;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:112:\"Gutenberg Times: WordPress 7.0, Playground MCP, Gutenberg 22.8, PHP-only Blocks and more — Weekend Edition 362\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=44834\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:132:\"https://gutenbergtimes.com/wordpress-7-0-source-of-truth-playground-mcp-gutenberg-22-8-php-only-blocks-and-more-weekend-edition-362/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:33739:\"<p class=\"wp-block-paragraph\">Hi,</p>\n\n\n\n<p class=\"wp-block-paragraph\">In less than two weeks, WordPress 7.0 is scheduled to be released. Are you ready? Or are you someone I used to be who waits two to three weeks to see what quirks early adopters find and if they warrant an early point release? Be that as it may, waiting only delays the inevitable, though, sooner or later you get to benefit from the new features and quality of life improvements to the Admin, Editor and Blocks. </p>\n\n\n\n<p class=\"wp-block-paragraph\">The first version of the <a href=\"https://gutenbergtimes.com/wordpress-7-0-source-of-truth/\"><strong>WordPress 7.0 Source of Truth</strong></a> has been published. It&#8217;s again a mammoth post of 4500 words, including 21 images and ten videos. I hope you enjoy the list of all the big and small feature and updates. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Next week, I will be on my way to Mumbai. The next weekend edition will arrive in your inbox after WordCamp Asia, on April 17th, 2026. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Yours, <img alt=\"💕\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f495.png\" style=\"height: 1em;\" /><br /><em>Birgit</em></p>\n\n\n\n<p class=\"wp-block-paragraph\">PS: Should you be in Mumbai, grab a coffee of lunch spot <a href=\"https://calendly.com/pauli-haack/wcasia\">from my public calendar</a>, I&#8217;d love to meet you! </p>\n\n\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-word-press-release-information\">WordPress 7.0 </h2>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"Highlight grid WordPress 7.0\" class=\"wp-image-44936\" height=\"375\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2026/03/7-0_highlight-grid-2026-03-26.png?resize=652%2C375&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>WordPress 7.0 </strong>Release candidate 1 <a href=\"https://make.wordpress.org/core/2026/03/19/wordpress-7-0-release-candidate-1-delayed/\">was moved to this week</a>. The <a href=\"https://wordpress.org/news/2026/03/wordpress-7-0-release-candidate-2/\">WordPress 7.0 RC2</a> was still on schedule for Thursday, though. Meanwhile, more Dev Notes were published.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/core/2026/03/16/pattern-overrides-in-wp-7-0-support-for-custom-blocks/\"><strong>Pattern Overrides in WP 7.0</strong></a> is your heads-up to act before the release lands. WordPress 7.0 lifts the old restriction — Pattern Overrides now work with any block attribute that supports Block Bindings, not just a hardcoded Core block list. You opt in via the <code>block_bindings_supported_attributes</code> filter, and the post walks you through edge cases for static blocks where a <code>render_callback</code> may still be needed.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/core/2026/03/15/pattern-editing-in-wordpress-7-0/\"><strong>Pattern Editing in WordPress 7.0</strong></a> explains that ContentOnly mode for unsynced patterns is now the default, meaning block structure and style controls are hidden from editors by default. Block authors need to audit <code>\"role\": \"content\"</code> attributes in <code>block.json</code>, theme authors should test their patterns, and plugin developers should verify UI components still render correctly under the new, more broadly applied editing modes.</p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/core/2026/03/15/block-visibility-in-wordpress-7-0/\"><strong>Block Visibility in WordPress 7.0</strong></a> dev note is relevant if your theme or plugin touches block markup server-side. The new <code>viewport</code> key inside <code>blockVisibility</code> metadata lets users show or hide blocks per device — mobile, tablet, desktop — via CSS, not DOM removal. If your code assumes <code>blockVisibility</code> is always a boolean, you&#8217;ll need to update it to handle an object too. No changes are needed if your blocks don&#8217;t interact with markup server-side.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Anne McCarthy</strong> walks through <a href=\"https://www.youtube.com/watch?v=0Yq7aVoJIOk\">one of WordPress 7.0&#8217;s most-requested features</a>: viewport-based block visibility. You&#8217;ll see exactly how showing or hiding any block by screen size works in practice — no extra plugins or CSS workarounds needed — and why it is relevant for responsive design. If you&#8217;ve been waiting for a native way to tailor content for mobile, tablet, and desktop separately, this is your preview before the April 9th release.</p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-4-3 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">The <strong><a href=\"https://make.wordpress.org/core/2026/03/15/dimensions-support-enhancements-in-wordpress-7-0/\">Dimensions Support Enhancements in WordPress 7.0</a> </strong>comprise width and height as first-class block supports. Block builders and theme designer opt in with a single line in <code>block.json</code>, set defaults in <code>theme.json</code>, and the sidebar UI comes for free. Themes can also define named <code>dimensionSizes</code> presets, giving users a consistent palette rather than free-form inputs. If your block has custom width/height attributes today, this is a good moment to consider migrating.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">A long-requested feature finally lands in WordPress 7.0. The dev note on <strong><a href=\"https://make.wordpress.org/core/2026/03/15/custom-css-for-individual-block-instances-in-wordpress-7-0/\">Custom CSS for Individual Block Instances</a> </strong>hold all the details. The new <code>customCSS</code> block support — enabled by default for all blocks — adds a Custom CSS field in the Advanced panel of the block inspector, scoped automatically to that instance via a generated class. Block authors whose blocks wrap raw or opaque content should explicitly opt out via <code>block.json</code>. If your <code>render_callback</code> is in play, make sure your block&#8217;s outermost element is a standard HTML tag.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">A typography feature requested since 2021 finally arrives in WordPress 7.0, the dev note on <strong><a href=\"https://make.wordpress.org/core/2026/03/15/new-block-support-text-indent-textindent/\">the new <code>textIndent</code> block support</a> </strong>has all the details for developers working on blocks or themes. Opt in with a single line in <code>block.json</code>, and a Line Indent control appears automatically in the Typography panel. Theme authors get <code>theme.json</code> configuration too, including a thoughtful <code>subsequent</code> vs <code>all</code> toggle that respects both LTR and RTL typographic conventions. No breaking changes — purely additive./</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0 ships a new<strong> <a href=\"https://make.wordpress.org/core/2026/03/18/introducing-the-connectors-api-in-wordpress-7-0/\">Connectors API</a> </strong>— and if you build AI-adjacent plugins, this dev note belongs on your reading list. The new framework standardizes how WordPress registers and manages connections to external services — starting with AI providers — giving you a consistent admin UI, API key management, and auto-discovery via the WP AI Client. Three providers ship out of the box: Anthropic, Google, and OpenAI. The <code>wp_connectors_init</code> action is your hook for registering additional connectors or overriding existing metadata.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Felix Arntz </strong>details<strong> <a href=\"https://make.wordpress.org/core/2026/03/24/introducing-the-ai-client-in-wordpress-7-0/\">the new AI Client landing in WordPress 7.0</a></strong> — a provider-agnostic PHP API that lets your plugin send prompts for text, images, speech, or video without touching credentials or provider logic. You chain methods on <code>wp_ai_client_prompt()</code>, declare model preferences, and WordPress routes to whatever the site owner has configured. Three official provider plugins cover Anthropic, Google, and OpenAI. Client-side JS exists but remains admin-only for now.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Jorge Costa</strong> details the <a href=\"https://make.wordpress.org/core/2026/03/24/client-side-abilities-api-in-wordpress-7-0/\"><strong>client-side Abilities API arriving in WordPress 7.0</strong></a>, the JavaScript counterpart to the PHP Abilities API introduced in 6.9. Two new packages handle it: <code>@wordpress/abilities</code> for pure state management and <code>@wordpress/core-abilities</code> for the WordPress integration layer that auto-fetches server-registered abilities via REST. You can register abilities with input/output schemas, permission callbacks, and annotations — laying the groundwork for browser agents and WebMCP integration.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"gutenberg-22-8\">Gutenberg 22.8</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Gutenberg 22.8 release lead <strong>Dean Sas</strong> highlighted in his post <a href=\"https://make.wordpress.org/core/2026/03/25/whats-new-in-gutenberg-22-8-25-march/\"><strong>What’s new in Gutenberg 22.8? (25 March)</strong></a>  the following features: </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2026/03/25/whats-new-in-gutenberg-22-8-25-march/#real-time-collaboration-improvements\">Real-time Collaboration improvements</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/25/whats-new-in-gutenberg-22-8-25-march/#button-pseudo-state-styling-in-global-styles\">Button pseudo-state styling in Global Styles</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/25/whats-new-in-gutenberg-22-8-25-march/#site-logo-icon-in-the-design-panel\">Site Logo &amp; Icon in the Design panel</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/25/whats-new-in-gutenberg-22-8-25-march/#connectors-extensibility\">Connectors extensibility</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/03/25/whats-new-in-gutenberg-22-8-25-march/#other-notable-highlights\">Other Notable Highlights</a></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">The real-time collaboration improvements and the Connectors extensibility will make it into the WordPress 7.0 release.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">I had a blast chatting with <strong>Beth Soderberg </strong>from <a href=\"https://bethink.studio/\">Bethink Studio</a> on the recording of Gutenberg changelog 129. We dove into some cool stuff like using AI, WordPress 7.0, and Gutenberg 22.8. It was such a fun convo, and we even touched on that little mental block some users might hit when they see the fresh new look of the wp-admin screens and try to wrap their heads around the change. The episode will drop into your favorite podcast app over the weekend. The 130th episode will be recorded after I return from WordCamp Asia.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-45032\" height=\"185\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2026/03/Screenshot-2026-03-28-at-12.00.17.png?resize=652%2C185&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-constrained wp-block-group-is-layout-constrained\">\n<p class=\"wp-block-paragraph\"><img alt=\"🎙\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f399.png\" style=\"height: 1em;\" /> The latest episode is <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-129/\">Gutenberg Changelog #129 Artificial Intelligence, WordPress 7.0 and Gutenberg 22.8</a> with Beth Soderberg, of BeThink Studio </p>\n\n\n\n<figure class=\"wp-block-image size-full is-style-no-vertical-margin\"><img alt=\"Beth Soderberg and Birgit Pauli-Haack recording the Gutenberg Changelog 129\" class=\"wp-image-45032\" height=\"185\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2026/03/Screenshot-2026-03-28-at-12.00.17.png?resize=652%2C185&#038;ssl=1\" width=\"652\" /></figure>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-rich is-provider-pocket-casts wp-block-embed-pocket-casts\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div></div></div>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-p\">Plugins, Themes, and Tools for #nocode site builders and owners</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Courtney Robertson</strong> at GoDaddy breaks down <a href=\"https://www.godaddy.com/resources/news/wordpress-7-0-real-time-collaboration-arrives-in-core\"><strong>what WordPress 7.0 brings when it ships April 9 at WordCamp Asia</strong></a>. Your editor finally gets real-time multi-user collaboration powered by Yjs, alongside visual block-level revisions, a Breadcrumbs block, Icon block, and customizable navigation overlays. Developers gain a provider-agnostic WP AI Client with a Connectors UI, PHP-only block registration, and Interactivity API improvements. The minimum PHP requirement bumps to 7.4 — worth flagging for clients on older hosting now.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">A little over a month ago, <strong>Johanne Courtright</strong>, founder of Groundworx, launched<strong> <a href=\"https://www.reddit.com/r/WordPressBlocks/comments/1rb20y1/welcome_to_rwordpressblocks/\">r/WordPressBlocks</a></strong>, a dedicated Reddit community for developers and builders working with the block editor. A longtime block developer and free plugin author, Courtright created the space because scattered conversations about custom blocks, theme.json, full site editing, and Gutenberg&#8217;s direction deserved a proper home. All skill levels welcome — come share tips, tools, wins, and frustrations.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</h2>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;re finding it a drag to edit <code>theme.json</code>, check out <strong>Sérgio Santos</strong>&#8216;s creation, <a href=\"https://marketplace.visualstudio.com/items?itemName=s3rgiosan.vscode-wp-theme-json-editor\"><strong>WP Theme JSON Editor</strong></a>. It&#8217;s a VS Code and Cursor extension that makes dealing with JSON way easier with its cool visual interface. You can easily tweak colors, typography, spacing, and block settings using the official WordPress JSON Schema. Plus, it’s got handy features like CSS variable autocomplete, CodeMirror 6 syntax highlighting, drag-and-drop for palettes and font sizes, and real-time validation, and you even get to play with some experimental WP core properties. I’m not sure if it’s really easier than writing JSON from scratch, but hey, that’s just a personal choice, right?</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-45040\" height=\"356\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2026/03/Screenshot-2026-03-28-at-13.19.14.png?resize=652%2C356&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">You can now <a href=\"https://wordpress.com/blog/2026/03/16/how-to-build-a-wordpress-theme-with-telex/\"><strong>generate a block theme with Telex</strong></a>, Automattic&#8217;s experimental AI theme builder. You describe your site, hit &#8220;Enhance Prompt&#8221; to let Telex flesh out the design brief, optionally upload a reference image, then pick from four generated variations. From there you build out additional page templates, refine typography and colors conversationally, and download a ready-to-install ZIP containing your templates, styles, and theme.json — no PHP or CSS knowledge required.</p>\n\n\n<div class=\"ng-block-14a095745431b236 wp-block-newsletterglue-container ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div class=\"ng-block-vs ng-block-vs-1\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div><div><div class=\"ng-block-hs ng-block-hs-1\" height=\"0\" style=\"width: 0px;\"></div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 20px; padding-bottom: 20px; padding-left: 0px; padding-right: 0px; text-align: none; color: #666666; background-color: #fdfcea; border-radius: 12px;\"><div class=\"ng-block-d73a8f02251a9c6c wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p><strong> <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/\" rel=\"noreferrer noopener\" target=\"_blank\">&#8220;Keeping up with Gutenberg &#8211; Index 2026&#8221;</a> </strong><br />A chronological list of the WordPress Make Blog posts from various teams involved in Gutenberg development: Design, Theme Review Team, Core Editor, Core JS, Core CSS, Test, and Meta team from Jan. 2024 on. Updated by yours truly. </p></div></div></div></div>\n\n<div class=\"ng-block-4045ea43434f512c wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p>The previous years are also available: <br /><strong><strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2020/\">2020</a> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2021/\">2021</a></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2022/\">2022</a></strong></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2023\">2023</a></strong> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2024/\"><strong>2024</strong></a></p></div></div></div></div></div><div class=\"ng-block-hs ng-block-hs-2\" height=\"0\" style=\"width: 0px;\"></div></div><div><div class=\"ng-block-vs ng-block-vs-2\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div></div></div>\n\n\n<h2 class=\"wp-block-heading\" id=\"3-building-themes-for-fse-and-word-press\">Building Blocks and Tools for the Block editor.</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Troy Chaplin</strong> launched <a href=\"https://veilsoffate.com/\">Veils of Fate</a>, a choose-your-own-adventure game built in WordPress using the Interactivity API, post types, and taxonomies. Spanning 3 acts, 18 quests, and 112 scenes, the story was co-written with Claude AI. If you love interactive storytelling, this one&#8217;s for you. Nano banana handled the pixel art, Miles created the theme, and Kinsta provides the hosting. A family-inspired project: Troy&#8217;s kids are avid readers and his wife is a librarian.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>WordPress Studio</strong> is a free, open-source local development tool powered by WordPress Playground that has been around for two years now. The team has now published <a href=\"https://www.npmjs.com/package/wp-studio\">wp-studio</a> the CLI installer you can use to spin up local sites instantly — no Docker, NGINX, Apache, or MySQL required — sync them with WordPress.com or Pressable, share live preview links with clients, and tap into a built-in AI assistant that runs WP-CLI commands natively. It&#8217;s only early access to there might be dragons. <img alt=\"🐉\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f409.png\" style=\"height: 1em;\" /> Also available in WordPress Studio you can use phpMyAdmin to access the database and use it dark mode. </p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-45047\" height=\"491\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2026/03/Screenshot-2026-03-28-at-13.53.48.png?resize=652%2C491&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Carlo Daniele</strong> at Kinsta walks you through <strong><a href=\"https://kinsta.com/blog/php-only-gutenberg-blocks/\">building PHP-only Gutenberg blocks</a>,</strong> a feature introduced in Gutenberg 21.8 that lets you register blocks entirely in PHP—no React, Node.js, or build steps required. Using the new <code>auto_register</code> support flag, your attributes automatically generate inspector controls in the editor. You&#8217;ll build a pricing card block and learn how to wrap legacy shortcodes as proper blocks, finally giving your PHP-side clients and developers a gentler path into the block editor. It will also come to a WordPress instance near you soon with WordPress 7.0. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;d rather watch a video for education, <strong>Brian Coords</strong> demonstrates <a href=\"https://www.youtube.com/watch?v=HS0pUU-cSpM\"><strong>how PHP-only block registration in WordPress 7.0 </strong>removes the build-tool barrier entirely</a> You&#8217;ll see a Hello World block built with custom fields, a WooCommerce integration using the Store API, and how to handle frontend JavaScript when backend JS has limitations. The real payoff comes when you combine PHP-only blocks with Claude Code skills, letting you generate blocks through conversation rather than scaffolding. The code is on <a href=\"https://github.com/bacoords/example-p...\">GitHub</a>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<h2 class=\"wp-block-heading\" id=\"playground-news\">Playground News</h2>\n\n\n\n<p class=\"wp-block-paragraph\">On this episode of <em>The WP Minute+</em>, <strong>Eric Karkovack</strong> sits down with WordPress contributors <strong>Alex Kirk</strong> and <strong>Brandon Payton</strong> to <strong><a href=\"https://www.youtube.com/watch?v=lbsFmIqP0_g\">explore my.WordPress.net</a>,</strong> a browser-based WordPress sandbox built around privacy, portability, and AI. Think personal CRM, private family blogging, chat-to-blog workflows, and an AI playground — all running in your browser without a server. The demo shows how plugins become app-like modules, how messaging apps like Beeper can feed content in, and how AI can modify plugins live. Your data stays yours, portable across devices.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<h2 class=\"wp-block-heading\" id=\"ai-in-wordpress\">AI in WordPress</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Fellyph Cintra</strong> announces that <a href=\"https://make.wordpress.org/playground/2026/03/17/connect-ai-coding-agents-to-wordpress-playground-with-mcp/\">AI coding agents can now connect directly to <strong>WordPress Playground via MCP</strong></a>, thanks to the new <code>@wp-playground/mcp</code> package built by <strong>Berislav Grgicak</strong>. One command wires up Claude Code or Gemini CLI to a browser-based Playground instance over WebSocket, letting your agent read and write files, execute PHP, manage sites, and navigate pages — all locally, without touching WordPress admin. Think plugin testing, live database debugging, and theme scaffolding driven entirely by conversation.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Gary Pendergast</strong>, long-time core committer, introduces <a href=\"https://pento.net/2026/03/20/introducing-claudaborative-editing/\">claudaborative-editing</a>, an MCP server — written by Claude Code, fittingly — that lets Claude edit WordPress posts live alongside you in Gutenberg. Built on WordPress 7.0&#8217;s Yjs-powered collaborative editing protocol, your changes and Claude&#8217;s sync in real time with no conflicts. A single <code>npx claudaborative-editing setup</code> gets you started. Claude appears in the collaborators list, edits at the block level, and even streams text character by character as it types. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Darin Koster</strong>, developer at Fueled, walks you through <a href=\"https://darinkotter.com/ai-featured-images/\"><strong>how AI featured image generation works</strong></a> inside the <a href=\"https://wordpress.org/plugins/ai/\">WordPress AI plugin</a>. One button click kicks off a five-step chain built on the Abilities API: gather post context, generate an image prompt via an LLM, generate the image, optionally create alt text, then import and set it as the featured image — all in about 30 seconds. The post doubles as a practical demonstration of how WordPress&#8217;s AI building blocks can be composed into real editor workflows.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">In <strong><a href=\"https://wpbuilds.com/2026/03/26/462-debating-ais-impact-with-jamie-marsland-content-creativity-slop-and-the-future-of-wordpress/\">this lively WP Builds debate on AI, content, and the future of WordPress</a>,</strong> <strong>Jamie Marsland </strong>— Automattic&#8217;s head of YouTube and prolific WordPress educator — squares off against a gleefully curmudgeonly <strong>Nathan Wrigley</strong>. Marsland champions the new Claude–WordPress.com integration, which gives AI full context of your site for content, branding, and SEO. <strong>Wrigley</strong> pushes back on authenticity, AI slop, and eroding community skills. You&#8217;ll find both sides genuinely persuasive — and probably switch teams more than once.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://wpbuilds.com/2026/03/26/462-debating-ais-impact-with-jamie-marsland-content-creativity-slop-and-the-future-of-wordpress/\"><img alt=\"\" class=\"wp-image-45035\" height=\"342\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2026/03/WPBuilds462-Nathan-Wrigley-Jamie-Marsland.webp?resize=652%2C342&#038;ssl=1\" width=\"652\" /></a></figure>\n\n\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">As an example of how AI might change how you use WordPress, <strong>Jamie Marsland</strong> demonstrates that <a href=\"https://www.youtube.com/watch?v=Jywvzfo_w8c\"><strong>You can now Vibe Code with WordPress.com</strong></a>. on YouTube. He shows what&#8217;s possible once Claude is connected to your site via MCP, from building full landing pages and wiring up contact forms with a single prompt to running promotions across multiple sites, generating downloadable SEO reports, auditing for accessibility, and tracking activity with visual dashboards. Think of it as your WordPress workflow, but driven entirely by conversation.</p>\n\n\n\n<p class=\"wp-block-paragraph\">You can learn more about the official WordPress.com connector for Claude in below blog post and video. </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://wordpress.com/blog/2026/03/20/ai-agent-manage-content/\"><strong>Your AI agent can now create, edit, and manage content on WordPress.com</strong></a> by Jonathan Bossenger </li>\n\n\n\n<li><br /><strong><a href=\"https://www.youtube.com/watch?v=ujFGAuUc-x4\">It’s Official: You Can Now Use Claude with WordPress!</a></strong> also with Jamie Marsland</li>\n</ul>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n<div class=\"ng-block-dfadc298cd10a13e wp-block-newsletterglue-container ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div class=\"ng-block-vs ng-block-vs-1\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div><div><div class=\"ng-block-hs ng-block-hs-1\" height=\"0\" style=\"width: 0px;\"></div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 20px; padding-bottom: 20px; padding-left: 0px; padding-right: 0px; text-align: none; color: #666666; background-color: #f8f8f8; border-radius: 8px;\"><div class=\"ng-block-0d89cb78b7624a03 wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p><strong><a href=\"https://gutenbergtimes.com/need-a-zip-from-master/\">Need a plugin .zip from Gutenberg&#8217;s master branch?</a></strong><br />Gutenberg Times provides daily build for testing and review.</p></div></div></div></div>\n\n<div class=\"ng-block-6666ba3d1f8c4809 wp-block-newsletterglue-image ng-block size-full is-resized\" width=\"100%\"><div><div><div align=\"center\" class=\"ng-block-td\" style=\"padding-top: 0px; padding-bottom: 0px; padding-left: 0px; padding-right: 0px;\"><a href=\"https://playground.wordpress.net/?blueprint-url=https://gutenbergtimes.com/wp-content/uploads/2020/11/playnightly.json\"><img alt=\"\" class=\"wp-image-42874 ng-image\" height=\"45\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2024/02/Screenshot-2025-11-15-at-12.06.44.png?resize=196%2C45&#038;ssl=1\" style=\"border-style: none; border-color: transparent;\" width=\"196\" /></a></div></div></div></div>\n\n<div class=\"ng-block-b24cca94d98113e0 wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p>Now also available via <a href=\"https://playground.wordpress.net/?blueprint-url=https://gutenbergtimes.com/wp-content/uploads/2020/11/playnightly.json\">WordPress Playground</a>. There is no need for a test site locally or on a server. Have you been using it? <a href=\"mailto:pauli@gutenbergtimes.com\">Email me </a>with your experience.</p></div></div></div></div></div><div class=\"ng-block-hs ng-block-hs-2\" height=\"0\" style=\"width: 0px;\"></div></div><div><div class=\"ng-block-vs ng-block-vs-2\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div></div></div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"has-text-align-center has-small-font-size wp-block-paragraph\"><em>Questions? Suggestions? Ideas? </em><br /><em>Don&#8217;t hesitate to send <a href=\"mailto:pauli@gutenbergtimes.com\">them via email</a> or</em><br /><em> send me a message on WordPress Slack or Twitter @bph</em>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"has-text-align-center has-small-font-size wp-block-paragraph\">For questions to be answered on the <a href=\"http://gutenbergtimes.com/podcast\">Gutenberg Changelog</a>, <br />send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a></p>\n\n\n<div class=\"ng-block-adb1e4604d28fdf2 wp-block-newsletterglue-separator ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"center\" class=\"ng-block-td\" style=\"padding-top: 20px; padding-bottom: 20px; padding-left: 20px; padding-right: 20px; color: #666666;\"><hr style=\"background-color: transparent; color: transparent; margin: 0; border: 0; border-top: 1px solid #666666; width: 560px; height: 0;\" /></div></div></div></div>\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\"><div class=\"ng-block-d99738c5ab34413e wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 14px; font-family: Helvetica; line-height: 0.2; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p><strong>Featured Image: </strong></p></div></div></div></div></div>\n\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 28 Mar 2026 03:40:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";O:48:\"WpOrg\\Requests\\Utility\\CaseInsensitiveDictionary\":1:{s:7:\"\0*\0data\";a:9:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Wed, 22 Apr 2026 23:07:17 GMT\";s:12:\"content-type\";s:8:\"text/xml\";s:13:\"last-modified\";s:29:\"Wed, 22 Apr 2026 22:45:21 GMT\";s:4:\"vary\";s:15:\"Accept-Encoding\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:2:\"br\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 2\";}}s:5:\"build\";i:1727736619;s:21:\"cache_expiration_time\";i:1776942438;s:23:\"__cache_expiration_time\";i:1776942438;}','off'),
