_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:13:\"lastBuildDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Thu, 23 Apr 2026 06:08:41 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:3:\"ttl\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"60\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"item\";a:15:{i:0;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:98:\"Uusi materiaali paljastaa, että EU:n edellyttämät eläinkokeet aiheuttavat vakavaa kärsimystä\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:285:\"Eri eläimiä altistetaan myrkyille kivuliaissa EU:n vaatimissa eläinkokeissa, joita tehdään myös Suomessa. Kuvamateriaalin julkaisivat eläinkoelaitoksen työntekijät kokemansa moraalisen ristiriidan takia. Järjestöt vaativat nopeaa siirtymää eläinkokeettomaan tutkimukseen.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:129:\"https://www.verdelehti.fi/2026/04/22/uusi-materiaali-paljastaa-etta-eu-n-edellyttamat-elainkokeet-aiheuttavat-vakavaa-karsimysta/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69e5f5dacd4f8200016c02b9\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:7:\"Uutinen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:12:\"eläinkokeet\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:24:\"Kulttuuri ja yhteiskunta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Wed, 22 Apr 2026 17:23:47 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"Toimitus JL\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:133:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/dbe2e4dc-553a-4003-8b9a-4121f83781d2.jpg\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:4542:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/dbe2e4dc-553a-4003-8b9a-4121f83781d2.jpg\" alt=\"Uusi materiaali paljastaa, ett&#xE4; EU:n edellytt&#xE4;m&#xE4;t el&#xE4;inkokeet aiheuttavat vakavaa k&#xE4;rsimyst&#xE4;\"><p>Tuore&#xA0;Isossa-Britanniassa&#xA0;kuvattu&#xA0;materiaali&#xA0;paljastaa, ett&#xE4;&#xA0;Euroopan unionin vaatimusten takia teht&#xE4;v&#xE4;t&#xA0;el&#xE4;inkokeet tuottavat el&#xE4;imille suurta k&#xE4;rsimyst&#xE4;, Animalia tiedottaa. El&#xE4;inj&#xE4;rjest&#xF6;t vaativat v&#xE4;lit&#xF6;nt&#xE4; siirtym&#xE4;&#xE4; el&#xE4;inkokeettomaan tieteeseen.</p><p>EU velvoittaa useille alueelleen tuleville tuotteille, kuten kemikaaleille ja l&#xE4;&#xE4;kkeille, el&#xE4;imill&#xE4; teht&#xE4;vi&#xE4; myrkyllisyyskokeita. Animals Internationalille luovutettu materiaali paljastaa, millaisia el&#xE4;inkokeita EU:ssa toimivien yritysten tuotteiden vuoksi tehd&#xE4;&#xE4;n.&#xA0;&#xA0;</p><p>Kuvissa ja videoissa rotat, kanit, koirat, siat ja makakiapinat altistetaan myrkyllisille aineille. Kokeissa el&#xE4;imi&#xE4; pistet&#xE4;&#xE4;n ja pakkosy&#xF6;tet&#xE4;&#xE4;n ja niille tehd&#xE4;&#xE4;n avohaavoja, joille levitet&#xE4;&#xE4;n testattavaa ainetta. Niit&#xE4; pakotetaan hengitt&#xE4;m&#xE4;&#xE4;n myrkyllisi&#xE4; aineita.&#xA0;&#xA0;</p><p>&#x201D;Materiaali ei kuvaa laittomuuksia tai laiminly&#xF6;ntej&#xE4;. Se kuvaa t&#xE4;ysin tavanomaisia ja laillisia el&#xE4;inkokeita, joita tehd&#xE4;&#xE4;n EU:n vaatimusten takia. J&#xE4;rkytt&#xE4;v&#xE4;st&#xE4; materiaalista n&#xE4;kee selv&#xE4;sti, ett&#xE4; el&#xE4;imet kokevat silmit&#xF6;nt&#xE4; tuskaa, pelkoa ja ahdistusta&#x201D;, toteaa Animalian toiminnanjohtaja&#xA0;<strong>Heidi Kivek&#xE4;s</strong>.&#xA0;&#xA0;</p><h3 id=\"myrkyllisyyskokeet-k%C3%A4yt%C3%B6ss%C3%A4-my%C3%B6s-suomessa\">Myrkyllisyyskokeet k&#xE4;yt&#xF6;ss&#xE4; my&#xF6;s Suomessa</h3><p>Julkaistussa materiaalissa n&#xE4;kyv&#xE4;t kokeet on tehty l&#xE4;&#xE4;kkeiden, kuten antibioottien sek&#xE4; kipu-, astma-, painonpudotus-, ja sienil&#xE4;&#xE4;kkeiden myrkyllisyyskokeita varten. Samanlaisia testej&#xE4; tehd&#xE4;&#xE4;n my&#xF6;s teollisuuskemikaalien, torjunta-aineiden ja ruokien lis&#xE4;aineiden takia.&#xA0;&#xA0;<br>&#xA0;<br>My&#xF6;s Suomessa tehd&#xE4;&#xE4;n samankaltaisia myrkyllisyyskokeita ainakin rotille, hiirille, koirille ja minisioille. Myrkyllisyyskokeissa&#xA0;el&#xE4;imille annetaan ainetta jopa satakertaisena pitoisuutena verrattuna m&#xE4;&#xE4;r&#xE4;&#xE4;n, jolle ihmiset saattaisivat altistua. Kokeissa testataan, mill&#xE4; pitoisuudella aine aiheuttaa el&#xE4;imelle joko haittaa, sairauden tai kuoleman. Kokeiden j&#xE4;lkeen el&#xE4;imet, jotka eiv&#xE4;t ole jo kuolleet, tapetaan.</p><p>Suomessa testeiss&#xE4; ei k&#xE4;ytet&#xE4;&#xA0;apinoita, mutta yritykset voivat tilata k&#xE4;dellisill&#xE4; teht&#xE4;vi&#xE4;&#xA0;kokeita muista maista.&#xA0;&#xA0;</p><h3 id=\"koe-el%C3%A4inhoitajien-moraalinen-ristiriita-johti-paljastukseen\">Koe-el&#xE4;inhoitajien moraalinen ristiriita johti paljastukseen&#xA0;</h3><p>Materiaali on el&#xE4;inkoelaitoksen ty&#xF6;ntekij&#xF6;iden kuvaamaa. Kuvien julkaisun motiiviksi he ovat kertoneet kokemansa moraalisen ristiriidan. Ty&#xF6;ntekij&#xE4;t v&#xE4;litt&#xE4;v&#xE4;t huolehtimistaan koe-el&#xE4;imist&#xE4;, mutta joutuvat silti satuttamaan ja tappamaan niit&#xE4;.&#xA0;&#xA0;<br>&#xA0;<br>Vaikka EU on kielt&#xE4;nyt kosmetiikan el&#xE4;inkokeet, ja pesuaineiden el&#xE4;inkoekielto tulee voimaan vuonna 2029, ovat kemikaalien turvallisuustestauksen vuoksi teht&#xE4;v&#xE4;t el&#xE4;inkokeet edelleen pakollisia. Myrkyllisuuskokeet ovat osa turvallisuustestauksia.</p><p>EU on kuitenkin parhaillaan laatimassa suunnitelmaa el&#xE4;inkokeettomaan tutkimukseen siirtymiseksi kemikaalien myrkyllisyyskokeissa. Jotta tavoite toteutuisi, suunnitelmalla pit&#xE4;&#xE4; olla riitt&#xE4;v&#xE4; rahoitus. Animalia vaatiikin yhdess&#xE4; Animals Internationalin ja muiden el&#xE4;inj&#xE4;rjest&#xF6;jen kanssa EU:lta toimia.&#xA0;&#xA0;</p><p>&#x201D;Vetoamme muiden kansainv&#xE4;listen el&#xE4;inj&#xE4;rjest&#xF6;jen kanssa EU:hun, jotta suunnitelma toteutuu. Lis&#xE4;ksi Suomessa puolueiden tulee ottaa el&#xE4;inkokeiden lopettaminen tavoitteeksi vaality&#xF6;ss&#xE4;&#xE4;n. Vuoden 2027 hallitusohjelmassa hallituksen tulee sitoutua konkreettiseen suunnitelmaan, jonka tavoitteena on koe-el&#xE4;inm&#xE4;&#xE4;rien v&#xE4;hent&#xE4;minen ja el&#xE4;inkokeiden lopettaminen&#x201D;, Kivek&#xE4;s toteaa.&#xA0;</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:104:\"Saksa säästää miljoonia irtautumalla Microsoftista – Suomessa ei edes tiedetä maksujen määrää\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:270:\"Schleswig-Holsteinin osavaltio Saksassa on säästänyt 12 miljoonaa siirtymällä avoimen lähdekoodin ohjelmistoihin. Tietopyynnöllä selvisi, että Suomen julkishallinto ei tiedä tarkkaan, kuinka paljon veronmaksajien rahaa kuluu ulkomaisille teknologiayrityksille.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:129:\"https://www.verdelehti.fi/2026/04/22/saksa-saastaa-miljoonia-irtautumalla-microsoftista-suomessa-ei-edes-tiedeta-maksujen-maaraa/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69e880fdfd0ac800013735c5\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:7:\"Uutinen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:19:\"Tiede ja teknologia\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:25:\"digitaalinen itsenäisyys\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Wed, 22 Apr 2026 17:07:20 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Toimitus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:116:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/Building92microsoft.jpg\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:3821:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/Building92microsoft.jpg\" alt=\"Saksa s&#xE4;&#xE4;st&#xE4;&#xE4; miljoonia irtautumalla Microsoftista &#x2013; Suomessa ei edes tiedet&#xE4; maksujen m&#xE4;&#xE4;r&#xE4;&#xE4;\"><p>Suomen julkishallinnossa ei tarkalleen tiedet&#xE4;, kuinka paljon Microsoftille ja muille amerikkalaisille teknologiaj&#xE4;teille maksetaan. T&#xE4;m&#xE4; selvisi Digitaalinen itsen&#xE4;isyys -kansalaisaloitteen alullepanijoiden tekem&#xE4;st&#xE4; tietopyynn&#xF6;st&#xE4;. </p><p>Tietopyynt&#xF6; l&#xE4;hetettiin Suomen kymmenelle suurimmalle kaupungille sek&#xE4; Uudenmaan, Pirkanmaan ja Varsinais-Suomen hyvinvointialueille ja HUS:lle. Tavoitteena oli selvitt&#xE4;&#xE4;, kuinka paljon julkinen sektori on maksanut ulkomaisten teknologiayritysten palveluista vuosina 2019&#x2013;2024. </p><p>Vastauksista k&#xE4;vi ilmi, ett&#xE4; vain seitsem&#xE4;n n&#xE4;ist&#xE4; tahoista tiet&#xE4;&#xE4; osan kustannuksistaan, mutta l&#xE4;pin&#xE4;kym&#xE4;tt&#xF6;mien hankintak&#xE4;yt&#xE4;nt&#xF6;jen vuoksi tarkkoja lukuja ei ole saatavilla. </p><p>Ainoastaan Jyv&#xE4;skyl&#xE4;n kaupunki vastasi tietopyynt&#xF6;&#xF6;n tarkasti. Se ilmoitti maksaneensa amerikkalaisille digij&#xE4;teille vuosittain seitsem&#xE4;nnumeroisen summan. Vuonna 2024 Microsoftille maksettiin 1,3 miljoonaa euroa.</p><p>Pirkanmaan hyvinvointialue kertoi Microsoftin laskuttavan suoraan noin kymmenen miljoonaa euroa vuodessa. </p><p>Muista kustannuksista ei ole kattavaa selvityst&#xE4;, sill&#xE4; useat julkiset toimijat eiv&#xE4;t pysty erittelem&#xE4;&#xE4;n ulkomaisille teknologiayrityksille maksettuja summia. Tiedot on usein kirjattu kumppaniyritysten kautta, mik&#xE4; vaikeuttaa kustannusseurantaa.</p><p>Nykyisill&#xE4; hankintak&#xE4;yt&#xE4;nn&#xF6;ill&#xE4; tarkkoja kustannuksia ei voida selvitt&#xE4;&#xE4; ilman merkitt&#xE4;vi&#xE4; lis&#xE4;kustannuksia tai viivytyksi&#xE4;.</p><p>Digitaalinen itsen&#xE4;isyys -aloitteen laatijat vaativat hankintakulujen l&#xE4;pin&#xE4;kyvyytt&#xE4; ja lis&#xE4;&#xE4; keskustelua siit&#xE4;, miten Suomi voi v&#xE4;hent&#xE4;&#xE4; riippuvuuttaan ulkomaisista teknologiayrityksist&#xE4; sek&#xE4; kehitt&#xE4;&#xE4; kotimaisia ja eurooppalaisia digitaalisia ratkaisuja kustannusten karsimiseksi ja kansallisen itsem&#xE4;&#xE4;r&#xE4;&#xE4;misoikeuden turvaamiseksi. <br><br>&quot;Esimerkiksi Schleswig-Holsteinin osavaltio Saksassa l&#xE4;hti irtautumaan amerikkalaisista palveluntarjoajista viisi vuotta sitten s&#xE4;&#xE4;st&#xF6;syist&#xE4;. T&#xE4;ll&#xE4; viikolla he raportoivat s&#xE4;&#xE4;st&#xE4;neens&#xE4; lisenssimaksuissa 12 miljoonaa euroa sen j&#xE4;lkeen, kun ovat k&#xE4;ytt&#xE4;neet 9 miljoonaa euroa siirty&#xE4;kseen avoimen l&#xE4;hdekoodin ratkaisuihin&quot;, kertoi Lauri Lavanti, yksi aloitteen alullepanijoista.&#xA0;</p><p>Aloitteen taustalla on Trumpin valtaannousun j&#xE4;lkeinen kehitys Yhdysvalloissa. Trumpin hallinto asetti helmikuussa 2025 pakotteet Kansainv&#xE4;liselle rikostuomioistuimelle (ICC) vastauksena siihen, ett&#xE4; tuomioistuin oli antanut pid&#xE4;tysm&#xE4;&#xE4;r&#xE4;yksen Israelin p&#xE4;&#xE4;ministeri <strong>Benjamin Netanjahusta</strong> Gazan sotarikostutkinnassa. Pakotteiden kohteeksi oli asetettu yhteens&#xE4; kuusi ICC:n tuomaria ja kolme syytt&#xE4;j&#xE4;&#xE4;. Heid&#xE4;n Microsoft-s&#xE4;hk&#xF6;postitilins&#xE4; suljettiin ja pankkitilej&#xE4; j&#xE4;&#xE4;dytettiin. Tuomioistuin oli vahvasti riippuvainen yhdysvaltalaisista palveluntarjoajista, kuten Microsoftista, ja sille aiheutui t&#xE4;st&#xE4; vakavia toiminnallisia ongelmia. Sittemmin tuomioistuin on luopunut Microsoftin k&#xE4;yt&#xF6;st&#xE4;.</p><p><em>Verden p&#xE4;&#xE4;toimittaja Johanna Kohvakka on yksi kansalaisaloitteen alullepanijoista</em></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:42:\"Tekoälymurroksen suomalaiset pullonkaulat\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:228:\"Suomi jää tekoälymurroksessa jälkeen politiikan, ei teknologian vuoksi, kirjoittaa Oskari Lahtinen. Kehitystä jarruttavat erityisesti hajautunut hallinto, varovaisuus ja puuttuva johtajuus. Virosta olisi kiire ottaa mallia.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://www.verdelehti.fi/2026/04/22/tekoalymurroksen-suomalaiset-pullonkaulat/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69e63dfccd4f8200016c02e7\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:11:\"Puheenvuoro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"tekoäly\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:19:\"Tiede ja teknologia\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Wed, 22 Apr 2026 13:11:46 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"Toimitus JL\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:119:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/pexels-pixabay-373543.jpeg\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7469:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/pexels-pixabay-373543.jpeg\" alt=\"Teko&#xE4;lymurroksen suomalaiset pullonkaulat\"><p>Teko&#xE4;ly on hyvinvointivaltion kohtalonkysymys. Suomen tulisi pystytt&#xE4;&#xE4; rakenteet ja saada aikaan samanlainen tahtotila, jolla Viro vie teko&#xE4;lyasiaa eteenp&#xE4;in &#x2013; t&#xE4;t&#xE4; aihetta on hiljattain <a href=\"https://www.verdelehti.fi/2026/04/08/tekoaly-voi-ratkaista-hyvinvointivaltion-kohtalon/\" rel=\"noreferrer\">Verdess&#xE4;</a> k&#xE4;siteltykin.</p><p>Suomen tulee ratkaista ainakin seuraavat nelj&#xE4; ongelmaa liikkuakseen Viron suuntaan. </p><h3 id=\"p%C3%A4%C3%A4ministerin-tulisi-ottaa-asia-omakseen\">P&#xE4;&#xE4;ministerin tulisi ottaa asia omakseen</h3><p>Suomi ei uhkaa ep&#xE4;onnistua teko&#xE4;lymurroksessa teknisesti vaan poliittisesti. Viron entinen presidentti <strong>Toomas Ilves</strong> priorisoi aikanaan valtion digitalisoinnin kaiken muun edelle. T&#xE4;m&#xE4;n seurauksena Virolla on nyt modernit rakenteet, joihin integroida tuorein teko&#xE4;ly verrattain pienell&#xE4; vaivalla. Maan nykyinen p&#xE4;&#xE4;ministeri <strong>Kristen Michal</strong>&#xA0;kertoi juuri Viron pyrkiv&#xE4;n teko&#xE4;lyn soveltamisen johtajaksi. Se integroi teko&#xE4;lymenetelm&#xE4;t kaikille yhteiskunnan sektoreille ja pyrkii kaksinkertaistamaan maan bruttokansantuotteen vuoteen 2035 menness&#xE4;. </p><figure class=\"kg-card kg-image-card\"><img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/image-1_OskariL.png\" class=\"kg-image\" alt=\"Teko&#xE4;lymurroksen suomalaiset pullonkaulat\" loading=\"lazy\" width=\"1170\" height=\"506\" srcset=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/size/w600/2026/04/image-1_OskariL.png 600w, https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/size/w1000/2026/04/image-1_OskariL.png 1000w, https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/image-1_OskariL.png 1170w\" sizes=\"(min-width: 720px) 720px\"></figure><p>Suomessa kukaan ei ole ottanut vastaavaa omistajuutta valtion digitalisoinnin tai teko&#xE4;lymurroksen suhteen.</p><p>Meill&#xE4; teko&#xE4;lymurrosta ratkotaan t&#xE4;ll&#xE4; hetkell&#xE4; <a href=\"https://vm.fi/generatiivisen-tekoalyn-hyodyntamisen-julkisen-hallinnon-verkosto?utm_source=chatgpt.com\">yhteisty&#xF6;foorumeilla</a>. Hallinto kartoittaa, melko vaatimattomalla budjetilla, mit&#xE4; pit&#xE4;isi tehd&#xE4;. Viime viikolla entinen p&#xE4;&#xE4;ministeri <strong>Juha Sipil&#xE4;</strong> kuitenkin <a href=\"https://www.is.fi/politiikka/art-2000011943944.html\">v&#xE4;l&#xE4;ytti teko&#xE4;lymurrosta</a> ratkaisuna Suomen kest&#xE4;vyysvajeeseen. Seuraavan p&#xE4;&#xE4;ministerin tulisi astua Sipil&#xE4;n raottamasta ovesta.</p><p>T&#xE4;ll&#xE4; hetkell&#xE4; voi olla vaikea olla optimistinen seuraavan hallituskauden suhteen, sill&#xE4; ainakaan nykyinen hallitus ei k&#xE4;yt&#xE4;nn&#xF6;ss&#xE4; keskustele lainkaan teko&#xE4;lyst&#xE4; julkisuudessa. Leikkaus- ja veronkorotuspuheen dominanssi kielii, ettei meill&#xE4; viel&#xE4; ole eteenp&#xE4;in viev&#xE4;&#xE4; visiota. </p><p>Teko&#xE4;ly ei kuitenkaan odota.<strong> </strong>Paineen muuttua tulisi tuntua v&#xE4;litt&#xF6;m&#xE4;sti, ja sen tulisi tulla valtionhallinnon huipulta. Ilman t&#xE4;t&#xE4; muut korjausliikkeet ovat toissijaisia.</p><h3 id=\"suomessa-ollaan-varovaisia\">Suomessa ollaan varovaisia</h3><p>Varovaisuus on Suomen poliittisen j&#xE4;rjestelm&#xE4;n kulttuurinen ilmi&#xF6;. Teko&#xE4;lyyn tutustutaan virkamieskunnassa tunnustelujen, pilottien ja kartoitusten kautta. Eri pilotteja on kymmeni&#xE4;. Ne vaikuttavat kuitenkin olevan vaihtelevasti yhteensopiva kokonaisuus pitkin hallinnon tasoja, siiloutuneina eri puolille maata. Niiden skaalaaminen voi t&#xE4;ten olla haastavaa ja toimivatkin pilotit uhkaavat j&#xE4;&#xE4;d&#xE4; paikallisiksi.</p><p>Esimerkiksi HUS on ottanut k&#xE4;ytt&#xF6;&#xF6;n <a href=\"https://www.hus.fi/tietoa-meista/kehittaminen-husissa/digitaalinen-kehittaminen\">teko&#xE4;lyratkaisuja</a>. On kuitenkin ep&#xE4;selv&#xE4;&#xE4;, milloin TYKSiss&#xE4; tai TAYSiss&#xE4; n&#xE4;hd&#xE4;&#xE4;n vastaavat uudistukset, koska kyseess&#xE4; on HUSin uudistus, ei koko terveydenhuollon. </p><p>Virossa murroksen toteutus koskee suuria rakenteita, jotka jakavat yhteisen digitaalisen infran ja johon kuuluvat terveydenhuolto, koulutus, julkishallinto ja liike-el&#xE4;m&#xE4;n tukeminen. Skaalautuvuus on k&#xE4;yt&#xE4;nn&#xF6;ss&#xE4; sis&#xE4;&#xE4;nrakennettua.</p><h3 id=\"suomen-hallintorakenne-on-hajallaan\">Suomen hallintorakenne on hajallaan</h3><p>Suomessa ei ole yht&#xE4; julkista sektoria, jolla teko&#xE4;ly voitaisiin ottaa k&#xE4;ytt&#xF6;&#xF6;n. Meill&#xE4; on hyvinvointialueet, valtionhallinto ja yli 300 melko autonomista kuntaa. Kukin puuhaa v&#xE4;h&#xE4;n omaansa ja vuoropuhelu hallinnonalojen v&#xE4;lill&#xE4; on v&#xE4;h&#xE4;ist&#xE4;. Viro suunnitteli hallintorakenteensa ik&#xE4;&#xE4;n kuin puhtaalta p&#xF6;yd&#xE4;lt&#xE4; Neuvostoliiton hajottua. Suomessa on rakennettu kerrosta kerroksen p&#xE4;&#xE4;lle.</p><p>Kuten valtiovarainministeri&#xF6;n johtava asiantuntija <strong>Aleksi Kopponen</strong> <a href=\"https://www.youtube.com/watch?v=65w92Dsxt1E&amp;t=1715s\" rel=\"noreferrer\">totesi</a>, valtion rakenne on sedimentaarinen. Nopeita muutoksia tapahtuu vain kriisitilanteissa, kun tarve muutokselle on tarpeeksi vahva.&#xA0;Vaatisi ennenn&#xE4;kem&#xE4;tt&#xF6;m&#xE4;n lains&#xE4;&#xE4;d&#xE4;nt&#xF6;projektin muuntaa Suomen hallintorakenteet teko&#xE4;ly-yhteensopiviksi lyhyess&#xE4; aikaikkunassa. Suomessa ei my&#xF6;sk&#xE4;&#xE4;n ole yksitt&#xE4;ist&#xE4; tahoa, joka voisi helposti toteuttaa muutoksen. Tahtotilan tulisi olla yhteinen, kulttuurinen ja p&#xE4;&#xE4;ministeril&#xE4;ht&#xF6;inen.</p><h3 id=\"tarvitsemme-jaetun-teknisen-alustan\">Tarvitsemme jaetun teknisen alustan</h3><p>Virolla on <a href=\"https://fi.wikipedia.org/wiki/X-Road\">X-Road</a>, jossa viranomaisten data liikkuu jouhevasti ja jossa ihmiset voivat tunnistautua yhdell&#xE4; kertaa eri palveluihin. Suurin osa p&#xE4;&#xE4;llekk&#xE4;isyydest&#xE4; on karsittu digitaalisesta asioinnista. Suomen X-road -perustainen Suomi.fi-j&#xE4;rjestelm&#xE4; on otettu hajanaisemmin k&#xE4;ytt&#xF6;&#xF6;n, ja digitaalinen asiointi on Suomessa yh&#xE4; verrattain k&#xF6;mpel&#xF6;&#xE4; ja hidasta. Saadaksemme Viron kiinni, tarvitsemme yhteisen alustan. Teko&#xE4;lymurros edellytt&#xE4;&#xE4; digitalisaatiota, ja seuraavan hallituksen tulisikin tehd&#xE4; siit&#xE4; muiden asioiden edelle ajava ykk&#xF6;sprioriteetti.</p><p>Teko&#xE4;lymurros ei oikeastaan ole yksi politiikan alalaji muiden joukossa vaan julkisen sektorin t&#xE4;ysremontti. Viro on l&#xE4;htenyt fiksusti liikkeelle ja johtaa pian Eurooppaa esimerkill&#xE4;&#xE4;n. Meill&#xE4; keskustelu py&#xF6;rii edelleen sen ymp&#xE4;rill&#xE4;, tulisiko leikata lis&#xE4;&#xE4; vai kenties nostaa veroja. Ongelmamme ratkeavat kuitenkin vasta, kun k&#xE4;ymme k&#xE4;siksi niiden rakenteellisiin juurisyihin. </p><p>Toimiakseen tulevaisuudessa julkinen sektori tarvitsee uuden toimintalogiikan. Paras ehdokas t&#xE4;h&#xE4;n on teko&#xE4;ly&#xE4; laajasti hy&#xF6;dynt&#xE4;v&#xE4; digitaalinen hallinto.</p><p></p><p><strong>Oskari Lahtinen</strong><br><em>Kirjoittaja on turkulainen psykologian tutkija</em></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:49:\"&quot;Ei takaisin puuhun vaan puut takaisin&quot;\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:282:\"Ekologisen kriisin kiireellisyys tekee vihreiden vanhasta kiistakapulasta, talouskasvusta, jälleen ajankohtaisen. Konsta Nylanderin mukaan meidän tulisi unohtaa talouskasvu yhteiskunnallisena prioriteettina ja keskittyä toteuttamaan kestävyysmurrokseen tarvittavat investoinnit.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:75:\"https://www.verdelehti.fi/2026/04/22/ei-takaisin-puuhun-vaan-puut-takaisin/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69df6090cd4f8200016bfeda\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:11:\"Puheenvuoro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:6:\"Talous\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:11:\"talouskasvu\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Wed, 22 Apr 2026 05:40:50 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Toimitus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:127:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/schlappohr-branch-3880865_1280.jpg\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:10735:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/schlappohr-branch-3880865_1280.jpg\" alt=\"&quot;Ei takaisin puuhun vaan puut takaisin&quot;\"><p>Vihre&#xE4;ss&#xE4; liikkeess&#xE4; kuohui 1980-luvulla. Liike oli jakautunut etenkin sen suhteen, mink&#xE4;lainen poliittisen toiminnan muoto olisi paras maailman muuttamiseksi. <strong>Sari Aallon</strong> historiikissa Vaihtoehtopuolue &#x2013; Vihre&#xE4;n liikkeen tie puolueeksi kuvataan sosiaalivihreiden ja jyrkempien ekologisten v&#xE4;list&#xE4; jakolinjaa, joka sai ajoittain varsin ik&#xE4;vi&#xE4; piirteit&#xE4;. Vuosien 1985&#x2013;1988 ristiriitavaiheessa talouskasvukriittiset ekologistit <strong>Pentti Linkola</strong> johtohahmonaan uhkailivat jo kilpailevan puolueen perustamisella.</p><p>Vihre&#xE4; liike rekister&#xF6;itiin lopulta puolueeksi vuonna 1988, ja vaikka kyseess&#xE4; oli jonkinasteinen kompromissi, j&#xE4;iv&#xE4;t radikaaleimmat osat siit&#xE4; pois. Liikkeess&#xE4; pitk&#xE4;&#xE4;n vallalla ollut talouskasvukriittisyys j&#xE4;i hiljalleen historiaan.</p><figure class=\"kg-card kg-image-card kg-card-hascaption\"><img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/Vihrea--t_pa--a--ttiva--t_ja--rjesta--ytya--_valtakunnalliseksi_yhdistykseksi_muttei_puolueeksi_Tampereella_1986.jpg\" class=\"kg-image\" alt=\"&quot;Ei takaisin puuhun vaan puut takaisin&quot;\" loading=\"lazy\" width=\"1920\" height=\"1261\" srcset=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/size/w600/2026/04/Vihrea--t_pa--a--ttiva--t_ja--rjesta--ytya--_valtakunnalliseksi_yhdistykseksi_muttei_puolueeksi_Tampereella_1986.jpg 600w, https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/size/w1000/2026/04/Vihrea--t_pa--a--ttiva--t_ja--rjesta--ytya--_valtakunnalliseksi_yhdistykseksi_muttei_puolueeksi_Tampereella_1986.jpg 1000w, https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/size/w1600/2026/04/Vihrea--t_pa--a--ttiva--t_ja--rjesta--ytya--_valtakunnalliseksi_yhdistykseksi_muttei_puolueeksi_Tampereella_1986.jpg 1600w, https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/Vihrea--t_pa--a--ttiva--t_ja--rjesta--ytya--_valtakunnalliseksi_yhdistykseksi_muttei_puolueeksi_Tampereella_1986.jpg 1920w\" sizes=\"(min-width: 720px) 720px\"><figcaption><span style=\"white-space: pre-wrap;\">Vihre&#xE4;t Tampereella 1986. Kuva: Veli-Matti Parkkinen</span></figcaption></figure><h3 id=\"kasvun-rajat-eiv%C3%A4t-katoa-puhumalla-kest%C3%A4vyydest%C3%A4\">Kasvun rajat eiv&#xE4;t katoa puhumalla kest&#xE4;vyydest&#xE4;</h3><p>Lienee kuitenkin j&#xE4;rkeenk&#xE4;yp&#xE4;&#xE4; sanoa, ett&#xE4; rajoittamaton talouden kasvu rajallisella planeetalla on fysikaalinen mahdottomuus. Talouskasvusta tulee ep&#xE4;taloudellista, kun sen ymp&#xE4;rist&#xF6;lle aiheuttamat ja sosiaaliset kustannukset ovat suuremmat kuin kasvun tuomat hy&#xF6;dyt. Sen takia kaikki puhuvat nyky&#xE4;&#xE4;n kest&#xE4;v&#xE4;st&#xE4; talouskasvusta. Taustalla on oletus siit&#xE4;, ett&#xE4; talouskasvu voidaan irrottaa ymp&#xE4;rist&#xF6;tuhoista.</p><p>Unelmoivatpa taloustieteilij&#xE4;t aineettomasta kasvusta miten paljon hyv&#xE4;ns&#xE4;, n&#xE4;ytt&#xE4;&#xE4; se olevan hyvin vaikeaa. Pelkkien hiilidioksidip&#xE4;&#xE4;st&#xF6;jen tuijottaminen vie nimitt&#xE4;in harhaan. Syyllistymme putkin&#xE4;k&#xF6;isyyteen kun unohdamme, ett&#xE4; olemme jo ylitt&#xE4;neet seitsem&#xE4;n yhdeks&#xE4;st&#xE4; turvallisen ja vakaan maapallon rajasta. </p><p>Vaikka osittaista irtikytkent&#xE4;&#xE4; hiilidioksidin suhteen tapahtuukin, ei se ole riitt&#xE4;v&#xE4;n nopeaa. T&#xE4;ll&#xE4; vauhdilla Pariisin ilmastosopimuksen edellytt&#xE4;m&#xE4;&#xE4;n 95% p&#xE4;&#xE4;st&#xF6;v&#xE4;hennykseen p&#xE4;&#xE4;st&#xE4;isiin noin 220 vuodessa, vaikka p&#xE4;&#xE4;st&#xF6;jen pit&#xE4;isi puolittua joka vuosikymmen 2020-2050.</p><p>Suomessakin p&#xE4;&#xE4;st&#xF6;j&#xE4; on saatu laskettua muun muassa siirtym&#xE4;ll&#xE4; v&#xE4;h&#xE4;p&#xE4;&#xE4;st&#xF6;isiin energianl&#xE4;hteisiin ja ulkoistamalla tuotantoa kehittyviin maihin kuten Kiinaan. Koko tuotantoketjua katsottaessa vauraiden maiden riippuvuus luonnonvaroista osoittautuu hyvin suureksi, eik&#xE4; luonnonvarojen k&#xE4;yt&#xF6;n irtikytkent&#xE4;&#xE4; talouskasvusta ole n&#xE4;kyviss&#xE4;.</p><h3 id=\"talouskasvu-ei-ole-vain-talouskysymys\">Talouskasvu ei ole vain talouskysymys</h3><p>Kuten amerikkalainen toimittaja <strong>H. L. Mencken</strong> on todennut, on &#x201C;jokaiseen monimutkaiseen ongelmaan olemassa ratkaisu, joka on selke&#xE4;, yksinkertainen ja v&#xE4;&#xE4;r&#xE4;&#x201D;. Kasvava talous tarkoittaa lis&#xE4;&#xE4; vakavia ymp&#xE4;rist&#xF6;-ongelmia ja luonnon ekosysteemien tuhoutumista.</p><p>Taloustieteess&#xE4; talouskasvu on onnistumisen mitta, mutta muut tieteenalat ovat alkaneet eneneviss&#xE4; m&#xE4;&#xE4;rin huolestumaan maapallon kantokyvyst&#xE4;. On ristiriitaista, ett&#xE4; talousviisaat kehottavat kansaa kuluttamaan enemm&#xE4;n, jotta talous kasvaisi, mutta k&#xE4;yt&#xE4;nn&#xF6;ss&#xE4; kaikki muut tieteenalat kehottavat ihmisi&#xE4; v&#xE4;hent&#xE4;m&#xE4;&#xE4;n kulutusta ymp&#xE4;rist&#xF6;n k&#xE4;rsiess&#xE4;.</p><p>Voidaankin sanoa, ett&#xE4; taloustieteen ja muiden tieteiden v&#xE4;lille on revennyt railo. Valtaosa taloustieteellisist&#xE4; malleista ennustaa ilmaston l&#xE4;mpenemisen olevan vain pieni t&#xF6;yssy talouden kannalta. Taloustieteen Nobelilla ilmastotutkimuksistaan palkittu William Nordhaus on laskenut, ett&#xE4; 3&#xB0;C l&#xE4;mpeneminen laskisi maailman BKT:ta vain 2,1 prosentilla.</p><p>Mallinnukset vaativat oletuksia, ja Nordhaus j&#xE4;tti huomioimatta teollisuudenalat, joiden tuotanto toteutuu tarkasti valvotussa ymp&#xE4;rist&#xF6;ss&#xE4;, joihin ilmastonmuutos ei vaikuta suoraan. N&#xE4;iden osuus on 87% koko bruttokansantuotteesta. Jos p&#xE4;&#xE4;ll&#xE4; on siis katto, ilmastonmuutoksella ei ole vaikutuksia. Taloustieteilij&#xF6;iden tulisi pysty&#xE4; parempaan.</p><p>Ongelma talouskasvun ja ymp&#xE4;rist&#xF6;n suhteen on viheli&#xE4;inen, sill&#xE4; jos talous ei kasva, ajaudumme velkaantuneisuuden ja korkojen takia ongelmiin. Suomessa on Euroopan pahimmat ty&#xF6;tt&#xF6;myysluvut ja kuluttaja ei kuluta, sill&#xE4; ep&#xE4;varmuus tulevaisuudesta saa s&#xE4;&#xE4;st&#xE4;m&#xE4;&#xE4;n. Voiko mukana olla jollain tasolla my&#xF6;s kasvava tiedostus kuluttamisen ja talouskasvun ymp&#xE4;rist&#xF6;llisist&#xE4; ongelmista? Ehk&#xE4; pienelt&#xE4; osin, mutta nykyinen oikeistohallitus leikkauslistoineen tekee osansa talouskasvun hyydytyksess&#xE4; samalla v&#xE4;hent&#xE4;en polttoaineveroja.</p><p>Jos talouskasvu on mahdotonta ymp&#xE4;rist&#xF6;llisist&#xE4; syist&#xE4; eik&#xE4; talousj&#xE4;rjestelm&#xE4;mme kest&#xE4; talouskasvuttomuutta, mit&#xE4; tehd&#xE4;? Ymp&#xE4;rist&#xF6; on reaalinen rajoite kun taas talousj&#xE4;rjestelm&#xE4; ihmisen kehittelem&#xE4; tuote. Onko helpompi muuttaa ajatuksia vai fysiikkaa?</p><p>Kun ymp&#xE4;rist&#xF6;velka kasvaa, rahan s&#xE4;&#xE4;nn&#xF6;t jouduttaneen kirjoittamaan joka tapauksessa uusiksi. Sill&#xE4; jos emme itse rajoita talouskasvua, niin luonto kyll&#xE4; lopettaa talouskasvun lopulta ymp&#xE4;rist&#xF6;ongelmien pahentuessa. Silloin vasta yhteiskunnallisia ongelmia ilmeneekin.</p><p>Vakuutusmatematiikkoja ja riskin ammattilaisia voi tuskin kukaan v&#xE4;itt&#xE4;&#xE4; ilmastoalarmisteiksi, sill&#xE4; mit&#xE4; syyt&#xE4; heill&#xE4; siihen olisi. He n&#xE4;kev&#xE4;t tulevaisuuden 2070-2090 -lukujen paikkeilla niin, ett&#xE4; maailmantalous olisi tuhojen takia noin 50% pienempi. Vertailuna 2008 finanssikriisin vaikutus oli noin -5%, koronapandemian noin -4%. Vakuutusmatemaatikot p&#xE4;&#xE4;tt&#xE4;v&#xE4;t raporttinsa kohtalaisen kuivasti: &#x201C;jos emme hillitse ilmastonmuutosta, taloudellisen tuoton saaminen tulee olemaan poikkeuksellisen haastavaa&#x201D;.</p><h3 id=\"heitet%C3%A4%C3%A4n-talouskasvu-tavoitteena-roskakoriin\">Heitet&#xE4;&#xE4;n talouskasvu tavoitteena roskakoriin</h3><p>Otsikon sitaatti &quot;Ei takaisin puuhun vaan puut takaisin&quot; on alunperin <strong>Pekka Haaviston</strong> kyn&#xE4;st&#xE4; 70-luvun lopun <em>K&#xF6;ynn&#xF6;s</em>-lehden p&#xE4;&#xE4;kirjoituksesta. Olisin itse varmaan tuolloin ollut kallellani soininvaaralaisittaisiin sosiaalivihreisiin ja kummastellut radikaaleja ekologisteja. Mutta n&#xE4;ytt&#xE4;&#xE4; silt&#xE4;, etteiv&#xE4;t ekologistit aivan v&#xE4;&#xE4;r&#xE4;ss&#xE4; olleet, sill&#xE4; talouskasvu n&#xE4;ytt&#xE4;&#xE4; olevan vahvasti yhteydess&#xE4; ymp&#xE4;rist&#xF6;ongelmiin.</p><p>Huomionarvoista kuitenkin on, ett&#xE4; vaikka talous jatkossa supistuisikin, pahentuisi ekologinen kriisi nykyrakenteilla. Ehk&#xE4; meid&#xE4;n tarvitsee mielummin unohtaa talouskasvu yhteiskunnallisena prioriteettina ja keskitty&#xE4; toteuttamaan kest&#xE4;vyysmurrokseen tarvittavat investoinnit. Siirtym&#xE4; v&#xE4;h&#xE4;hiiliseen ja ymp&#xE4;rist&#xF6;lle kest&#xE4;v&#xE4;&#xE4;n tulevaisuuteen on teht&#xE4;v&#xE4; hallitusti ja sosiaalisesti oikeudenmukaisesti, muuten sille ei synny riitt&#xE4;v&#xE4;&#xE4; poliittista kannatusta. </p><p>Toivoa luova ajatus onkin, ett&#xE4; ilmasto- ja luontokriisien p&#xE4;&#xE4;syy ei olekaan ihmisen kyltym&#xE4;t&#xF6;n halu kasvattaa taloutta, vaan talouskasvun tarve on nykyisen rahaj&#xE4;rjestelm&#xE4;mme ominaisuus. Ei ole tarvetta palata asumaan maakuoppaan tai turvautua linkolalaiseen ekofasismiin. </p><p>Tulevaisuuden taloustieteilij&#xE4;t voivat osata tarjota meille vaihtoehtoja ikuiseen talouskuriin, sill&#xE4; rahoitusj&#xE4;rjestelm&#xE4; on lopulta riippuvainen valtioista, ei toisinp&#xE4;in. Yhdysvaltain katastrofaalisen 1930-luvun laman j&#xE4;lkeen presidentti <strong>Franklin Roosevelt</strong> toteutti tunnetun taloustieteilij&#xE4; <strong>John Maynard Keynesin </strong>mallintamia ideoita jo ennen kuin Keynes oli niit&#xE4; edes muotoillut. Voikin olla, ett&#xE4; jatkossa taloustieteilij&#xE4;t p&#xE4;&#xE4;tyv&#xE4;t k&#xE4;yt&#xE4;nn&#xF6;nl&#xE4;heisten ja rohkeiden poliitikkojen haastamiksi &#x2013; tai huomaavat vaikutusvaltansa lipuvan pois k&#xE4;sist&#xE4;&#xE4;n.</p><p>Kuten Pekka Haavisto on my&#xF6;hemmin sanonut, on meill&#xE4; varaa ja mahdollisuuksia yhteiskunnassa sek&#xE4; suojella luontoa ett&#xE4; el&#xE4;&#xE4; kohtuullisessa elintasossa. Seh&#xE4;n on ollut vihreiden teesi oikeastaan alusta alkaen.<br></p><p><strong>Konsta Nylander&#x2028;</strong><br>Kirjoittaja on Varsinais-Suomen hyvinvointialueen aluevaltuutettu ja aluehallituksen j&#xE4;sen&#x2028;sek&#xE4; Talousdemokratia-kansalaisj&#xE4;rjest&#xF6;n puheenjohtaja</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:75:\"Raportti: media käsittelee naisiin kohdistuvaa väkivaltaa yhä vähemmän\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:232:\"Naisiin kohdistuva väkivalta saa vähemmän tilaa uutisissa samaan aikaan kun naisvihamielinen retoriikka voimistuu. Uusi analyysi osoittaa, että media käsitteli aihetta vuonna 2025 vähemmän kuin kertaakaan yhdeksään vuoteen.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:107:\"https://www.verdelehti.fi/2026/04/21/raportti-media-kasittelee-naisiin-kohdistuvaa-vakivaltaa-yha-vahemman/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69e5cd33cd4f8200016c01c5\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:4:{i:0;a:5:{s:4:\"data\";s:7:\"Uutinen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:10:\"väkivalta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:16:\"naisten oikeudet\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:5:\"media\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Tue, 21 Apr 2026 09:15:13 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Toimitus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:120:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/pexels-jaralol-17155075.jpg\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5763:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/pexels-jaralol-17155075.jpg\" alt=\"Raportti: media k&#xE4;sittelee naisiin kohdistuvaa v&#xE4;kivaltaa yh&#xE4; v&#xE4;hemm&#xE4;n\"><p>Kansainv&#xE4;linen uutismedia k&#xE4;sitteli vuonna 2025 naisiin ja tytt&#xF6;ihin kohdistuvaa v&#xE4;kivaltaa poikkeuksellisen v&#xE4;h&#xE4;n, paljastaa uusi AKAS-ajatushautomon <a href=\"https://www.akas.london/userfiles/The%20Global%20Misogyny%20News%20Coverage%20Tracker%20Final%2014.04.26.pdf\" rel=\"noreferrer\">analyysi</a>. <a href=\"https://www.theguardian.com/global-development/2026/apr/17/media-coverage-violence-against-women-low-report?utm_source=chatgpt.com\" rel=\"noreferrer\">The Guardianin</a> mukaan misogynistista v&#xE4;kivaltaa tai h&#xE4;irint&#xE4;&#xE4; koskevia termej&#xE4; esiintyi vain 1,3 prosentissa kaikista maailman verkkomediassa julkaistuista uutisista. Se on matalin osuus koko vuosien 2017&#x2013;2025 tarkastelujaksolla.</p><p><a href=\"https://www.akas.london/\" rel=\"noreferrer\">AKASin</a> seurantaraportti pohjaa yli miljardiin verkkoartikkeliin, ja sen tarkoitus on mitata sek&#xE4; misogyniaa koskevan uutisoinnin m&#xE4;&#xE4;r&#xE4;&#xE4; ett&#xE4; laatua. Analyysi tarkastelee my&#xF6;s sit&#xE4;, miten uutismedia k&#xE4;sittelee naisiin kohdistuvaa v&#xE4;kivaltaa ja misogynistista h&#xE4;irint&#xE4;&#xE4;. Seurannan on tarkoitus jatkua vuosittain.</p><p>Huomio naisten kokemaan h&#xE4;irint&#xE4;&#xE4;n on laskenut selv&#xE4;sti sitten #MeToo-liikkeen huippuvuosien. Guardianin mukaan osuus oli korkeimmillaan 2,2 prosenttia vuonna 2018. Raportti nostaa esiin ristiriidan: vaikka naisiin kohdistuva v&#xE4;kivalta, my&#xF6;s teko&#xE4;lyn avulla tuotettu digitaalinen v&#xE4;kivalta, on yleistynyt ja saanut uusia muotoja, aihe n&#xE4;kyy uutisissa yh&#xE4; harvemmin.</p><p>Raportin mukaan ongelmana on uutisoinnin m&#xE4;&#xE4;r&#xE4;n lis&#xE4;ksi my&#xF6;s valitut n&#xE4;k&#xF6;kulmat. V&#xE4;kivaltaa k&#xE4;sittelev&#xE4; uutisointi j&#xE4;&#xE4; usein tapauskohtaiseksi, ja lis&#xE4;ksi siin&#xE4; painottuvat miesasiantuntijat. Usein selviytyneiden &#xE4;&#xE4;ni sek&#xE4; ratkaisuihin keskittyv&#xE4; n&#xE4;k&#xF6;kulma puuttuvat. </p><p>The Guardian nostaa esiin my&#xF6;s sen, ett&#xE4; edes n&#xE4;kyviss&#xE4; hyv&#xE4;ksik&#xE4;ytt&#xF6;- ja v&#xE4;kivaltatapauksissa sukupuolistunutta v&#xE4;kivaltaa ei aina sanoiteta sellaisena. Lehden mukaan esimerkiksi <strong>Jeffrey Epsteini&#xE4;</strong> koskevissa uutisissa vain 0,1 prosenttia artikkeleista viittasi naisiin kohdistuvaan v&#xE4;kivaltaan, vaikka tapausten ytimess&#xE4; oli alaik&#xE4;isiin tytt&#xF6;ihin ja nuoriin naisiin kohdistunut hyv&#xE4;ksik&#xE4;ytt&#xF6;.</p><p>Samaan aikaan kun v&#xE4;kivaltauutisointi hiipuu, naisvihamielinen retoriikka on vahvistunut. Termin &quot;sukupuoli-ideologia&quot;, jota tasa-arvoa vastustavat liikkeet k&#xE4;ytt&#xE4;v&#xE4;t naisten oikeuksien horjuttamiseen, k&#xE4;ytt&#xF6; kasvoi 42-kertaiseksi vuosien 2020 ja 2025 v&#xE4;lill&#xE4;.</p><p>Ilmi&#xF6;ll&#xE4; on yhteys laajempaan poliittiseen kehitykseen. </p><p>&quot;Kehitys on j&#xE4;rkytt&#xE4;v&#xE4;&#xE4;, etenkin kun huomioi ongelman laajuuden ja sen, miten autoritaariset toimijat ovat ottaneet misogynian ja naisiin kohdistuvan v&#xE4;kivallan suorastaan poliittisiksi aseiksi oikeuksien kaventamisessa,&quot; kommentoi Journalismin ja demokratian keskuksen johtaja <strong>Julie Posetti</strong> asiaa <a href=\"https://www.thenews.com.pk/latest/1399314-violence-against-women-underreported-as-media-coverage-drops-to-pitiful-low\" rel=\"noreferrer\"><em>The News</em></a>-lehdelle. </p><p>&quot;T&#xE4;m&#xE4; kertoo lehdist&#xF6;n ep&#xE4;onnistumisesta &#x2013; kuinka v&#xE4;h&#xE4;n olemme edistyneet, ja kuinka pitk&#xE4; matka on viel&#xE4; edess&#xE4;&quot;, Posetti sanoo.</p><p>Brittil&#xE4;inen turvakotij&#xE4;rjest&#xF6; <a href=\"https://refuge.org.uk/news/refuge-urges-for-improved-media-reporting-on-violence-against-women-and-girls/\" rel=\"noreferrer\">Refuge</a> vaati raportin j&#xE4;lkeen mediaa muuttamaan tapaansa k&#xE4;sitell&#xE4; naisiin kohdistuvaa v&#xE4;kivaltaa. J&#xE4;rjest&#xF6;n mukaan uutisoinnilla on keskeinen rooli siin&#xE4;, miten yleis&#xF6; ymm&#xE4;rt&#xE4;&#xE4; v&#xE4;kivallan laajuuden, syyt ja seuraukset. Refuge viittasi my&#xF6;s raportin havaintoon, jonka mukaan haut termill&#xE4; &#x201C;domestic abuse support&#x201D; kasvoivat vuosina 2017&#x2013;2025 viisinkertaisiksi, vaikka aihetta koskeva uutisn&#xE4;kyvyys samalla heikkeni.</p><p>AKASin raportin mukaan tilannetta voisi parantaa siten, ett&#xE4; media tekisi naisiin kohdistuvasta v&#xE4;kivallasta satunnaisten rikosuutisten sijaan jatkuvan ja rakenteellisen seurannan kohteen. Toimitusten pit&#xE4;isi nostaa selviytyjien &#xE4;&#xE4;nt&#xE4;, tarjota useammin tietoa avun hakemiseen ja vahvistaa sellaista journalismia, joka tarkastelee v&#xE4;kivallan yhteytt&#xE4; sukupuolten eriarvoisuuteen. </p><p>Yksi konkreettinen keino on antaa enemm&#xE4;n tilaa toimittajille, joilla on valmiutta ja resursseja k&#xE4;sitell&#xE4; aihetta johdonmukaisesti eik&#xE4; vain yksitt&#xE4;isten tapausten kautta. Samalla toimitusten olisi syyt&#xE4; kiinnitt&#xE4;&#xE4; huomiota siihen, ket&#xE4; he k&#xE4;ytt&#xE4;v&#xE4;t asiantuntijoina ja millaisia n&#xE4;k&#xF6;kulmia toistetaan.</p><p>AKAS sanoo raporttinsa olevan kohdistettu erityisesti toimituksille, p&#xE4;&#xE4;toimittajille, toimittajille, rahoittajille, p&#xE4;&#xE4;tt&#xE4;jille ja kansalaisj&#xE4;rjest&#xF6;ille. Ajatushautomon mukaan tavoitteena on osoittaa, miksi journalismiin, joka tutkii misogyniaa ja asettaa naiset ja tyt&#xF6;t kertomusten keski&#xF6;&#xF6;n, pit&#xE4;isi investoida nykyist&#xE4; enemm&#xE4;n.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:62:\"Mitä jos lääkärikäyntisi päättyisi luontolähetteeseen?\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:260:\"Tutkimus osoittaa jälleen, että luonnossa vietetty aika parantaa mielenterveyttä, unta ja toimintakykyä. Silti luontoyhteyttä hyödynnetään terveydenhuollossa vähän. Lääkäri Annika Kolster kannustaa ottamaan luontolähetteen useammin osaksi hoitoa.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:91:\"https://www.verdelehti.fi/2026/04/20/mita-jos-laakarikayntisi-paattyisi-luontolahetteeseen/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69e0c8dfcd4f8200016c0018\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:4:{i:0;a:5:{s:4:\"data\";s:7:\"Uutinen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:17:\"Luonto ja ilmasto\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:7:\"terveys\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:13:\"mielenterveys\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Mon, 20 Apr 2026 20:10:47 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"Toimitus JL\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:134:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/pexels-lauripoldre-33961185-copy-2-1.jpeg\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:3154:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/pexels-lauripoldre-33961185-copy-2-1.jpeg\" alt=\"Mit&#xE4; jos l&#xE4;&#xE4;k&#xE4;rik&#xE4;yntisi p&#xE4;&#xE4;ttyisi luontol&#xE4;hetteeseen?\"><p>Tutkimus vahvistaa sen, mit&#xE4; moni suomalainen jo kokemusper&#xE4;isesti tiet&#xE4;&#xE4;: luonto tekee hyv&#xE4;&#xE4;. Luonnossa vietetty aika edist&#xE4;&#xE4; mielenterveytt&#xE4;, toimintakyky&#xE4; ja p&#xE4;rj&#xE4;&#xE4;mist&#xE4;. Vaikka tutkimusn&#xE4;ytt&#xF6; on vahvaa, tiedon soveltaminen terveydenhuollossa on edelleen lapsen kengiss&#xE4;.</p><p>Helsingin yliopistossa v&#xE4;ittelev&#xE4; terveyskeskusl&#xE4;&#xE4;k&#xE4;ri&#xA0;<strong>Annika Kolster</strong>&#xA0;tutki luontoyhteyden vaikutusta eri ryhmille. </p><p>&quot;I&#xE4;kk&#xE4;ill&#xE4; palvelutalon asukkailla vahvempi luontoyhteys oli yhteydess&#xE4; parempaan mielenterveyteen. Luonto oli heille eritt&#xE4;in t&#xE4;rke&#xE4; asia, jopa suurempi kun osasin odottaa. Uskon, ett&#xE4; luontosuhdetta vahvistamalla voidaan parantaa i&#xE4;kk&#xE4;iden toimintakyky&#xE4; ja yleist&#xE4; hyvinvointia&quot;, Kolster kertoo.&#xA0;</p><p>Kolster tutki my&#xF6;s terveyskeskuksen asiakkaita. Heill&#xE4; luonnossa tapahtuva toiminta tuki mielenterveytt&#xE4; ja paransi unta.</p><h3 id=\"luontosuhteen-vahvistaminen-osaksi-hoitosuunnitelmaa\">Luontosuhteen vahvistaminen osaksi hoitosuunnitelmaa</h3><p>Kolster suosittelee luonnossa liikkumista kaikille. Etenkin ryhm&#xE4;ss&#xE4; liikkumisesta on hy&#xF6;ty&#xE4;, ja mik&#xE4; vain l&#xE4;hiluontokohdekin kelpaa hyvin.</p><p>Terveyskeskusl&#xE4;&#xE4;k&#xE4;rin&#xE4; Kolster rohkaisee terveydenhuollon ammattilaisia suosittelemaan luonnossa oleskelua yhten&#xE4; l&#xE4;&#xE4;kkeett&#xF6;m&#xE4;n&#xE4; hoitokeinona.</p><p>&quot;Meid&#xE4;n on t&#xE4;rke&#xE4;&#xE4; l&#xF6;yt&#xE4;&#xE4; keinoja, joilla voidaan edist&#xE4;&#xE4; terveytt&#xE4; ja toimintakyky&#xE4;. N&#xE4;m&#xE4; l&#xE4;&#xE4;kkeett&#xF6;m&#xE4;t keinot voivat olla my&#xF6;s jo olemassa olevan sairauden hoitoa. Luontol&#xE4;hetett&#xE4; voitaisiin hy&#xF6;dynt&#xE4;&#xE4; nykyist&#xE4; paremmin esimerkiksi ty&#xF6;tt&#xF6;mien, mielenterveysasiakkaiden ja i&#xE4;kk&#xE4;iden terveyspalveluissa&quot;, Kolster summaa.</p><p>Luontol&#xE4;hete tarkoittaa ihmisten ohjaamista ja kannustamista omaehtoiseen hyvinvoinnin yll&#xE4;pitoon luonnon keskell&#xE4;. T&#xE4;llainen toiminta voi sis&#xE4;lt&#xE4;&#xE4; liikkumista, luonnon ilmi&#xF6;iden tarkastelua ja keskustelua. </p><p>Kolster haluaisi, ett&#xE4; terveydenhoidon ammattilaiset olisivat k&#xE4;rkijoukoissa vahvistamassa ihmisten luontoyhteytt&#xE4;. Luonnolla on h&#xE4;nen mukaansa kokonaisvaltainen merkitys osana sairauden hoitoa.</p><p>&quot;Pelk&#xE4;&#xE4;n, ett&#xE4; ihmisten vieraantuminen luonnosta aiheuttaa lis&#xE4;&#xE4;ntyv&#xE4;&#xE4; oireilua ja sairautta. Olen erityisen huolissani luonnon monimuotoisuuden k&#xF6;yhtymisest&#xE4;. Emme ehk&#xE4; ymm&#xE4;rr&#xE4;k&#xE4;&#xE4;n, mink&#xE4;laiset seuraukset terveyteen t&#xE4;ll&#xE4; voi olla. Suuntaa voidaan muuttaa, mutta meill&#xE4; on jo kiire toimia.&quot;</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:100:\"Holopainen kirittää hallitusta: ”Droonien torjunnan lisäksi tarvitaan laajempaa varautumista”\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:299:\"Vihreiden kansanedustaja Hanna Holopainen on tyytyväinen hallituksen aikeisiin panostaa droonien torjuntaan osana tulevan kehysriihen päätöksiä. Hän muistuttaa, että hyvinvointialueiden rahoituksen turvaaminen erityisesti rajamaakunnissa on välttämätöntä laajemman varautumisen kannalta.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:128:\"https://www.verdelehti.fi/2026/04/20/holopainen-kirittaa-hallitusta-droonien-torjunnan-lisaksi-tarvitaan-laajempaa-varautumista/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69e61c7dcd4f8200016c02c1\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:7:\"Uutinen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:10:\"Politiikka\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:24:\"kansallinen turvallisuus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Mon, 20 Apr 2026 20:08:55 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Toimitus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:139:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/94ba103b-083c-49b3-8272-d2135dc9c4f8-w_960.jpg\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2194:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/94ba103b-083c-49b3-8272-d2135dc9c4f8-w_960.jpg\" alt=\"Holopainen kiritt&#xE4;&#xE4; hallitusta: &#x201D;Droonien torjunnan lis&#xE4;ksi tarvitaan laajempaa varautumista&#x201D;\"><p>Puolustusvaliokunnan j&#xE4;sen, vihreiden lappeenrantalainen kansanedustaja <strong>Hanna Holopainen</strong> (vihr) on tyytyv&#xE4;inen mediatietoihin, joiden mukaan hallitus on satsaamassa kehysriihess&#xE4; droonien torjuntaan.</p><p>&quot;T&#xE4;m&#xE4; mediatietojen mukaan muutaman kymmenen miljoonan kokoinen lis&#xE4;rahoitus poliisille sek&#xE4; rajavartiolaitokselle on hyv&#xE4; ja tarpeellinen alku droonien torjunnan vahvistamiseen. Viimeaikaisten havaintojen j&#xE4;lkeen on t&#xE4;rke&#xE4;&#xE4; vahvistaa luottamusta siihen, ett&#xE4; Suomessa ollaan varauduttu t&#xE4;h&#xE4;nkin&quot;, Kaakkois-Suomessa asuva Holopainen toteaa.</p><p>Holopainen per&#xE4;&#xE4; hallitukselta kuitenkin laajempaa, kokonaisturvallisuuden huomioivaa varautumista. H&#xE4;nen mukaansa on ristiriitaista tarttua yksitt&#xE4;iseen julkisuudessa esill&#xE4; olleeseen ongelmaan samalla, kun kokonaisturvallisuutta heikennet&#xE4;&#xE4;n toisaalla rajuilla leikkauksilla.</p><p>&quot;Droonien torjunnan lis&#xE4;ksi tarvitaan laajempaa varautumista. Hyvinvointialueet ja kunnat ovat t&#xE4;ss&#xE4; keskeisess&#xE4; asemassa, sill&#xE4; ne huolehtivat siviiliyhteiskunnan toimintojen suojaamisesta niin poikkeusoloissa kuin normaaliolojen h&#xE4;iri&#xF6;tilanteissa. Etel&#xE4;-Karjalassa varautumisessa oleellista on t&#xE4;ll&#xE4; hetkell&#xE4; hyvinvointialueen riitt&#xE4;v&#xE4; rahoitus, jotta rajaseudun maakuntana voidaan huolehtia riitt&#xE4;v&#xE4;st&#xE4; varautumisesta&quot;, Holopainen painottaa.</p><p>Hallituksen oman p&#xE4;&#xE4;t&#xF6;ksen lis&#xE4;ksi Holopainen pit&#xE4;&#xE4; t&#xE4;rke&#xE4;n&#xE4;, ett&#xE4; EU toimii asiassa yhten&#xE4;isesti ja tukee my&#xF6;s taloudellisesti droonien torjuntaan liittyvi&#xE4; hankkeita. </p><p>Haaste on h&#xE4;nen mukaansa koko unionin laajuinen, sill&#xE4; droonien muodostama uhka ei rajoitu pelk&#xE4;st&#xE4;&#xE4;n it&#xE4;rajan tuntumaan.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:123:\"Tutkimus paljastaa, missä näätä, kärppä ja lumikko viihtyvät – elinympäristöt kartoitettiin ensimmäistä kertaa\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:264:\"Näädän, kärpän ja lumikon kannat ovat kutistuneet eri puolilla Suomea jo vuosikymmeniä. Muutos voi heijastua peto-saalissuhteisiin ja metsien ekosysteemeihin. Tuore tutkimus kertoo nyt, millaisissa elinympäristöissä näätäeläimet menestyvät parhaiten.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:144:\"https://www.verdelehti.fi/2026/04/20/tutkimus-paljastaa-missa-naata-karppa-ja-lumikko-viihtyvat-elinymparistot-kartoitettiin-ensimmaista-kertaa/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69e0cf81cd4f8200016c003b\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:7:\"Uutinen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:17:\"Luonto ja ilmasto\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:12:\"petoeläimet\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Mon, 20 Apr 2026 20:06:16 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Toimitus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:139:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/36a5fb1a-0830-4928-8732-6d52dbe7b50e-w_720.png\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5736:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/36a5fb1a-0830-4928-8732-6d52dbe7b50e-w_720.png\" alt=\"Tutkimus paljastaa, miss&#xE4; n&#xE4;&#xE4;t&#xE4;, k&#xE4;rpp&#xE4; ja lumikko viihtyv&#xE4;t &#x2013; elinymp&#xE4;rist&#xF6;t kartoitettiin ensimm&#xE4;ist&#xE4; kertaa\"><p>Aalto-yliopiston tutkijat ovat ensimm&#xE4;ist&#xE4; kertaa kartoittaneet n&#xE4;&#xE4;d&#xE4;n, k&#xE4;rp&#xE4;n ja lumikon elinymp&#xE4;rist&#xF6;j&#xE4; koko Suomen laajuudelta. Lentolaserkeilaukseen ja lumij&#xE4;lkiin perustuva tutkimus tarjoaa ainutlaatuista tietoa siit&#xE4;, miten mets&#xE4;rakenne ja maasto vaikuttavat lajien esiintymiseen.</p><p>&#x201C;Useiden n&#xE4;&#xE4;t&#xE4;el&#xE4;inten kannat ovat romahtaneet, eik&#xE4; niiden elinymp&#xE4;rist&#xF6;ist&#xE4; ole aiemmin ollut koko maan kattavaa tutkimusta. Uuden tutkimusmenetelm&#xE4;n avulla saimme arvokasta tietoa, joka auttaa tunnistamaan n&#xE4;&#xE4;t&#xE4;el&#xE4;imille t&#xE4;rkeit&#xE4; elinymp&#xE4;rist&#xF6;j&#xE4; aiempaa laajemmin &#x2013; ja jatkossa arvioimaan esimerkiksi maank&#xE4;yt&#xF6;n muutosten vaikutuksia niihin&#x201D;, kertoo geoinformatiikan v&#xE4;it&#xF6;skirjatutkija&#xA0;<strong>Pinja-Emilia L&#xE4;ms&#xE4;</strong>&#xA0;Aalto-yliopistosta.</p><p><a href=\"https://www.sciencedirect.com/science/article/pii/S0378112726002409\">Tutkimuksessa</a>&#xA0;havaittiin selvi&#xE4; eroja lajien v&#xE4;lill&#xE4;: n&#xE4;&#xE4;t&#xE4; viihtyy tiheiss&#xE4; ja monikerroksisissa varttuneemmissa metsiss&#xE4;, k&#xE4;rpp&#xE4; puolestaan hy&#xF6;dynt&#xE4;&#xE4; sek&#xE4; metsi&#xE4; ett&#xE4; avoimempia alueita. Lumikon esiintyminen n&#xE4;ytt&#xE4;&#xE4; kytkeytyv&#xE4;n v&#xE4;hemm&#xE4;n mets&#xE4;n rakenteeseen ja enemm&#xE4;n maanpinnan kasvillisuuteen.</p><p>&#x201C;Lumikko el&#xE4;&#xE4; l&#xE4;hemp&#xE4;n&#xE4; maanpintaa ja k&#xE4;ytt&#xE4;&#xE4; l&#xE4;hes yksinomaan myyri&#xE4; ravintonaan. Myyrien saatavuus saattaa siis olla sille maaston rakenneominaisuuksia t&#xE4;rke&#xE4;mpi tekij&#xE4; elinymp&#xE4;rist&#xF6;&#xE4; valitessa&#x201D;, L&#xE4;ms&#xE4; sanoo.</p><figure class=\"kg-card kg-image-card kg-card-hascaption\"><img src=\"https://www.sttinfo.fi/data/images/public/37936456/71950663/36a5fb1a-0830-4928-8732-6d52dbe7b50e-w_720.png\" class=\"kg-image\" alt=\"Tutkimus paljastaa, miss&#xE4; n&#xE4;&#xE4;t&#xE4;, k&#xE4;rpp&#xE4; ja lumikko viihtyv&#xE4;t &#x2013; elinymp&#xE4;rist&#xF6;t kartoitettiin ensimm&#xE4;ist&#xE4; kertaa\" loading=\"lazy\" width=\"720\" height=\"540\"><figcaption><span style=\"white-space: pre-wrap;\">Lentolaserkeilaukseen ja lumij&#xE4;lkiin perustuvat kartat kertovat, miss&#xE4; n&#xE4;&#xE4;t&#xE4;el&#xE4;imi&#xE4; on havaittu. Kuva: Pinja-Emilia L&#xE4;ms&#xE4; / Aalto-yliopisto</span></figcaption></figure><h3 id=\"k%C3%A4rp%C3%A4n-ja-lumikon-kannat-romahtaneet\">K&#xE4;rp&#xE4;n ja lumikon kannat romahtaneet</h3><p>Luonnonvarakeskuksen vuonna 2024 julkaiseman&#xA0;<a href=\"https://jukuri.luke.fi/server/api/core/bitstreams/d3823a2b-e65f-4d82-8c93-0315f28e6474/content\">raportin</a>&#xA0;mukaan kaikkien kolmen lajin kannat ovat laskeneet Suomessa monin paikoin viime vuosikymmenten aikana. N&#xE4;&#xE4;d&#xE4;n kanta on Etel&#xE4;-Suomessa pudonnut noin puoleen 1990-luvun tasosta, mutta Pohjois-Suomessa kanta on kasvanut merkitt&#xE4;v&#xE4;sti. </p><p>Suomen k&#xE4;rpp&#xE4;kannasta on h&#xE4;vinnyt noin 84 prosenttia ja lumikkokannasta noin 70 prosenttia.</p><p>Kyse ei ole pelkist&#xE4; lyhytaikaisista kannanvaihteluista, vaan erityisesti k&#xE4;rp&#xE4;n ja lumikon kohdalla pitk&#xE4;aikaisesta ja voimakkaasta taantumasta, L&#xE4;ms&#xE4; sanoo. Tarkkaa syyt&#xE4; ei viel&#xE4; tunneta, mutta taustalla voivat olla esimerkiksi heikentyneet myyr&#xE4;syklit ja metsien rakenteen muutokset.</p><p>&#x201C;Kaikki kolme ovat meill&#xE4; luonnonvaraisia ja kuuluvat Suomen luontoon. Kantojen v&#xE4;heneminen ja lopulta mahdollinen h&#xE4;vi&#xE4;minen vaikuttaa eli&#xF6;iden v&#xE4;liseen vuorovaikutukseen ja ravintoverkkoihin. T&#xE4;m&#xE4; voi heijastua edelleen kasvillisuuteen ja jopa koko ekosysteemin toimintaan&quot;, L&#xE4;ms&#xE4; toteaa.</p><p>&quot;Esimerkiksi lumikon ja k&#xE4;rp&#xE4;n v&#xE4;henemisen on arvioitu lis&#xE4;&#xE4;v&#xE4;n myyr&#xE4;kantoja, mik&#xE4; puolestaan voi johtaa lis&#xE4;&#xE4;ntyviin taimikkotuhoihin ja siten vaikuttaa sek&#xE4; luonnonmetsiin ett&#xE4; mets&#xE4;talouteen.&#x201D;</p><h2 id=\"maaston-mittausta-ilmasta-k%C3%A4sin\">Maaston mittausta ilmasta k&#xE4;sin</h2><p>Aalto-yliopiston ja Luonnonvarakeskuksen yhteisess&#xE4; tutkimuksessa hy&#xF6;dynnettiin Maanmittauslaitoksen koko Suomen kattavaa lentolaserkeilausaineistoa (ALS), jonka avulla voidaan muodostaa kolmiulotteinen malli maastosta ja metsist&#xE4;: puuston korkeudesta, tiheydest&#xE4; ja kerroksellisuudesta sek&#xE4; maiseman vaihtelusta.</p><p>T&#xE4;t&#xE4; mets&#xE4;rakennetta kuvaavaa aineistoa yhdistettiin Luonnonvarakeskuksen lumij&#xE4;lkiaineistoon kymmenen vuoden ajalta.</p><p>&#x201C;Lentokoneesta teht&#xE4;v&#xE4;n laserkeilauksen avulla voidaan kuvata tarkasti elinymp&#xE4;rist&#xF6;jen, esimerkiksi metsien, rakennetta, mihin monien lajien esiintyminen kytkeytyy. N&#xE4;in el&#xE4;inten elinymp&#xE4;rist&#xF6;j&#xE4; voidaan tutkia laajemmassa mittakaavassa ja tehokkaammin kuin perinteisten maastomittausten avulla&#x201D;, L&#xE4;ms&#xE4; kertoo.</p><p>Tutkijat painottavat, ett&#xE4; n&#xE4;&#xE4;t&#xE4;el&#xE4;inkantojen vahvistamiseksi tarvitaan lis&#xE4;&#xE4; tietoa taantumisen syist&#xE4;. Tulevaisuuden tutkimuksessa keskeist&#xE4; on yhdist&#xE4;&#xE4; laserkeilaus entist&#xE4; tarkempaan tietoon esimerkiksi myyr&#xE4;kannoista, ilmastosta ja aluskasvillisuuden rakenteesta.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:68:\"Hyönteiskarkotteiden myrkky häiritsee kimalaisten suunnistuskykyä\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:224:\"Jo lyhyt altistuminen hyönteiskarkotteissa käytetylle myrkylle voi heikentää merkittävästi kimalaisten kykyä löytää takaisin pesälleen. Kimalaisten kyky suunnistaa takaisin pesälleen on koko yhdyskunnan elinehto.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:103:\"https://www.verdelehti.fi/2026/04/20/hyonteiskarkotteiden-myrkky-hairitsee-kimalaisten-suunnistuskykya/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69e0e23ecd4f8200016c0102\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:7:\"Uutinen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:17:\"Luonto ja ilmasto\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:11:\"hyönteiset\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Mon, 20 Apr 2026 08:10:33 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Toimitus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:139:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/eea8d20b-8d8d-4a97-9e9c-dde1fd56217e-w_720.jpg\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:4121:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/eea8d20b-8d8d-4a97-9e9c-dde1fd56217e-w_720.jpg\" alt=\"Hy&#xF6;nteiskarkotteiden myrkky h&#xE4;iritsee kimalaisten suunnistuskyky&#xE4;\"><p>Kes&#xE4;ll&#xE4; moni turvautuu hy&#xF6;nteiskarkotteisiin v&#xE4;hent&#xE4;&#xE4;kseen inin&#xE4;&#xE4; ja pistoksia. Yksi viime vuosina yleistynyt ratkaisu on Thermacell&#x2011;laite, joka vapauttaa ilmaan h&#xF6;yrystetty&#xE4; pralletriinia. Aineen vaikutuksista luontoon ja erityisesti p&#xF6;lytt&#xE4;jiin on keskusteltu viime vuosina paljon, mutta tutkimustietoa on ollut rajallisesti.</p><p>Turun ja Oulun yliopistojen tutkijat selvittiv&#xE4;t, miten pralletriini vaikuttaa kimalaisten k&#xE4;ytt&#xE4;ytymiseen. Tulokset osoittavat, ett&#xE4; jo lyhyt altistuminen aineelle voi heikent&#xE4;&#xE4; merkitt&#xE4;v&#xE4;sti kimalaisten kyky&#xE4; l&#xF6;yt&#xE4;&#xE4; takaisin pes&#xE4;lleen.</p><p>&quot;Kimalaisille pes&#xE4;lle palaaminen ei ole sivuseikka, vaan se on koko yhdyskunnan elinehto&quot;, sanoo dosentti&#xA0;<strong>Olli Loukola</strong>&#xA0;Turun yliopistosta.</p><p>Tutkimuksessa tarkkailtiin 167 kontukimalaisen k&#xE4;ytt&#xE4;ytymist&#xE4;. Ne altistettiin pralletriinille yhden, kymmenen tai 20 minuutin ajan kuluttajak&#xE4;ytt&#xF6;&#xF6;n tarkoitetulla karkotelaitteella, mink&#xE4; j&#xE4;lkeen kimalaiset vapautettiin kilometrin p&#xE4;&#xE4;h&#xE4;n pes&#xE4;st&#xE4;&#xE4;n ja niiden paluuta seurattiin kolmen p&#xE4;iv&#xE4;n ajan.</p><p>Tulokset olivat selkeit&#xE4;. Vertailuryhm&#xE4;n kimalaisista, joita ei altistettu pralletriinille, 37 prosenttia palasi pes&#xE4;lle. Minuutin altistuksen saaneiden kimalaisten paluuprosentti ei viel&#xE4; eronnut vertailuryhm&#xE4;n kimalaisista, mutta kymmenen minuutin altistuksen saaneista kimalaisista vain 17 prosenttia l&#xF6;ysi takaisin pes&#xE4;&#xE4;ns&#xE4;. Kimalaisista, jotka saivat 20 minuutin altistuksen, pes&#xE4;lle palasi en&#xE4;&#xE4; noin 5 prosenttia.</p><p>Niill&#xE4; yksil&#xF6;ill&#xE4;, jotka onnistuivat palaamaan, matkaan kulunut aika ei pidentynyt. Lis&#xE4;ksi laboratoriokokeet osoittivat, ettei altistus lis&#xE4;nnyt kimalaisten kuolleisuutta, mik&#xE4; viittaa siihen, ett&#xE4; vaikutus liittyy nimenomaan suunnistuskyvyn h&#xE4;iriintymiseen eik&#xE4; suoraan myrkyllisyyteen.</p><p>&quot;Kimalaispes&#xE4; on riippuvainen ravintoa ker&#xE4;&#xE4;vist&#xE4; ty&#xF6;l&#xE4;isist&#xE4;, ja jos ne eiv&#xE4;t l&#xF6;yd&#xE4; takaisin pes&#xE4;&#xE4;n, ravinnon saanti heikkenee. Pitk&#xE4;ll&#xE4; aikav&#xE4;lill&#xE4; t&#xE4;m&#xE4; voi heikent&#xE4;&#xE4; pes&#xE4;n elinvoimaa, v&#xE4;hent&#xE4;&#xE4; uusien kuningattarien syntymist&#xE4; ja pahimmillaan johtaa pes&#xE4;n kuolemiseen&quot;, toteaa tutkija&#xA0;<strong>Kimmo Kaakinen</strong>&#xA0;Turun yliopistosta.</p><h3 id=\"hy%C3%B6nteiskarkotteiden-ekologista-turvallisuutta-arvioitava-uudelleen\">Hy&#xF6;nteiskarkotteiden ekologista turvallisuutta arvioitava uudelleen</h3><p>Suomessa Thermacell&#x2011;laitteiden k&#xE4;ytt&#xF6; on sallittua, mutta niiden k&#xE4;ytt&#xF6;&#xE4; on rajoitettu asuinrakennusten v&#xE4;litt&#xF6;m&#xE4;&#xE4;n l&#xE4;heisyyteen, kuten pihoille ja terasseille. Laitteita ei saa k&#xE4;ytt&#xE4;&#xE4; sis&#xE4;tiloissa eik&#xE4; luonnonymp&#xE4;rist&#xF6;iss&#xE4;, kuten metsiss&#xE4; tai kansallispuistoissa.</p><p>&quot;Pralletriinipohjaisia karkotteita k&#xE4;ytet&#xE4;&#xE4;n monissa maissa l&#xE4;hinn&#xE4; mukavuussyist&#xE4;. Joissakin tilanteissa niiden k&#xE4;ytt&#xF6; voi olla perusteltua esimerkiksi hyttysten levitt&#xE4;mien tautien torjunnassa&quot;, Kaakinen sanoo.</p><p>Tutkijoiden mukaan onkin t&#xE4;rke&#xE4;&#xE4; arvioida tarkemmin my&#xF6;s kotitalousk&#xE4;ytt&#xF6;&#xF6;n tarkoitettujen hy&#xF6;nteismyrkkyjen vaikutuksia p&#xF6;lytt&#xE4;jiin. Heid&#xE4;n mukaansa tutkimuksen tulokset nostavat esiin tarpeen arvioida n&#xE4;iden tuotteiden ekologista turvallisuutta uudelleen.</p><p>Tutkimus on toteutettu Turun ja Oulun yliopistojen yhteisty&#xF6;n&#xE4; ja julkaistu&#xA0;<em>Biology Letters</em>&#xA0;&#x2011;lehdess&#xE4;.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"Talousvaliokunta kirittää hallitusta tiukempiin toimiin krääsätaloutta vastaan\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:302:\"Talousvaliokunta antoi mietintönsä kansalaisaloitteesta suomalaisyritysten ja kuluttajien oikeuksien puolesta. Valiokunta vaatii valtioneuvostolta selvitystä halpatuonnin kansallisista toimista ja niihin liittyvästä lainsäädännöstä.Vihreiden Tynkkynen iloitsi yksimielisestä päätöksestä.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:116:\"https://www.verdelehti.fi/2026/04/20/talousvaliokunta-kirittaa-hallitusta-tiukempiin-toimiin-kraasataloutta-vastaan/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69e225a6cd4f8200016c019e\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:7:\"Uutinen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:6:\"Talous\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:12:\"kuluttaminen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Mon, 20 Apr 2026 07:01:42 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Toimitus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:121:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/SheinPopupStoreSquareOne.jpg\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6048:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/SheinPopupStoreSquareOne.jpg\" alt=\"Talousvaliokunta kiritt&#xE4;&#xE4; hallitusta tiukempiin toimiin kr&#xE4;&#xE4;s&#xE4;taloutta vastaan\"><p>Talousvaliokunta sai perjantaina 17.4. valmiiksi mietint&#xF6;ns&#xE4; kansalaisaloitteesta (KAA 7/2025 vp) suomalaisyritysten ja kuluttajien oikeuksien puolesta. Mietint&#xF6; oli yksimielinen. Aloitteessa ehdotetaan ultrapikamuodin ja kr&#xE4;&#xE4;s&#xE4;kaupan mainonnan kielt&#xE4;mist&#xE4; sek&#xE4; vaaditaan selvitt&#xE4;m&#xE4;&#xE4;n mahdollisuutta vaikuttaa kr&#xE4;&#xE4;s&#xE4;kaupan kasvuun verotuksella.</p><p>Talousvaliokunta pit&#xE4;&#xE4; kansalaisaloitetta t&#xE4;rke&#xE4;n&#xE4; ja ajankohtaisena, sill&#xE4; aloitteessa kuvattu ongelma ja sen yhteiskunnalliset vaikutukset ovat merkitt&#xE4;vi&#xE4;. </p><p>&#x201D;Erityisesti kiinalaisten tuontituotteiden jatkuva kasvu on ongelmallista vastuullisesti toimivien yritysten kilpailukyvyn heikentymisen, kuluttajansuojan rapautumisen sek&#xE4; luonnonvarojen ylikulutuksen ja j&#xE4;teongelmien vuoksi&#x201D;, toteaa valiokunnan puheenjohtaja <strong>Vilhelm Junnila</strong>. </p><p>&#x201D;Sen vuoksi valiokunta edellytt&#xE4;&#xE4;, ett&#xE4; valtioneuvosto selvitt&#xE4;&#xE4; kansallisia toimia halpatuontiin puuttumiseksi ja valmistelee viipym&#xE4;tt&#xE4; t&#xE4;h&#xE4;n liittyv&#xE4;t lains&#xE4;&#xE4;d&#xE4;nn&#xF6;n ehdotukset.&#x201D;</p><p>Valiokunta katsoo, ett&#xE4; kolmansista maista tuotteita v&#xE4;litt&#xE4;vien verkkoalustojen ep&#xE4;asialliseen ja aggressiiviseen markkinointiin tulee voida puuttua nykyist&#xE4; tehokkaammin. </p><p>&#x201D;On selvitett&#xE4;v&#xE4; perusteellisesti, miten kolmansista maista tulevaa markkinointia olisi mahdollista s&#xE4;&#xE4;nnell&#xE4; kansallisesti EU-lains&#xE4;&#xE4;d&#xE4;nn&#xF6;n sallimissa rajoissa&#x201D;, toteaa valiokunnan varapuheenjohtaja <strong>Pauli Aalto-Set&#xE4;l&#xE4;</strong>.</p><p>Valiokunnan mietinn&#xF6;ss&#xE4; todetaan, ett&#xE4; halpatuontiin puuttuvien toimenpiteiden rinnalla on t&#xE4;rke&#xE4;&#xE4; tukea vastuullista kuluttamista sek&#xE4; kiertotalouden tutkimus- ja kehitystoimintaa. Talousvaliokunta katsoo, ett&#xE4; tehostetulla neuvonnalla ja ohjauksella tulee pyrki&#xE4; lis&#xE4;&#xE4;m&#xE4;&#xE4;n kuluttajien tietoisuutta halpatuontituotteiden terveyteen ja turvallisuuteen liittyvist&#xE4; riskeist&#xE4;.</p><p>Valiokunta edellytt&#xE4;&#xE4; mietinn&#xF6;ss&#xE4;&#xE4;n, ett&#xE4; valtioneuvosto selvitt&#xE4;&#xE4; mahdollisuudet ker&#xE4;t&#xE4; tuottajavastuun maksut kolmansista maista suoraan kuluttajille myydyist&#xE4; tuotteista tullimaksujen yhteydess&#xE4; ja valmistelee viipym&#xE4;tt&#xE4; t&#xE4;h&#xE4;n liittyv&#xE4;t lains&#xE4;&#xE4;d&#xE4;nn&#xF6;n ehdotukset. Samoin valiokunta edellytt&#xE4;&#xE4;, ett&#xE4; valtioneuvosto edist&#xE4;&#xE4; EU:ssa m&#xE4;&#xE4;r&#xE4;tietoisesti toimia halpatuontiin puuttumiseksi ja ett&#xE4; kaikkien toimenpiteiden etenemisest&#xE4; raportoidaan talousvaliokunnalle.</p><p>Asian k&#xE4;sittely jatkuu seuraavaksi eduskunnan t&#xE4;ysistunnossa, joka k&#xE4;sittelee aloitetta talousvaliokunnan mietinn&#xF6;n pohjalta.</p><h3 id=\"tynkkynen-iloitsee-yksimielisest%C3%A4-p%C3%A4%C3%A4t%C3%B6ksest%C3%A4\">Tynkkynen iloitsee yksimielisest&#xE4; p&#xE4;&#xE4;t&#xF6;ksest&#xE4;</h3><p>Vihre&#xE4;n eduskuntaryhm&#xE4;n puheenjohtaja <strong>Oras Tynkkynen</strong> iloitsee talousvaliokunnan hyv&#xE4;ksym&#xE4;st&#xE4; mietinn&#xF6;st&#xE4;, jossa se edellytt&#xE4;&#xE4; hallitukselta viipym&#xE4;tt&#xE4; tekoja kiinalaiseen kr&#xE4;&#xE4;s&#xE4;kauppaan puuttumiseksi. Nyt on hallituksen velvollisuus pikaisesti n&#xE4;ytt&#xE4;&#xE4;, ett&#xE4; se ottaa eduskunnan tahdon tosissaan, Tynkkynen vaatii tiedotteessa.</p><p>&quot;Verkon kr&#xE4;&#xE4;s&#xE4;kauppa v&#xE4;h&#xE4;t v&#xE4;litt&#xE4;&#xE4; Suomen ja Euroopan laeista. Kiinasta vy&#xF6;ryv&#xE4; tavarasunaami uhkaa niin terveytt&#xE4;, turvallisuutta, kuluttajansuojaa, ymp&#xE4;rist&#xF6;&#xE4; kuin kotimaisia yritt&#xE4;ji&#xE4;kin. Vastuuttomalle ja ylikulutusta ruokkivalle tavararallille on korkea aika laittaa piste&quot;, Tynkkynen linjaa.</p><p>Mietinn&#xF6;n taustalla ollut kansalaisaloite saa kiitosta Tynkkyselt&#xE4;.</p><p>&quot;Kansalaisaloite on ansiokkaasti vahvistanut tietoisuutta kr&#xE4;&#xE4;s&#xE4;kaupan vakavista ongelmista ja luonut poliittista painetta niihin puuttumiseksi. Haluan l&#xE4;mpim&#xE4;sti kiitt&#xE4;&#xE4; aloitteen tekij&#xF6;it&#xE4; ja tukijoita polttavan asian nostamisesta eduskunnan p&#xF6;yd&#xE4;lle&quot;, vihreit&#xE4; talousvaliokunnassa edustava Tynkkynen jatkaa.</p><p>Talousvaliokunta esitt&#xE4;&#xE4; mietinn&#xF6;ss&#xE4;&#xE4;n kansalaisaloitteen hylk&#xE4;&#xE4;mist&#xE4;, koska se ei sovi toteutettavaksi sellaisenaan. Samalla valiokunta kuitenkin tukee vahvasti aloitteen tavoitteita ja edellytt&#xE4;&#xE4; hallitukselta pikaisia toimia kr&#xE4;&#xE4;s&#xE4;kauppaan puuttumiseksi.</p><p>&quot;Yksimielinen talousvaliokunta l&#xE4;hett&#xE4;&#xE4; t&#xE4;n&#xE4;&#xE4;n vahvan viestin. Eduskunta vaatii hallitukselta pikaisia toimia kr&#xE4;&#xE4;s&#xE4;kaupan suitsimiseksi. Odotan ja edellyt&#xE4;n hallitukselta pontevia tekoja viel&#xE4; t&#xE4;m&#xE4;n kauden aikana&quot;, Tynkkynen painottaa.</p><p>Poliittisesti eripuraisina aikoina ei ole itsest&#xE4;&#xE4;nselvyys, ett&#xE4; puolueet laidasta laitaan kykenev&#xE4;t yksimieliseen p&#xE4;&#xE4;t&#xF6;kseen. Tynkkynen kiitt&#xE4;&#xE4;kin talousvaliokunnan kollegoita yhteisty&#xF6;st&#xE4;.</p><p>&quot;Voimme ajoittain olla kiivaastikin eri mielt&#xE4;, mutta t&#xE4;m&#xE4; meit&#xE4; yhdist&#xE4;&#xE4;: halu puuttua kr&#xE4;&#xE4;s&#xE4;kaupan ongelmiin ja turvata kaikille yht&#xE4;l&#xE4;iset pelis&#xE4;&#xE4;nn&#xF6;t. Kun talousvaliokunta on l&#xE4;hett&#xE4;nyt yksimielisen viestin, pallo on hallituksella. Jokainen kivi on nyt k&#xE4;&#xE4;nnett&#xE4;v&#xE4; kr&#xE4;&#xE4;s&#xE4;kaupan suitsimiseksi&quot;, Tynkkynen p&#xE4;&#xE4;tt&#xE4;&#xE4;.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:10;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:58:\"Unkarin vaalitulos muistuttaa, että hyvä voittaa lopulta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:270:\"Unkarin vaalit osoittavat, ettei valheellinen propaganda pure ihmisiin loputtomiin. Orbánin 16 vuotta kestänyt valtakausi päättyi, vaikka hänen tuekseen rakennettiin viholliskuvien ja disinformaation koneisto, jota vahvistivat Venäjän ja Yhdysvaltojen avoin tuki.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:93:\"https://www.verdelehti.fi/2026/04/17/unkarin-vaalitulos-muistuttaa-etta-hyva-voittaa-lopulta/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69e0d257cd4f8200016c005c\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:4:{i:0;a:5:{s:4:\"data\";s:14:\"Pääkirjoitus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:10:\"Politiikka\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:6:\"Unkari\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:5:\"Orban\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Fri, 17 Apr 2026 11:24:39 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Toimitus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:122:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/Peter_Magyar.Viktor_Orban.jpg\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7527:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/Peter_Magyar.Viktor_Orban.jpg\" alt=\"Unkarin vaalitulos muistuttaa, ett&#xE4; hyv&#xE4; voittaa lopulta\"><p>Budapestissa juhlittiin viikonloppuna. Kaduilla itkettiin ilosta, halattiin tuntemattomia ja laulettiin aamunkoittoon saakka. Unkarilaiset olivat &#xE4;&#xE4;nest&#xE4;neet vapauden puolesta.</p><p>Oppositiopuolue Tisza kukisti Unkarin demokratiaa ja oikeusvaltiota purkaneen Fideszin murskaluvuin: Tisza saa parlamenttiin 138 kansanedustajaa eli yli kahden kolmasosan enemmist&#xF6;n. &#xC4;&#xE4;nestysaktiivisuus kohosi enn&#xE4;tyksellisesti l&#xE4;hes 80 prosenttiin. <strong>Viktor Orb&#xE1;n</strong>, 16 vuotta l&#xE4;hes kaikkivoipaisena maata hallinnut mies, joutui tunnustamaan tappionsa.</p><p>Orb&#xE1;n ei my&#xF6;sk&#xE4;&#xE4;n taistellut yksin. Ven&#xE4;j&#xE4;n sotilastiedustelupalvelu GRU:n upseereita l&#xE4;hetettiin Unkarin suurl&#xE4;hetyst&#xF6;&#xF6;n edist&#xE4;m&#xE4;&#xE4;n Fidesz-puolueen vaalimenestyst&#xE4; ja trollitehtaat kylviv&#xE4;t sosiaaliseen mediaan disinformaatiota t&#xE4;ydell&#xE4; teholla. Kampanjav&#xE4;ki levitti teko&#xE4;lykuvia, joissa ukrainalaiset sotilaat antavat kultaharkkoja oppositiopuolue Tiszalle. </p><p>My&#xF6;s Yhdysvallat heitti t&#xE4;yden panoksensa Orb&#xE1;nin taakse: presidentti <strong>Donald Trump</strong> lupasi Unkarille taloudellista tukea Fideszin voittaessa, varapresidentti <strong>J.D. Vance </strong>matkusti Budapestiin kampanjoimaan henkil&#xF6;kohtaisesti Orb&#xE1;nin puolesta, ja ulkoministeri <strong>Marco Rubio</strong> ilmoitti h&#xE4;peilem&#xE4;tt&#xE4; &#xE4;&#xE4;neen, ett&#xE4; Washington toivoo Orb&#xE1;nin pysyv&#xE4;n vallassa.</p><p>Valtiollinen media oli tuottanut pitk&#xE4;&#xE4;n yksipuolista propagandaa. Fideszin haastaja <strong>P&#xE9;ter Magyar</strong> esitettiin Brysselin ja <strong>Zelenskyin</strong> s&#xE4;tkynukkena, joka myisi Unkarin kansalliset edut ulkomaisille intresseille. Jokainen Orb&#xE1;nin poliittinen vastustaja leimattiin maanpetturiksi tai vieraan vallan k&#xE4;tyriksi.</p><p>Ja silti. T&#xE4;m&#xE4; ei riitt&#xE4;nyt.</p><p>Ihmiset olivat fiksumpia. Orb&#xE1;nin Unkarissa valtiollinen media menetti monen kansalaisen silmiss&#xE4; uskottavuutensa tuottamansa propagandan vuoksi. Autoritaarisen j&#xE4;rjestelm&#xE4;n ongelmana oli, ett&#xE4; se ryhtyi tuottamaan rinnakkaista todellisuutta. Ihmiset huomasivat, etteiv&#xE4;t valtion kertomukset vastanneet heid&#xE4;n omaa arkeaan &#x2013; sairaaloiden rappeutumista, korruptiota, k&#xF6;yhyytt&#xE4; ja vertailua muualta maailmasta saatuun tietoon.</p><p>Orb&#xE1;nin tarina on oppikirjaesimerkki oikeistopopulistisesta vallank&#xE4;yt&#xF6;st&#xE4;. Poliittiset vastustajat esitet&#xE4;&#xE4;n vihollisina, ei kilpailijoina. Monimutkaiset ongelmat yksinkertaistetaan k&#xE4;rjistettyihin viholliskuviin: maahanmuuttajat, Bryssel, &quot;sukupuoli-ideologia&quot;. Faktat ovat toissijaisia: t&#xE4;rkeint&#xE4; on heimoyhteenkuuluvuus, pelko sek&#xE4; tunne siit&#xE4;, ett&#xE4; ollaan puolustamassa jotain arvokasta, joka on uhattuna, tai jota rappio uhkaa.</p><p>Sama kaava toistuu kaikkialla, miss&#xE4; populistinen oikeisto on noussut valtaan. Lupaukset ovat suuria ja todellisuus pettymys, mutta silloin l&#xF6;ytyy yleens&#xE4; uusi syyllinen, uusi uhka, uusi valhe.</p><p>Miksi kannattajat useimmiten uskovat tai eiv&#xE4;t v&#xE4;lit&#xE4;? Osittain siksi, ett&#xE4; populismi tarjoaa yksinkertaisen tarinan monimutkaiseen maailmaan. Osittain siksi, ett&#xE4; huijatuksi tulemisen my&#xF6;nt&#xE4;minen on psykologisesti kivuliasta. Ja osittain siksi, ett&#xE4; sosiaalisen median kuplat ja trollitehtaat pit&#xE4;v&#xE4;t huolen siit&#xE4;, ettei oikea tieto koskaan t&#xE4;ysin tavoita kaikkia.</p><p>Mutta historia on my&#xF6;s armollinen. Se kertoo meille yh&#xE4; uudelleen saman tarinan: totuus ja vapaus voittavat lopulta.</p><p>Kun Eurooppaa halkova rautaesirippu nousi vuonna 1989, monikaan ei uskonut sen tapahtuvan niin nopeasti tai niin rauhanomaisesti. Berliinin muuri oli vuosikymmeni&#xE4; n&#xE4;ytt&#xE4;nyt pysyv&#xE4;lt&#xE4;. Ja sitten, muutamassa tunnissa, se oli poissa, kansalaisten k&#xE4;siss&#xE4; murtuen.</p><p>Etel&#xE4;-Afrikan apartheid n&#xE4;ytti 1970-luvulla voittamattomalta rakenteelta. Nelson Mandela istui vankilassa 27 vuotta. Ja silti: h&#xE4;n vapautui, johti maan vapaaseen demokratiaan ja osoitti, ett&#xE4; ihmisarvo ei lopulta taivu v&#xE4;kivallalle.</p><p>Latinalaisen Amerikan ja Kreikan sotilasditaktuurit, Iberian niemimaan fasistit, Etel&#xE4;-Korean ja Taiwanin autorit&#xE4;&#xE4;riset j&#xE4;rjestelm&#xE4;t &#x2013; usein sama kaari. Tyrannia luulee olevansa ikuinen. Se ei ole.</p><p>Lopulta historian painavin esimerkki on silti natsi-Saksa. Se n&#xE4;ytti 1930-luvulla monesta l&#xE4;nsimaisesta tarkastelijasta vahvalta, modernisoivalta voimalta. Sama ideologia nosti p&#xE4;&#xE4;t&#xE4;&#xE4;n my&#xF6;s Yhdysvalloissa, jossa liike sai runsaasti kannatusta ja poliittista sympatiaa. Sitten sotavuosien totuus Euroopasta kantautui Yhdysvaltoihin: keskitysleirit, kaasukammiot ja joukkomurhat saivat yhdysvaltalaiset k&#xE4;&#xE4;nt&#xE4;m&#xE4;&#xE4;n suunnan yhdess&#xE4; y&#xF6;ss&#xE4;, ja loppu on historiaa.</p><p>Edistys ei kuitenkaan koskaan kulje suoraviivaisesti. Takaiskut koettelevat t&#xE4;m&#xE4;n t&#xE4;st&#xE4; uskoa tulevaan. Silti pidemm&#xE4;ll&#xE4; aikav&#xE4;lill&#xE4; katsottuna suunta on usein ollut kohti laajempaa vapautta, vahvempaa demokratiaa ja suurempaa ihmisarvon kunnioitusta.</p><p>Emme my&#xF6;sk&#xE4;&#xE4;n saa olla naiiveja. Ulkopolitiikassa Unkarista tulee nyt varmasti helpompi kumppani, mutta mit&#xE4;&#xE4;n t&#xE4;ydellist&#xE4; muutosta ei pid&#xE4; odottaa. Tisza on konservatiivinen puolue, jonka Magyar perusti j&#xE4;tt&#xE4;ess&#xE4;&#xE4;n Fideszin vain muutama vuosi sitten. Unkaria johtaa edelleen yksi puolue t&#xE4;ydell&#xE4; enemmist&#xF6;ll&#xE4;, eik&#xE4; historian valossa n&#xE4;in voimakas vallan keskittyminen ole pitk&#xE4;ll&#xE4; aikav&#xE4;lill&#xE4; ollut hyv&#xE4; asia. Eiv&#xE4;tk&#xE4; Orb&#xE1;nin 16 vuoden aikana rakennetut rakenteet kaadu yhdess&#xE4; y&#xF6;ss&#xE4;. Populismi ei katoa Euroopasta eik&#xE4; maailmasta. Ven&#xE4;j&#xE4;n trollitehtaat jatkavat ty&#xF6;t&#xE4;&#xE4;n, ja sosiaalisen median alustat vahvistavat edelleen k&#xE4;rjistyv&#xE4;&#xE4; oikeistopopulistista sis&#xE4;lt&#xF6;&#xE4;. Samaan aikaan Yhdysvalloissa fasismin nousu saa yh&#xE4; huolestuttavampia piirteit&#xE4;, ja Israel syvent&#xE4;&#xE4; apartheidia muistuttavia rakenteitaan ja kiihdytt&#xE4;&#xE4; Palestiinan arabeihin kohdistuvia ihmisoikeusloukkauksia.</p><p>Mutta kaikesta huolimatta Unkarin tapahtumat muistuttavat meille jotain oleellista ja tuovat toivoa: valheellinen propaganda ja katteettomat lupaukset eiv&#xE4;t pure ihmisiin loputtomasti. Nykyisess&#xE4; globaalissa maailmassa ihmiset kyll&#xE4; ennemmin tai my&#xF6;hemmin saavat totuuden selville. Koko manipulaation malli alkaa murtua, kun ihmiset oppivat yh&#xE4; paremmin tunnistamaan sit&#xE4;, miten heihin yritet&#xE4;&#xE4;n vaikuttaa. Ja kun he lopulta nousevat liikkeelle, populistiset koneistot, diktaattorit ja trollit k&#xE4;yv&#xE4;t voimattomiksi.</p><p>Hyv&#xE4; ei voita itsest&#xE4;&#xE4;n. Se vaatii rohkeutta, k&#xE4;rsiv&#xE4;llisyytt&#xE4; ja sinnikkyytt&#xE4;. Se vaatii ihmisi&#xE4;, jotka v&#xE4;litt&#xE4;v&#xE4;t tarpeeksi saadakseen muutoksen aikaan. Mutta historian valossa se voittaa.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:11;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"Korkeakoulujärjestelmään lisää vaikuttavuutta uuden yhteistyömallin avulla\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:223:\"Pääkaupunkiseudun korkeakoulut ovat käynnistäneet valmistelut yhteistyön tiivistämiseksi. Tavoitteena on vahvistaa suomalaisen korkeakoulutuksen ja tutkimuksen vaikuttavuutta verkostomaisen toimintamallin avulla. \";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:112:\"https://www.verdelehti.fi/2026/04/17/korkeakoulujarjestelmaan-lisaa-vaikuttavuutta-uuden-yhteistyomallin-avulla/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69e0a8cccd4f8200016c0007\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:4:{i:0;a:5:{s:4:\"data\";s:7:\"Uutinen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:14:\"korkeakoulutus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:19:\"ammattikorkeakoulut\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:24:\"Kulttuuri ja yhteiskunta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Fri, 17 Apr 2026 05:30:48 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Toimitus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:150:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/University_of_Helsinki-_Main_Building_-52890135967--2.jpg\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:1694:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/University_of_Helsinki-_Main_Building_-52890135967--2.jpg\" alt=\"Korkeakouluj&#xE4;rjestelm&#xE4;&#xE4;n lis&#xE4;&#xE4; vaikuttavuutta uuden yhteisty&#xF6;mallin avulla\"><p>Tasavertaista yhteisty&#xF6;n mallia p&#xE4;&#xE4;kaupunkiseudulla on ehdotettu kahdelle yliopistolle ja kolmelle ammattikorkeakoululle. Mallilla ei tavoitella rakenteellisia muutoksia, vaan&#xA0;jokainen&#xA0;korkeakoulu s&#xE4;ilyy itsen&#xE4;isen&#xE4; instituutiona.&#xA0;Mukana ovat Aalto-yliopisto, Haaga-Helia ammattikorkeakoulu, Helsingin yliopisto, Laurea-ammattikorkeakoulu ja Metropolia Ammattikorkeakoulu.</p><p>Verkostomaisella&#xA0;yhteisty&#xF6;mallilla&#xA0;korkeakoulut&#xA0;haluavat&#xA0;vahvistaa Suomen elinvoimaa ja kasvua sek&#xE4; vastata kiristyv&#xE4;&#xE4;n kansainv&#xE4;liseen kilpailuun. P&#xE4;&#xE4;kaupunkiseutu on Suomen keskeinen osaamis- ja kasvukeskus, ja sen merkitys on ratkaiseva koko maan menestykselle.&#xA0;</p><p>Ehdotetun yhteisty&#xF6;n avulla&#xA0;voidaan&#xA0;kehitt&#xE4;&#xE4;&#xA0;esimerkiksi opiskelijaliikkuvuutta ja joustavia opintopolkuja, sujuvoittaa&#xA0;tutkimusta ja yhteiskehitt&#xE4;mist&#xE4; sek&#xE4; vahvistaa&#xA0;julkisen sektorin ja elinkeinoel&#xE4;m&#xE4;n kumppanuuksia.&#xA0;&#xA0;</p><p>Valmistelun ensimm&#xE4;isess&#xE4; vaiheessa kartoitetaan yhteiset tavoitteet ja toimintatavat koulutuksen, tutkimuksen ja innovaatiotoiminnan kehitt&#xE4;miseksi. Suuntaviivojen arvioidaan valmistuvan kes&#xE4;kuussa.&#xA0;</p><p>Keskustelut verkostomaisesta&#xA0;toimintamallista k&#xE4;ynnistyiv&#xE4;t Helsingin yliopiston rehtorin aloitteesta.&#xA0;</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:12;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"Atlantin tärkeä merivirtaus voi  tyrehtyä arvioitua todennäköisemmin\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:238:\"Uusi tutkimus viittaa siihen, että Atlantin tärkeän merivirran tulevaisuutta kuvaavat parhaiten juuri pessimistisimmät ilmastomallit. Amocin pysäyttävä keikahduspiste saatetaan saavuttaa jo tämän vuosisadan puolivälin tienoilla.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:105:\"https://www.verdelehti.fi/2026/04/16/atlantin-tarkea-merivirtaus-voi-tyrehtya-arvioitua-todennakoisemmin/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69e086fbcd4f8200016bff9d\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:4:{i:0;a:5:{s:4:\"data\";s:7:\"Uutinen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:17:\"Luonto ja ilmasto\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:14:\"ilmastonmuutos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:16:\"keikahduspisteet\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Thu, 16 Apr 2026 17:27:50 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Toimitus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:121:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/aiamkay-sea-6651168_1280.jpg\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:4226:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/aiamkay-sea-6651168_1280.jpg\" alt=\"Atlantin t&#xE4;rke&#xE4; merivirtaus voi  tyrehty&#xE4; arvioitua todenn&#xE4;k&#xF6;isemmin\"><p>Atlantin meriveden kiertoliike voi olla tyrehtym&#xE4;ss&#xE4; todenn&#xE4;k&#xF6;isemmin, kuin mit&#xE4; aiemmin on arvioitu. Asiasta kertoo The Guardian. J&#xE4;rjestelm&#xE4; s&#xE4;&#xE4;telee laajasti ilmastoa Euroopassa, Afrikassa sek&#xE4; Pohjois- ja Etel&#xE4;-Amerikassa. Tuore tutkimus viittaa siihen, ett&#xE4; juuri kaikkein synkimm&#xE4;t ilmastomallit n&#xE4;ytt&#xE4;v&#xE4;t olevan l&#xE4;himp&#xE4;n&#xE4; todellisuutta.</p><p>Atlantin meridionaalinen kiertoliike eli Amoc kuljettaa l&#xE4;mmint&#xE4; pintavett&#xE4; tropiikista kohti Eurooppaa ja arktista aluetta, miss&#xE4; vesi j&#xE4;&#xE4;htyy, muuttuu tihe&#xE4;mm&#xE4;ksi ja painuu syvyyksiin. T&#xE4;m&#xE4; syv&#xE4;n veden virtaus on keskeinen osa koko maapallon ilmastoj&#xE4;rjestelm&#xE4;&#xE4;.</p><p>J&#xE4;rjestelm&#xE4;n tiedet&#xE4;&#xE4;n olevan heikoimmillaan noin 1 600 vuoteen. Uuden tutkimuksen mukaan sen heikkeneminen vuosisadan loppuun menness&#xE4; voi olla huomattavasti suurempaa kuin aiemmin on arvioitu. Tutkijat yhdistiv&#xE4;t havaintoaineistoa merist&#xE4; ilmastomalleihin ja p&#xE4;&#xE4;tyiv&#xE4;t siihen, ett&#xE4; Amoc voi hidastua vuoteen 2100 menness&#xE4; noin 42&#x2013;58 prosenttia. T&#xE4;llainen heikkeneminen veisi j&#xE4;rjestelm&#xE4;n hyvin l&#xE4;helle romahduspistett&#xE4;.</p><p>Saksassa Potsdamin ilmastovaikutusten tutkimusinstituutissa ty&#xF6;skentelev&#xE4; <strong>Stefan Rahmstorf</strong> arvioi The Guardianille, ett&#xE4; aiemmin pessimistisiksi luokitellut mallit n&#xE4;ytt&#xE4;v&#xE4;t nyt olevan realistisimpia, koska ne vastaavat parhaiten havaintoaineistoa. </p><p>&quot;On yh&#xE4; vaikeampi sulkea pois mahdollisuutta, ett&#xE4; Amocin pys&#xE4;ytt&#xE4;v&#xE4; keikahduspiste saavutetaan jo t&#xE4;m&#xE4;n vuosisadan puoliv&#xE4;lin tienoilla.&quot;</p><p>Se merkitsisi Euroopalle vakavia seurauksia. Amocin romahdus voisi tuoda L&#xE4;nsi-Eurooppaan poikkeuksellisen kylmi&#xE4; talvia ja kuivia kesi&#xE4;. Samalla se muuttaisi trooppisten sateiden vy&#xF6;hykett&#xE4; ja vaarantaisi ruoantuotannon laajoilla alueilla. Lis&#xE4;ksi Atlantin rannikoilla merenpinta voisi nousta entisest&#xE4;&#xE4;n jopa 50&#x2013;100 sentill&#xE4; &#x2013; ja merenpinta kohoaa jo nyt kiihtyv&#xE4;ll&#xE4; vauhdilla.</p><p>Amocin heikkeneminen liittyy suoraan ilmaston l&#xE4;mpenemiseen. Arktinen alue l&#xE4;mpenee nopeasti, jolloin merivesi j&#xE4;&#xE4;htyy siell&#xE4; aiempaa hitaammin. L&#xE4;mpim&#xE4;mpi vesi on kevyemp&#xE4;&#xE4; eik&#xE4; painu syvyyksiin yht&#xE4; tehokkaasti. Samalla lis&#xE4;&#xE4;ntynyt sadem&#xE4;&#xE4;r&#xE4; v&#xE4;hent&#xE4;&#xE4; meriveden pinnan suolaisuutta ja tiheytt&#xE4;, mik&#xE4; edelleen hidastaa kiertoa. N&#xE4;in syntyy itse&#xE4;&#xE4;n vahvistava kierre.</p><p>Tutkijat korostavat, ettei n&#xE4;in monimutkaisen j&#xE4;rjestelm&#xE4;n k&#xE4;ytt&#xE4;ytymist&#xE4; tai romahtamisen tarkkaa ajankohtaa voi ennustaa t&#xE4;ydell&#xE4; varmuudella. Amociin vaikuttavat my&#xF6;s luonnolliset satunnaisvaihtelut. Uuden tutkimuksen viesti ei silti ole ep&#xE4;selv&#xE4;: j&#xE4;rjestelm&#xE4;n voimakas heikkeneminen n&#xE4;ytt&#xE4;&#xE4; entist&#xE4; todenn&#xE4;k&#xF6;isemm&#xE4;lt&#xE4;, ja se voi aiheuttaa vakavia seurauksia jo tulevina vuosikymmenin&#xE4;.</p><p>Huolta lis&#xE4;&#xE4; se, ett&#xE4; ilmastomallit eiv&#xE4;t The Guardianin mukaan edes t&#xE4;ysin huomioi Gr&#xF6;nlannin j&#xE4;&#xE4;tik&#xF6;n sulamisesta syntyv&#xE4;&#xE4; makeaa vett&#xE4;. Juuri se makeuttaa Atlanttia edelleen ja voi kiihdytt&#xE4;&#xE4; virtausj&#xE4;rjestelm&#xE4;n heikkenemist&#xE4;. Rahmstorf arvioikin, ett&#xE4; todellinen kehitys voi olla viel&#xE4; uudenkin tutkimuksen esitt&#xE4;mi&#xE4; arvioita synkempi.</p><p>Tutkimus muistuttaa siit&#xE4;, ett&#xE4; ilmastokriisi etenee oleellisesti keikahduspisteiden kautta. Kun t&#xE4;llainen kynnys ylitet&#xE4;&#xE4;n, muutokset voivat olla nopeita, vaikeasti hallittavia ja k&#xE4;yt&#xE4;nn&#xF6;ss&#xE4; peruuttamattomia ihmisen aikaskaalassa.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:13;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:68:\"Väitös: Röntgenin avulla voidaan parantaa ydinjäteturvallisuutta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:282:\"Tuore väitöstutkimus osoittaa, että kehittyneet röntgenkuvantamismenetelmät tarjoavat uusia mahdollisuuksia materiaalien rakenteen, kosteuden ja kestävyyden tutkimiseen eli ilmiöihin, jotka ovat keskeisiä niin teollisuudessa kuin yhteiskunnan kriittisissä järjestelmissä.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:96:\"https://www.verdelehti.fi/2026/04/16/vaitos-rontgentutkimus-voi-parantaa-ydinjateturvallisuutta/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69dde79cf1e31e0001cb5b81\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:7:\"Uutinen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:19:\"Tiede ja teknologia\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:9:\"ydinvoima\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Thu, 16 Apr 2026 06:15:26 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Toimitus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:127:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/Geological_mapping_in_Onkalo_2.jpg\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:3499:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/Geological_mapping_in_Onkalo_2.jpg\" alt=\"V&#xE4;it&#xF6;s: R&#xF6;ntgenin avulla voidaan parantaa ydinj&#xE4;teturvallisuutta\"><p>Jyv&#xE4;skyl&#xE4;n yliopistossa tehty fysiikan <a href=\"https://jyx.jyu.fi/jyx/Record/jyx_123456789_109585?sid=264857196%C2%A0%C2%A0\"><u>v&#xE4;it&#xF6;stutkimus</u></a> tuo uutta tietoa siit&#xE4;, miten kosteus liikkuu materiaaleissa ja miten materiaalit kest&#xE4;v&#xE4;t erilaisia olosuhteita. Keskeinen tutkimuksen kohde liittyy veden kulkeutumiseen bentoniittisavessa, joka on t&#xE4;rke&#xE4; materiaali ydinj&#xE4;tteiden loppusijoituksessa.</p><p>V&#xE4;it&#xF6;skirjatutkija <strong>Janne Yliharju</strong> osoittaa, ett&#xE4; kaksoisenergia-r&#xF6;ntgenkuvantaminen kykenee tuottamaan tarkkaa tietoa siit&#xE4;, miten veden ja bentoniitin massajakaumat muuttuvat materiaalissa.&#xA0;</p><p>Kolmiulotteisessa kaksoisenergiar&#xF6;ntgenkuvauksessa kohde kuvataan kahdella eri r&#xF6;ntgens&#xE4;teilyn energialla. Menetelm&#xE4; auttaa erottamaan paremmin eri materiaalit toisistaan, ei vain rakenteita kuten tavallisessa r&#xF6;ntgenkuvauksessa. N&#xE4;in voidaan saada tarkempaa tietoa materiaalin koostumuksesta ja esimerkiksi veden jakautumisesta sen sis&#xE4;ll&#xE4;.</p><p>&quot;T&#xE4;m&#xE4; parantaa ymm&#xE4;rryst&#xE4; bentoniitin k&#xE4;ytt&#xE4;ytymisest&#xE4; olosuhteissa, joissa l&#xE4;mp&#xF6;tila vaihtelee esimerkiksi ydinj&#xE4;tteiden loppusijoituksen yhteydess&#xE4;&quot;, selvent&#xE4;&#xE4; Yliharju.&#xA0;</p><h3 id=\"tulokset-tukevat-yhteiskunnan-kriittisi%C3%A4-ratkaisuja\">Tulokset tukevat yhteiskunnan kriittisi&#xE4; ratkaisuja</h3><p>Bentoniittia k&#xE4;ytet&#xE4;&#xE4;n ydinj&#xE4;tteiden loppusijoituksessa, jossa sen teht&#xE4;v&#xE4; on erist&#xE4;&#xE4; j&#xE4;te ymp&#xE4;rist&#xF6;st&#xE4;. Yliharjun tulokset lis&#xE4;&#xE4;v&#xE4;t tietoa siit&#xE4;, miten bentoniitin kosteus ja tiheys muuttuvat veden ja l&#xE4;mp&#xF6;tilan vaikutuksesta.&#xA0;</p><p>&quot;T&#xE4;t&#xE4; tietoa voidaan hy&#xF6;dynt&#xE4;&#xE4; loppusijoituksen pitk&#xE4;aikaisturvallisuuden arvioinnissa niin mallinnuksen kuin kokeellisten havaintojen kautta&quot;, sanoo Yliharju.&#xA0;</p><p>Lis&#xE4;ksi tutkimuksessa arvioitiin Jyv&#xE4;skyl&#xE4;n yliopiston kemian laitoksella kehitettyj&#xE4; suodattimia. Ne osoittautuivat kest&#xE4;viksi, mik&#xE4; tukee niiden soveltuvuutta kriittisten raaka-aineiden talteenottoon esimerkiksi teollisuuden j&#xE4;tevesist&#xE4;.&#xA0;</p><p>&quot;Suodattimien kest&#xE4;vyys on ratkaisevaa, kun tavoitteena on kehitt&#xE4;&#xE4; pitk&#xE4;ik&#xE4;isi&#xE4; ja taloudellisia ratkaisuja&quot;, t&#xE4;sment&#xE4;&#xE4; Yliharju.&#xA0;</p><h3 id=\"kaksoisenergiar%C3%B6ntgenill%C3%A4-laaja-potentiaali\">Kaksoisenergiar&#xF6;ntgenill&#xE4; laaja potentiaali</h3><p>Vaikka kaksoisenergiar&#xF6;ntgenkuvantamisen sovellusmahdollisuudet ovat laajat, menetelm&#xE4;n tarkkuuteen vaikuttavat monet k&#xE4;yt&#xE4;nn&#xF6;n tekij&#xE4;t. V&#xE4;it&#xF6;stutkimus syvent&#xE4;&#xE4; ymm&#xE4;rryst&#xE4; menetelm&#xE4;n suorituskyvyst&#xE4; konkreettisen esimerkin kautta.</p><p>&quot;Monien materiaalien, kuten bentoniitin ja puupohjaisten tuotteiden, ominaisuudet ovat vahvasti sidoksissa niiden kosteuteen. Kosteusvaihteluiden vaikutusten ymm&#xE4;rt&#xE4;minen on t&#xE4;rke&#xE4;&#xE4;, kun suunnitellaan j&#xE4;rjestelmi&#xE4;, joissa materiaalien vesipitoisuus voi muuttua&quot;, Yliharju toteaa.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:14;a:6:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:106:\"Fatim Diarra: Hallituksen määräaikaisten työsuhteiden joustot polkevat naisvaltaisten alojen oikeuksia\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:277:\"Vihreiden Fatim Diarra ja neljä SDP:n kansanedustajaa jättivät eriävän mielipiteen lakiesityksestä, joka koskee määräaikaisia työsopimuksia. Esitystä on arvosteltu työntekijöiden oikeuksien heikentämisestä sekä raskaus- ja perhevapaasyrjinnän lisäämisestä. \";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:139:\"https://www.verdelehti.fi/2026/04/16/fatim-diarra-hallituksen-maaraaikaisten-tyosuhteiden-joustot-polkevat-naisvaltaisten-alojen-oikeuksia/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"69df5816cd4f8200016bfebc\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:4:{i:0;a:5:{s:4:\"data\";s:7:\"Uutinen\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:10:\"Politiikka\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:8:\"hallitus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:11:\"työelämä\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"Thu, 16 Apr 2026 05:20:43 GMT\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Toimitus\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:29:\"http://search.yahoo.com/mrss/\";a:1:{s:7:\"content\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:2:{s:3:\"url\";s:139:\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/87e5f2fe-8ae1-493d-baf7-940957091f23-w_720.jpg\";s:6:\"medium\";s:5:\"image\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:3987:\"<img src=\"https://storage.ghost.io/c/ee/6d/ee6da6b1-f7ea-40b6-9201-89b875a88ccb/content/images/2026/04/87e5f2fe-8ae1-493d-baf7-940957091f23-w_720.jpg\" alt=\"Fatim Diarra: Hallituksen m&#xE4;&#xE4;r&#xE4;aikaisten ty&#xF6;suhteiden joustot polkevat naisvaltaisten alojen oikeuksia\"><p>Vihreiden kansanedustaja <strong>Fatim Diarra</strong> ja nelj&#xE4; SDP:n kansanedustajaa j&#xE4;ttiv&#xE4;t eri&#xE4;v&#xE4;n mielipiteen lakiesityksest&#xE4;, joka koskee m&#xE4;&#xE4;r&#xE4;aikaisia ty&#xF6;sopimuksia. Perustuslakivaliokunta k&#xE4;sitteli asiaa kokouksessaan 14. huhtikuuta. Esityksen on kritisoitu heikent&#xE4;v&#xE4;n ty&#xF6;ntekij&#xF6;iden oikeuksia, kohdistuvan erityisesti naisvaltaisiin aloihin ja lis&#xE4;&#xE4;v&#xE4;n raskaus- ja perhevapaasyrjint&#xE4;&#xE4;. </p><p><strong>Orpon</strong> hallituksen esitys m&#xE4;&#xE4;r&#xE4;aikaisten ty&#xF6;suhteiden solmimisen helpottamisesta heikent&#xE4;&#xE4; ty&#xF6;ntekij&#xF6;iden oikeuksia erityisesti naisvaltaisilla aloilla.&#xA0;</p><p>&quot;Esitetty lains&#xE4;&#xE4;d&#xE4;nt&#xF6; mahdollistaisi m&#xE4;&#xE4;r&#xE4;aikaisten sopimusten ketjuttamisen jopa l&#xE4;hes kahden vuoden ajan ilman perusteltua syyt&#xE4;. Se siis vesitt&#xE4;isi toistaiseksi voimassa oleviin ty&#xF6;sopimuksiin kuuluvaa irtisanomissuojaa ja synnytt&#xE4;isi ty&#xF6;paikoille villin l&#xE4;nnen, jossa ainoa ketjutuksia rajoittava asia olisi ty&#xF6;nantajan moraali. Tilanne ei vastaisi perustuslain edellytt&#xE4;m&#xE4;&#xE4; lains&#xE4;&#xE4;d&#xE4;nn&#xF6;n t&#xE4;sm&#xE4;llisyytt&#xE4;&quot;, kansanedustaja ja perustuslakivaliokunnan j&#xE4;sen&#xA0;Fatim Diarra&#xA0;toteaa.</p><p>Jo t&#xE4;ll&#xE4; hetkell&#xE4; yleisin raskaus- ja perhevapaasyrjinn&#xE4;n muoto on m&#xE4;&#xE4;r&#xE4;aikaisen ty&#xF6;suhteen jatkamatta j&#xE4;tt&#xE4;minen.</p><p>&quot;Perustuslaki edellytt&#xE4;&#xE4; julkiselta vallalta yhdenvertaisuuden aktiivista edist&#xE4;mist&#xE4;. Hallituksen ty&#xF6;el&#xE4;m&#xE4;lains&#xE4;&#xE4;d&#xE4;nt&#xF6; tekee juuri p&#xE4;invastaista&quot;, Diarra summaa.</p><p>&quot;Hallituksen esitt&#xE4;m&#xE4; lakimuutos todenn&#xE4;k&#xF6;isesti lis&#xE4;&#xE4; raskaus- ja perhevapaasyrjint&#xE4;&#xE4;, ja yhdess&#xE4; muun hallituksen ty&#xF6;el&#xE4;m&#xE4;lains&#xE4;&#xE4;d&#xE4;nn&#xF6;n kanssa heikent&#xE4;&#xE4; nimenomaan naisvaltaisten alojen sek&#xE4; heikommassa ty&#xF6;markkina-asemassa olevien asemaa. N&#xE4;m&#xE4; vaikutukset on my&#xF6;s itse esityksess&#xE4; tunnistettu.&quot;</p><p>&quot;Sanon ihan suoraan: hallitus rakentaa ty&#xF6;markkinoita, joissa naisia ja v&#xE4;hemmist&#xF6;j&#xE4; on aiempaa helpompaa syrji&#xE4;&quot;, Diarra lataa.</p><p>My&#xF6;s lakiesityksess&#xE4; esitetty kielto sopia viikkoa pidemm&#xE4;st&#xE4; lomautusilmoitusajasta on ristiriidassa sek&#xE4; perustuslain ett&#xE4; Kansainv&#xE4;lisen ty&#xF6;j&#xE4;rjest&#xF6; ILO:n sopimusten takaaman kollektiivisen sopimusvapauden kanssa.</p><p>&quot;Hallitus tieten tahtoen rajoittaa sit&#xE4;, mit&#xE4; ty&#xF6;nantajat ja ty&#xF6;ntekij&#xE4;t voivat kesken&#xE4;&#xE4;n sopia. Hallitus tietoisesti romuttaa suomalaisen ty&#xF6;el&#xE4;m&#xE4;n vahvuutta eli sit&#xE4;, ett&#xE4; jyr&#xE4;&#xE4;misen sijaan asiat sovitaan yhteisesti&quot;, Diarra sanoo.</p><p>Esitys on her&#xE4;tt&#xE4;nyt aiemmin kritiikki&#xE4; my&#xF6;s hallituspuolueen sis&#xE4;ll&#xE4;. Kokoomusnaiset sek&#xE4; kokoomuksen naisj&#xE4;rjest&#xF6;jen toimijat ovat vaatineet lakiesityksen uutta tarkastelua erityisesti ty&#xF6;el&#xE4;m&#xE4;n tasa-arvon ja raskaussyrjinn&#xE4;n riskien vuoksi. Kritiikki&#xE4; on tullut my&#xF6;s ty&#xF6;oikeuden asiantuntijoilta ja palkansaajaj&#xE4;rjest&#xF6;ilt&#xE4;.</p><p>Vihreiden Diarran lis&#xE4;ksi eri&#xE4;v&#xE4;n mielipiteen lakimuutosehdotukseen j&#xE4;ttiv&#xE4;t t&#xE4;ll&#xE4; viikolla SDP:n&#xA0;<strong>Johannes Koskinen</strong>,&#xA0;<strong>Johanna Ojala-Niemel&#xE4;</strong>,&#xA0;<strong>Kimmo Kiljunen</strong>&#xA0;ja&#xA0;<strong>Saku Nikkanen</strong>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:30:\"https://www.verdelehti.fi/rss/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";O:48:\"WpOrg\\Requests\\Utility\\CaseInsensitiveDictionary\":1:{s:7:\"\0*\0data\";a:18:{s:14:\"content-length\";s:5:\"91244\";s:6:\"status\";s:6:\"200 OK\";s:3:\"via\";s:37:\"1.1 varnish, 1.1 varnish, 1.1 varnish\";s:6:\"server\";s:9:\"openresty\";s:4:\"etag\";s:37:\"W/\"1646c-Zz73Dkkz91EvIr1qmwf7x1IgrEU\"\";s:13:\"cache-control\";s:17:\"public, max-age=0\";s:12:\"content-type\";s:34:\"application/rss+xml; charset=utf-8\";s:13:\"accept-ranges\";s:5:\"bytes\";s:3:\"age\";s:4:\"1870\";s:4:\"date\";s:29:\"Thu, 23 Apr 2026 06:39:51 GMT\";s:11:\"x-served-by\";s:62:\"cache-ams2100094-AMS, cache-ams21067-AMS, cache-hel1410021-HEL\";s:7:\"x-cache\";s:14:\"MISS, HIT, HIT\";s:12:\"x-cache-hits\";s:7:\"0, 4, 0\";s:7:\"x-timer\";s:26:\"S1776926391.267151,VS0,VE1\";s:4:\"vary\";s:6:\"Cookie\";s:12:\"x-request-id\";s:36:\"ba096a97-2f3a-47d7-84b4-9e0fc48d35ed\";s:12:\"ghost-fastly\";s:15:\"true;production\";s:7:\"alt-svc\";s:5:\"clear\";}}s:5:\"build\";i:1727736619;s:21:\"cache_expiration_time\";i:1776969591;s:23:\"__cache_expiration_time\";i:1776969591;}','off'),
